-- Poems batch 21
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bdabff6f-1902-47c2-adcc-96f03549d10b','初著刺史緋荅友人見贈','白居易','唐','唐诗','tang','','[]','故人安慰善爲辭，五十專城道未遲。',64,'全唐诗/poet.tang.22000.json','["故人安慰善爲辭，五十專城道未遲。", "徒使花袍紅似火，其如蓬鬢白成絲。", "且貪薄俸君應惜，不稱衰容我自知。", "銀印可憐將底用，只堪歸舍嚇妻兒。"]'),
('40ca515d-7720-41fc-92c2-e3810c45909f','又荅賀客','白居易','唐','唐诗','tang','','[]','銀章暫假爲專城，賀客來多嬾起迎。',32,'全唐诗/poet.tang.22000.json','["銀章暫假爲專城，賀客來多嬾起迎。", "似挂緋衫衣架上，朽株枯竹有何榮。"]'),
('3925c75e-d4f1-427a-8ea2-5656ce0f2707','別草堂三絕句 一','白居易','唐','唐诗','tang','','[]','正聽山鳥向陽眠，黃紙除書落枕前。',32,'全唐诗/poet.tang.22000.json','["正聽山鳥向陽眠，黃紙除書落枕前。", "爲感君恩須暫起，爐峰不擬住多年。"]'),
('6a97143f-ba69-4c19-92c2-9f3f752a0876','別草堂三絕句 二','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','久眠褐被爲居士，忽挂緋袍作使君。',32,'全唐诗/poet.tang.22000.json','["久眠褐被爲居士，忽挂緋袍作使君。", "身出草堂心不出，廬山未要勒移文。"]'),
('d97383f9-fa42-458f-b3d6-064560ccfb11','別草堂三絕句 三','白居易','唐','唐诗','tang','','[]','三間茅舍向山開，一帶山泉遶舍迴。',32,'全唐诗/poet.tang.22000.json','["三間茅舍向山開，一帶山泉遶舍迴。", "山色泉聲莫惆悵，三年官滿却歸來。"]'),
('a7dd2d71-3511-48ef-ae58-dada6dced76d','鍾陵餞送','白居易','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','翠幕紅筵高在雲，歌鐘一曲萬家聞。',32,'全唐诗/poet.tang.22000.json','["翠幕紅筵高在雲，歌鐘一曲萬家聞。", "路人指點滕王閣，看送忠州白使君。"]'),
('fd87681a-a50b-4ced-a806-b7b6c6bba74c','潯陽宴別','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','鞍馬軍城外，笙歌祖帳前。',48,'全唐诗/poet.tang.22000.json','["鞍馬軍城外，笙歌祖帳前。", "乘潮發湓口，帶雪別廬山。", "暮景牽行色，春寒散醉顏。", "共嗟炎瘴地，盡室得生還。"]'),
('c214ce3f-5405-47ba-925f-ff9709c53987','戲贈戶部李巡官','白居易','唐','唐诗','tang','','[]','好去民曹李判官，少貪公事且謀歡。',32,'全唐诗/poet.tang.23000.json','["好去民曹李判官，少貪公事且謀歡。", "男兒未死爭能料，莫作忠州刺史看。"]'),
('c39f41dd-5f88-4c95-bfa4-2815e4ed58ab','行次夏口先寄李大夫','白居易','唐','唐诗','tang','','[]','連山斷處大江流，紅斾逶迤鎮上游。',64,'全唐诗/poet.tang.23000.json','["連山斷處大江流，紅斾逶迤鎮上游。", "幕下翱翔秦御史，軍前奔走漢諸侯。", "曾陪劒履升鸞殿，欲謁旌幢入鶴樓。", "假著緋袍君莫笑，恩深始得向忠州。"]'),
('ac38bd8e-3a65-4e4f-8397-1b873fb71614','重贈李大夫','白居易','唐','唐诗','tang','','[]','早接清班登玉陛，同承別詔直金鑾。',64,'全唐诗/poet.tang.23000.json','["早接清班登玉陛，同承別詔直金鑾。", "鳳巢閣上容身穩，鶴鏁籠中展翅難。", "流落多年應是命，量移遠郡未成官。", "慙君獨不欺顦顇，猶作銀臺舊眼看。"]'),
('a9751b3a-7a9d-4354-a74a-dd9beb5dfc3b','對鏡吟','白居易','唐','唐诗','tang','','[]','閑看明鏡坐清晨，多病姿容半老身。',64,'全唐诗/poet.tang.23000.json','["閑看明鏡坐清晨，多病姿容半老身。", "誰論情性乖時事，自想形骸非貴人。", "三殿失恩宜放棄，九宮推命合漂淪。", "如今所得須甘分，腰佩銀龜朱兩輪。"]'),
('53e02f22-5213-4ef0-8258-451dfe9d5052','江州赴忠州至江陵已來舟中示舍弟五十韻','白居易','唐','唐诗','tang','','[]','昔作咸秦客，常思江海行。',288,'全唐诗/poet.tang.23000.json','["昔作咸秦客，常思江海行。", "今來仍盡室，此去又專城。", "典午猶爲幸，分憂固是榮。", "箳篂州乘送，艛艓驛船迎。", "共載皆妻子，同遊即弟兄。", "寧辭浪跡遠，且貴賞心幷。", "雲展帆高挂，飆馳櫂迅征。", "泝流從漢浦，循路轉荆衡。", "山逐時移色，江隨地改名。", "風光近東早，水木向南清。", "夏口煙孤起，湘川雨半晴。", "日煎紅浪沸，月射白砂明。", "北渚寒留雁，南枝暖待鶯。", "駢朱桃露萼，點翠柳含萌。", "亥市魚鹽聚，神林鼓笛鳴。", "壺漿椒葉氣，歌曲竹枝聲。", "繫纜憐沙靜，垂綸愛岸平。", "水飡紅粒稻，野茹紫花菁。", "甌汎茶如乳，臺黏酒似餳。", "膾長抽錦縷，藕脆削瓊英。", "容易來千里，斯須進一程。", "未曾勞氣力，漸覺有心情。", "臥穩添春睡，行遲帶酒酲。", "忽愁牽世網，便欲濯塵纓。"]'),
('e229e9d5-aeae-4a03-aa03-d0a8970f27b1','題岳陽樓','白居易','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','岳陽城下水漫漫，獨上危樓倚曲欄。',64,'全唐诗/poet.tang.23000.json','["岳陽城下水漫漫，獨上危樓倚曲欄。", "春岸綠時連夢澤，夕波紅處近長安。", "猨攀樹立啼何苦，雁點湖飛渡亦難。", "此地唯堪畫圖障，華堂張與貴人看。"]'),
('9af6afbe-fec1-48b8-a633-d9af51587254','入峽次巴東','白居易','唐','唐诗','tang','','[]','不知遠郡何時到，猶喜全家此去同。',64,'全唐诗/poet.tang.23000.json','["不知遠郡何時到，猶喜全家此去同。", "萬里王程三峽外，百年生計一舟中。", "巫山暮足霑花雨，隴水春多逆浪風。", "兩片紅旌數聲鼓，使君艛艓上巴東。"]'),
('26bd5c77-3ac8-4384-b873-d1b76d5df8dd','十年三月三十日別微之於[灃]上十四年三月十一日夜遇微之於峽中停舟夷陵三宿而別言不盡者以詩終之因賦七言十七韻以贈且欲記所遇之地與相見之時爲他年會話張本也','白居易','唐','唐诗','tang','','[]','[灃]水店頭春盡日，送君上馬謫通川。',274,'全唐诗/poet.tang.23000.json','["[灃]水店頭春盡日，送君上馬謫通川。", "夷陵峽口明月夜，此處逢君是偶然。", "一別五年方見面，相攜三宿未迴船。", "坐從日暮唯長歎，語到天明竟未眠。", "齒髮蹉跎將五十，關河迢遞過三千。", "生涯共寄滄江上，鄉國俱拋白日邊。", "往事渺茫都似夢，舊遊流落半歸泉。", "醉悲灑淚春杯裏，吟苦支頤曉燭前。", "莫問龍鍾惡官職，且聽清脆好文篇。", "別來只是成詩癖，老去何曾更酒顛。", "各限王程須去住，重開離宴貴留連。", "黃牛渡北移征櫂，白狗崖東卷別筵。", "神女臺雲閑繚繞，使君灘水急潺湲。", "風淒暝色愁楊柳，月弔宵聲哭杜鵑。", "萬丈赤幢潭底日，一條白練峽中天。", "君還秦地辭炎徼，我向忠州入瘴煙。", "未死會應相見在，又知何地復何年。"]'),
('42dfacb7-79f8-4b80-8ab7-da5b3197baa5','題峽中石上','白居易','唐','唐诗','tang','','[]','巫女廟花紅似粉，昭君村柳翠於眉。',32,'全唐诗/poet.tang.23000.json','["巫女廟花紅似粉，昭君村柳翠於眉。", "誠知老去風情少，見此爭無一句詩。"]'),
('fd4fa892-989a-4f8a-b9ba-3b68eff6b719','夜入瞿唐峽','白居易','唐','唐诗','tang','','[]','瞿唐天下險，夜上信難哉。',48,'全唐诗/poet.tang.23000.json','["瞿唐天下險，夜上信難哉。", "岸似雙屏合，天如匹帛開。", "逆風驚浪起，拔𥮘暗船來。", "欲識愁多少，高於灩澦堆。"]'),
('c748e5bc-613c-4f37-8e9b-c636a4e92529','初到忠州贈李六','白居易','唐','唐诗','tang','','[]','好在天涯李使君，江頭相見日黃昏。',64,'全唐诗/poet.tang.23000.json','["好在天涯李使君，江頭相見日黃昏。", "吏人生梗都如鹿，市井疎蕪只抵村。", "一隻蘭船當驛路，百層石磴上州門。", "更無平地堪行處，虛受朱輪五馬恩。"]'),
('30489107-e4aa-4a33-b646-7924f618ec87','郡齋暇日憶廬山草堂兼寄二林僧社三十韻多敘貶官已來出處之意','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','諫諍知無補，遷移分所當。',288,'全唐诗/poet.tang.23000.json','["諫諍知無補，遷移分所當。", "不堪匡聖主，只合事空王。", "龍象投新社，鵷鸞失故行。", "沈吟辭北闕，誘引向西方。", "便住雙林寺，仍開一草堂。", "平治行道路，安置坐禪牀。", "手版支爲枕，頭巾閣在牆。", "先生烏几舃，居士白衣裳。", "竟歲何曾悶，終身不擬忙。", "滅除殘夢想，換盡舊心腸。", "世界多煩惱，形神久損傷。", "正從風鼓浪，轉作日銷霜。", "吾道尋知止，君恩偶未忘。", "忽蒙頒鳳詔，兼謝剖魚章。", "蓮靜方依水，葵枯重仰陽。", "三車猶夕會，五馬已晨裝。", "去似尋前世，來如別故鄉。", "眉低出鷲嶺，脚重下虵岡。", "漸望廬山遠，彌愁峽路長。", "香爐峰隱隱，巴字水茫茫。", "瓢挂留庭樹，經收在屋梁。", "春拋紅藥圃，夏憶白蓮塘。", "唯擬捐塵事，將何荅寵光。", "有期追永遠，無政繼龔黃。"]'),
('632f4dfa-6ae7-4d7c-a6af-4c8c7e180e8f','贈康叟','白居易','唐','唐诗','tang','','[]','八十秦翁老不歸，南賓太守乞寒衣。',32,'全唐诗/poet.tang.23000.json','["八十秦翁老不歸，南賓太守乞寒衣。", "再三憐汝非他意，天寶遺民見漸稀。"]'),
('f456d5bf-3eb1-47b0-80ae-322d3f1ad9ca','鸚鵡','白居易','唐','唐诗','tang','','[]','竟日語還默，中宵棲復驚。',48,'全唐诗/poet.tang.23000.json','["竟日語還默，中宵棲復驚。", "身囚緣彩翠，心苦爲分明。", "暮起歸巢思，春多憶侶聲。", "誰能拆籠破，從放快飛鳴。"]'),
('7b237287-cfeb-4e49-adab-723d53050128','京使回累得南省諸公書因以長句詩寄謝蕭五劉二元八吳十一韋大陸郎中崔二十二牛二李七庾三十二李六李十楊三樊大楊十二員外','白居易','唐','唐诗','tang','','[]','雪壓泥埋未死身，每勞存問媿交親。',64,'全唐诗/poet.tang.23000.json','["雪壓泥埋未死身，每勞存問媿交親。", "浮萍飄泊三千里，列宿參差十五人。", "禁月落時君待漏，畬煙深處我行春。", "瘴鄉得老猶爲幸，豈敢傷嗟白髮新。"]'),
('7a98546e-39d4-4784-b36e-41107d43b12a','東城春意','白居易','唐','唐诗','tang','','[]','風輭雲不動，郡城東北隅。',48,'全唐诗/poet.tang.23000.json','["風輭雲不動，郡城東北隅。", "晚來春澹澹，天氣似京都。", "弦管隨宜有，杯觴不道無。", "其如親故遠，無可共歡娛。"]'),
('9d551104-88c1-4011-b24a-2ef8f5e60731','木蓮樹生巴峽山谷間巴民亦呼爲黃心樹大者高五丈涉冬不凋身如青楊有白文葉如桂厚大無脊花如蓮香色豔膩皆同獨房蘂有異四月初始開自開迨謝僅二十日忠州西北十里有鳴玉谿生者穠茂尤異元和十四年夏命道士母丘元志寫惜其遐僻因題三絕句云 一','白居易','唐','唐诗','tang','','[]','如折芙蓉栽旱地，似拋芍藥挂高枝。',32,'全唐诗/poet.tang.23000.json','["如折芙蓉栽旱地，似拋芍藥挂高枝。", "雲埋水隔無人識，唯有南賓太守知。"]'),
('cd904f43-b9eb-4e30-a3fe-f2bcb215a8db','木蓮樹生巴峽山谷間巴民亦呼爲黃心樹大者高五丈涉冬不凋身如青楊有白文葉如桂厚大無脊花如蓮香色豔膩皆同獨房蘂有異四月初始開自開迨謝僅二十日忠州西北十里有鳴玉谿生者穠茂尤異元和十四年夏命道士母丘元志寫惜其遐僻因題三絕句云 二','白居易','唐','唐诗','tang','','[]','紅似燕支膩如粉，傷心好物不須臾。',32,'全唐诗/poet.tang.23000.json','["紅似燕支膩如粉，傷心好物不須臾。", "山中風起無時節，明日重來得在無。"]'),
('78975868-daef-40f6-89f2-1aa8b5308c55','木蓮樹生巴峽山谷間巴民亦呼爲黃心樹大者高五丈涉冬不凋身如青楊有白文葉如桂厚大無脊花如蓮香色豔膩皆同獨房蘂有異四月初始開自開迨謝僅二十日忠州西北十里有鳴玉谿生者穠茂尤異元和十四年夏命道士母丘元志寫惜其遐僻因題三絕句云 三','白居易','唐','唐诗','tang','','[]','已愁花落荒巖底，復恨根生亂石間。',32,'全唐诗/poet.tang.23000.json','["已愁花落荒巖底，復恨根生亂石間。", "幾度欲移移不得，天教拋擲在深山。"]'),
('bf541abf-a84b-4cbe-85e8-f9749fdf29e2','種桃杏','白居易','唐','唐诗','tang','','[]','無論海角與天涯，大抵心安即是家。',48,'全唐诗/poet.tang.23000.json','["無論海角與天涯，大抵心安即是家。", "路遠誰能念鄉曲，年深兼欲忘京華。", "忠州且作三年計，種杏栽桃擬待花。"]'),
('cf3c148b-5f04-40b0-b1a9-56a8c8415690','新秋','白居易','唐','唐诗','tang','','[]','二毛生鏡日，一葉落庭時。',48,'全唐诗/poet.tang.23000.json','["二毛生鏡日，一葉落庭時。", "老去爭由我，愁來欲泥誰。", "空銷閑歲月，不見舊親知。", "唯弄扶牀女，時時強展眉。"]'),
('1d612240-accd-4b78-9240-1d8965c02dbf','龍昌寺荷池','白居易','唐','唐诗','tang','','[]','冷碧新秋水，殘紅半破蓮。',24,'全唐诗/poet.tang.23000.json','["冷碧新秋水，殘紅半破蓮。", "從來寥落意，不似此池邊。"]'),
('633e01a6-7b1a-4999-92e3-e7b22f302aac','聽竹枝贈李侍御','白居易','唐','唐诗','tang','','[]','巴童巫女竹枝歌，懊惱何人怨咽多。',32,'全唐诗/poet.tang.23000.json','["巴童巫女竹枝歌，懊惱何人怨咽多。", "暫聽遣君猶悵望，長聞教我復如何。"]'),
('af16a9d7-99f9-440e-b4b6-2f6a101f3369','寄胡餅與楊萬州','白居易','唐','唐诗','tang','','[]','胡麻餅樣學京都，麪脆油香新出爐。',32,'全唐诗/poet.tang.23000.json','["胡麻餅樣學京都，麪脆油香新出爐。", "寄與飢饞楊大使，嘗看得似輔興無。"]'),
('442e03c3-9c14-4387-ab06-dd73c2c570b8','感櫻桃花因招飲客','白居易','唐','唐诗','tang','','[]','櫻桃昨夜開如雪，鬢髮今年白如霜。',48,'全唐诗/poet.tang.23000.json','["櫻桃昨夜開如雪，鬢髮今年白如霜。", "漸覺花前成老醜，何曾酒後更顛狂。", "誰能聞此來相勸，共泥春風醉一場。"]'),
('f013cfc5-58b2-440a-9873-7a3cc0f06df4','東亭閑望','白居易','唐','唐诗','tang','','[]','東亭盡日坐，誰伴寂寥身。',48,'全唐诗/poet.tang.23000.json','["東亭盡日坐，誰伴寂寥身。", "綠桂爲佳客，紅蕉當美人。", "笑言雖不接，情狀似相親。", "不作悠悠想，如何度晚春。"]'),
('69bbc13d-432c-43fd-b77b-5beb46825893','畫木蓮花圖寄元郎中','白居易','唐','唐诗','tang','','[]','花房膩似紅蓮朵，豔色鮮如紫牡丹。',32,'全唐诗/poet.tang.23000.json','["花房膩似紅蓮朵，豔色鮮如紫牡丹。", "唯有詩人能解愛，丹青寫出與君看。"]'),
('8429e384-8f41-480d-93bc-f5f3939fabe1','和李澧州題韋開州經藏詩','白居易','唐','唐诗','tang','','[]','既悟蓮花藏，須遺貝葉書。',48,'全唐诗/poet.tang.23000.json','["既悟蓮花藏，須遺貝葉書。", "菩提無處所，文字本空虛。", "觀指非知月，忘筌是得魚。", "聞君登彼岸，捨筏復何如。"]'),
('c7e9b291-b43b-4c27-8614-68de06de5295','九日題塗溪','白居易','唐','唐诗','tang','','[]','蕃草席鋪楓葉岸，竹枝歌送菊花杯。',32,'全唐诗/poet.tang.23000.json','["蕃草席鋪楓葉岸，竹枝歌送菊花杯。", "明年尚作南賓守，或可重陽更一來。"]'),
('04a4e1bc-8d5e-494b-a544-488aaf9eb0ea','即事寄微之','白居易','唐','唐诗','tang','','[]','畬田澀米不耕鉏，旱地荒園少菜蔬。',64,'全唐诗/poet.tang.23000.json','["畬田澀米不耕鉏，旱地荒園少菜蔬。", "想念土風今若此，料看生計合何如。", "衣縫紕纇黃絲絹，飯下腥鹹白小魚。", "飽暖飢寒何足道，此身長短是空虛。"]'),
('46dacd68-1e8b-41fa-b15f-f5a9ced5652e','題郡中荔枝詩十八韻兼寄萬州楊八使君','白居易','唐','唐诗','tang','','[]','奇果標南土，芳林對北堂。',216,'全唐诗/poet.tang.23000.json','["奇果標南土，芳林對北堂。", "素華春漠漠，丹實夏煌煌。", "葉捧低垂戶，枝擎重壓牆。", "始因風弄色，漸與日爭光。", "夕訝條懸火，朝驚樹點妝。", "深於紅躑躅，大校白檳榔。", "星綴連心朵，珠排耀眼房。", "紫羅裁襯殼，白玉裹填瓤。", "早歲曾聞說，今朝始摘嘗。", "嚼疑天上味，嗅異世間香。", "潤勝蓮生水，鮮逾橘得霜。", "燕支掌中顆，甘露舌頭漿。", "物少尤珍重，天高苦渺茫。", "已教生暑月，又使阻遐方。", "粹液靈難駐，妍姿嫩易傷。", "近南光景熱，向北道途長。", "不得充王賦，無由寄帝鄉。", "唯君堪擲贈，面白似潘郎。"]'),
('ba41a17b-454e-4643-b513-d1d9559fa971','留北客','白居易','唐','唐诗','tang','','[]','峽外相逢遠，樽前一會難。',48,'全唐诗/poet.tang.23000.json','["峽外相逢遠，樽前一會難。", "即須分手別，且強展眉歡。", "楚袖蕭條舞，巴弦趣數彈。", "笙歌隨分有，莫作帝鄉看。"]'),
('56e0d3a3-858b-4aa9-9227-e73b3c63265b','重寄荔枝與楊使君時聞楊使君欲種植故有落句之戲','白居易','唐','唐诗','tang','','[]','摘來正帶凌晨露，寄去須憑下水船。',64,'全唐诗/poet.tang.23000.json','["摘來正帶凌晨露，寄去須憑下水船。", "映我緋衫渾不見，對公銀印最相鮮。", "香連翠葉真堪畫，紅透青籠實可憐。", "聞道萬州方欲種，愁君得喫是何年。"]'),
('bf3103b8-41e4-4193-a126-22fa56214f25','和萬州楊使君四絕句 競渡','白居易','唐','唐诗','tang','','[]','競渡相傳爲汨羅，不能止遏意無他。',32,'全唐诗/poet.tang.23000.json','["競渡相傳爲汨羅，不能止遏意無他。", "自經放逐來顦顇，能校靈均死幾多。"]'),
('ebdb2dd1-2185-40d6-82ec-418d3f1a0326','和萬州楊使君四絕句 江邊草','白居易','唐','唐诗','tang','','[]','聞君澤畔傷春草，憶在天門街裏時。',32,'全唐诗/poet.tang.23000.json','["聞君澤畔傷春草，憶在天門街裏時。", "漠漠淒淒愁滿眼，就中惆悵是江蘺。"]'),
('bff42b52-6adf-4aab-82e2-330dff72a2ea','和萬州楊使君四絕句 嘉慶李','白居易','唐','唐诗','tang','','[]','東都綠李萬州栽，君手封題我手開。',32,'全唐诗/poet.tang.23000.json','["東都綠李萬州栽，君手封題我手開。", "把得欲嘗先悵望，與渠同別故鄉來。"]'),
('2488945f-090b-4316-975c-7dcc9b0e0f30','和萬州楊使君四絕句 白槿花','白居易','唐','唐诗','tang','','[]','秋蕣晚英無豔色，何因栽種在人家。',32,'全唐诗/poet.tang.23000.json','["秋蕣晚英無豔色，何因栽種在人家。", "使君自別羅敷面，爭解回頭愛白花。"]'),
('f6aebb26-626c-406f-94bc-ed747e029b70','和行簡望郡南山','白居易','唐','唐诗','tang','','[]','反照前山雲樹明，從君苦道似華清。',32,'全唐诗/poet.tang.23000.json','["反照前山雲樹明，從君苦道似華清。", "試聽腸斷巴猨呌，早晚驪山有此聲。"]'),
('203986a4-5636-4f5f-b145-a4c2c6c47554','種荔枝','白居易','唐','唐诗','tang','','[]','紅顆珍珠誠可愛，白鬚太守亦何癡。',32,'全唐诗/poet.tang.23000.json','["紅顆珍珠誠可愛，白鬚太守亦何癡。", "十年結子知誰在，自向庭中種荔枝。"]'),
('479e0900-3ebc-4812-a0ce-93b96238c3b0','陰雨','白居易','唐','唐诗','tang','','["\u601d\u4e61"]','嵐霧今朝重，江山此地深。',48,'全唐诗/poet.tang.23000.json','["嵐霧今朝重，江山此地深。", "灘聲秋更急，峽氣曉多陰。", "望闕雲遮眼，思鄉雨滴心。", "將何慰幽獨，賴此北窗琴。"]'),
('3b19db1d-14ec-42cf-854f-3c8680f69741','送客歸京','白居易','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b"]','水陸四千里，何時歸到秦？',48,'全唐诗/poet.tang.23000.json','["水陸四千里，何時歸到秦？", "舟辭三峽雨，馬入九衢塵。", "有酒留行客，無書寄貴人。", "唯憑遠傳語，好在曲江春。"]'),
('21dacc44-7329-44dd-9cde-2b66b4c43ce6','送蕭處士遊黔南','白居易','唐','唐诗','tang','','[]','能文好飲老蕭郎，身似浮雲鬢似霜。',64,'全唐诗/poet.tang.23000.json','["能文好飲老蕭郎，身似浮雲鬢似霜。", "生計拋來詩是業，家園忘却酒爲鄉。", "江從巴峽初成字，猨過巫陽始斷腸。", "不醉黔中爭去得，磨圍山月正蒼蒼。"]'),
('bb30ac5b-307b-4e79-b821-babf23112fb4','東樓醉','白居易','唐','唐诗','tang','','[]','天涯深峽無人地，歲暮窮陰欲夜天。',32,'全唐诗/poet.tang.23000.json','["天涯深峽無人地，歲暮窮陰欲夜天。", "不向東樓時一醉，如何擬過二三年。"]'),
('97e05dad-388b-4f77-adce-07958e3995f0','寄微之','白居易','唐','唐诗','tang','','[]','高天默默物茫茫，各有來由致損傷。',64,'全唐诗/poet.tang.23000.json','["高天默默物茫茫，各有來由致損傷。", "鸚爲能言長剪翅，龜緣難死久搘牀。", "莫嫌冷落拋閑地，猶勝炎蒸臥瘴鄉。", "外物竟關身底事，謾排門戟繫腰章。"]'),
('9a150ff6-124f-4aef-b62e-906b99c82f0c','東樓招客夜飲','白居易','唐','唐诗','tang','','[]','莫辭數數醉東樓，除醉無因破得愁。',32,'全唐诗/poet.tang.23000.json','["莫辭數數醉東樓，除醉無因破得愁。", "唯有綠樽紅燭下，暫時不似在忠州。"]'),
('acac50a2-b345-4810-9479-e28676c4861f','醉後戲題','白居易','唐','唐诗','tang','','[]','自知清冷似冬凌，每被人呼作律僧。',32,'全唐诗/poet.tang.23000.json','["自知清冷似冬凌，每被人呼作律僧。", "今夜酒醺羅綺暖，被君融盡玉壺冰。"]'),
('3212583f-5efa-4b6b-a56c-30f3d26300bd','冬至夜','白居易','唐','唐诗','tang','','[]','老去襟懷常濩落，病來鬚鬢轉蒼浪。',64,'全唐诗/poet.tang.23000.json','["老去襟懷常濩落，病來鬚鬢轉蒼浪。", "心灰不及爐中火，鬢雪多於砌下霜。", "三峽南賓城最遠，一年冬至夜偏長。", "今宵始覺房櫳冷，坐索寒衣託孟光。"]'),
('23b7387a-eb23-46c4-a30a-ef743d1faf4c','竹枝詞四首 一','白居易','唐','唐诗','tang','','[]','瞿唐峽口水煙低，白帝城頭月向西。',32,'全唐诗/poet.tang.23000.json','["瞿唐峽口水煙低，白帝城頭月向西。", "唱到竹枝聲咽處，寒猨闇鳥一時啼。"]'),
('89cd799a-026b-41e4-9a3a-b60a72745926','竹枝詞四首 二','白居易','唐','唐诗','tang','','[]','竹枝苦怨怨何人，夜靜山空歇又聞。',32,'全唐诗/poet.tang.23000.json','["竹枝苦怨怨何人，夜靜山空歇又聞。", "蠻兒巴女齊聲唱，愁殺江樓病使君。"]'),
('ebabd8f5-ebcf-462d-8f46-458f1ffe3689','竹枝詞四首 三','白居易','唐','唐诗','tang','','[]','巴東船舫上巴西，波面風生雨脚齊。',32,'全唐诗/poet.tang.23000.json','["巴東船舫上巴西，波面風生雨脚齊。", "水蓼冷花紅簇簇，江蘺濕葉碧淒淒。"]'),
('4c5ffce3-25e0-46ad-9b17-312f7ea6a8b0','竹枝詞四首 四','白居易','唐','唐诗','tang','','[]','江畔誰人唱竹枝，前聲斷咽後聲遲。',32,'全唐诗/poet.tang.23000.json','["江畔誰人唱竹枝，前聲斷咽後聲遲。", "怪來調苦緣詞苦，多是通州司馬詩。"]'),
('c938ab01-98dc-4238-a2e1-8b14252323b4','酬嚴中丞晚眺黔江見寄','白居易','唐','唐诗','tang','','[]','江水三迴曲，愁人兩地情。',48,'全唐诗/poet.tang.23000.json','["江水三迴曲，愁人兩地情。", "磨圍山下色，明月峽中聲。", "晚後連天碧，秋來徹底清。", "臨流有新恨，照見白鬚生。"]'),
('444fab89-095f-44d4-ac36-25b5d8c38eac','寄題楊萬州四望樓','白居易','唐','唐诗','tang','','[]','江上新樓名四望，東西南北水茫茫。',32,'全唐诗/poet.tang.23000.json','["江上新樓名四望，東西南北水茫茫。", "無由得與君攜手，同凭欄干一望鄉。"]'),
('00722fda-b954-4c36-95b5-b34d2abb7191','荅楊使君登樓見憶','白居易','唐','唐诗','tang','','[]','忠萬樓中南北望，南州煙水北州雲。',32,'全唐诗/poet.tang.23000.json','["忠萬樓中南北望，南州煙水北州雲。", "兩州何事偏相憶，各是籠禽作使君。"]'),
('f1702789-f0bc-4e5d-acd1-488e66fcd3ad','除夜','白居易','唐','唐诗','tang','','[]','歲暮紛多思，天涯渺未歸。',48,'全唐诗/poet.tang.23000.json','["歲暮紛多思，天涯渺未歸。", "老添新甲子，病減舊容輝。", "鄉國仍留念，功名已息機。", "明朝四十九，應轉悟前非。"]'),
('b9e7849b-cd10-4108-ae2f-83f882e48893','聞雷','白居易','唐','唐诗','tang','','[]','瘴地風霜早，溫天氣候催。',48,'全唐诗/poet.tang.23000.json','["瘴地風霜早，溫天氣候催。", "窮冬不見雪，正月已聞雷。", "震蟄蟲蛇出，驚枯草木開。", "空餘客方寸，依舊似寒灰。"]'),
('8d3276c8-262b-4c4f-a0b0-879aa318b53f','春至','白居易','唐','唐诗','tang','','[]','若爲南國春還至，爭向東樓日又長。',64,'全唐诗/poet.tang.23000.json','["若爲南國春還至，爭向東樓日又長。", "白片落梅浮澗水，黃梢新柳出城牆。", "閑拈蕉葉題詩詠，悶取藤枝引酒嘗。", "樂事漸無身漸老，從今始擬負風光。"]'),
('2b2d6510-fe0b-47ab-af02-5c5acf156b16','感春','白居易','唐','唐诗','tang','','[]','巫峽中心郡，巴城四面春。',48,'全唐诗/poet.tang.23000.json','["巫峽中心郡，巴城四面春。", "草青臨水地，頭白見花人。", "憂喜皆心火，榮枯是眼塵。", "除非一杯酒，何物更關身。"]'),
('de4a0501-d768-43c5-a889-403f5873633f','春江','白居易','唐','唐诗','tang','','[]','炎涼昏曉苦推遷，不覺忠州已二年。',64,'全唐诗/poet.tang.23000.json','["炎涼昏曉苦推遷，不覺忠州已二年。", "閉閣只聽朝暮鼓，上樓空望往來船。", "鶯聲誘引來花下，草色句留坐水邊。", "唯有春江看未厭，縈砂遶石淥潺湲。"]'),
('fda66788-1431-445b-9695-47c696d1265d','題東樓前李使君所種櫻桃花','白居易','唐','唐诗','tang','','[]','身入青雲無見日，手栽紅樹又逢春。',32,'全唐诗/poet.tang.23000.json','["身入青雲無見日，手栽紅樹又逢春。", "唯留花向樓前著，故故拋愁與後人。"]'),
('171fdc90-0c4d-4adf-bda7-f9219337c7d6','巴水','白居易','唐','唐诗','tang','','[]','城下巴江水，春來似麴塵。',48,'全唐诗/poet.tang.23000.json','["城下巴江水，春來似麴塵。", "軟沙如渭曲，斜岸憶天津。", "影蘸新黃柳，香浮小白蘋。", "臨流搔首坐，惆悵爲何人。"]'),
('80a4a379-1e79-4100-ac7d-9ad5f962a769','野行','白居易','唐','唐诗','tang','','[]','草潤衫襟重，沙乾屐齒輕。',48,'全唐诗/poet.tang.23000.json','["草潤衫襟重，沙乾屐齒輕。", "仰頭聽鳥立，信脚望花行。", "暇日無公事，衰年有道情。", "浮生短於夢，夢裏莫營營。"]'),
('7de1bc2c-bb36-4fc4-9a83-65ce422e7b73','送高侍御使迴因寄楊八','白居易','唐','唐诗','tang','','[]','明月峽邊逢制使，黃茅岸上是忠州。',32,'全唐诗/poet.tang.23000.json','["明月峽邊逢制使，黃茅岸上是忠州。", "到城莫說忠州惡，無益虛教楊八愁。"]'),
('ece7bc28-d82a-4330-8383-c9e908d45438','奉酬李相公見示絕句','白居易','唐','唐诗','tang','','[]','碧油幢下捧新詩，榮賤雖殊共一悲。',32,'全唐诗/poet.tang.23000.json','["碧油幢下捧新詩，榮賤雖殊共一悲。", "涕淚滿襟君莫怪，甘泉侍從最多時。"]'),
('10f4de4f-7936-44ee-a4e4-dda652914bb8','喜山石榴花開','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','忠州州裏今日花，廬山山頭去時樹。',64,'全唐诗/poet.tang.23000.json','["忠州州裏今日花，廬山山頭去時樹。", "已憐根損斬新栽，還喜花開依舊數。", "赤玉何人少琴軫，紅纈誰家合羅袴。", "但知爛熳恣情開，莫怕南賓桃李妬。"]'),
('23ceab0e-afd0-4b53-84a7-4d9e1674c30e','戲贈蕭處士清禪師','白居易','唐','唐诗','tang','','[]','三杯嵬峩忘機客，百衲頭陀任運僧。',32,'全唐诗/poet.tang.23000.json','["三杯嵬峩忘機客，百衲頭陀任運僧。", "又有放慵巴郡守，不營一事共騰騰。"]'),
('2506c2cd-d405-4515-b14f-092df16b6741','錢虢州以三堂絕句見寄因以本韻和之','白居易','唐','唐诗','tang','','[]','同事空王歲月深，相思遠寄定中吟。',32,'全唐诗/poet.tang.23000.json','["同事空王歲月深，相思遠寄定中吟。", "遙知清淨中和化，祗用金剛三昧心。"]'),
('8e8220f8-a403-4971-bca6-be3f153ed4ae','三月三日','白居易','唐','唐诗','tang','','[]','暮春風景初三日，流世光陰半百年。',32,'全唐诗/poet.tang.23000.json','["暮春風景初三日，流世光陰半百年。", "欲作閑遊無好伴，半江惆悵却回船。"]'),
('ce9bf8f7-fa18-450a-9e58-08444b7ac03d','寒食夜','白居易','唐','唐诗','tang','','[]','四十九年身老日，一百五夜月明天。',32,'全唐诗/poet.tang.23000.json','["四十九年身老日，一百五夜月明天。", "抱膝思量何事在，癡男騃女喚鞦韆。"]'),
('94f9e46a-1439-40c7-858f-f5067309e5db','代州民問','白居易','唐','唐诗','tang','','[]','龍昌寺底開山路，巴子臺前種柳林。',32,'全唐诗/poet.tang.23000.json','["龍昌寺底開山路，巴子臺前種柳林。", "官職家鄉都忘却，誰人會得使君心。"]'),
('958bc1ea-20bc-445b-8cc0-f947a2f385a2','荅州民','白居易','唐','唐诗','tang','','[]','宦情斗擻隨塵去，鄉思銷磨逐日無。',32,'全唐诗/poet.tang.23000.json','["宦情斗擻隨塵去，鄉思銷磨逐日無。", "唯擬騰騰作閑事，遮渠不道使君愚。"]'),
('ecb015f3-c6e1-4ef6-a6ad-6b6e3f2b8cd2','荔枝樓對酒','白居易','唐','唐诗','tang','','[]','荔枝新熟雞冠色，燒酒初開琥珀香。',32,'全唐诗/poet.tang.23000.json','["荔枝新熟雞冠色，燒酒初開琥珀香。", "欲摘一枝傾一醆，西樓無客共誰嘗。"]'),
('e1d545f9-3865-4e9c-8295-d6bebc07d173','房家夜宴喜雪戲贈主人','白居易','唐','唐诗','tang','','[]','風頭向夜利如刀，賴此溫爐輭錦袍。',64,'全唐诗/poet.tang.23000.json','["風頭向夜利如刀，賴此溫爐輭錦袍。", "桑落氣薰珠翠暖，柘枝聲引管弦高。", "酒鉤送醆推蓮子，燭淚黏盤壘蒲萄。", "不醉遣儂爭散得，門前雪片似鵝毛。"]'),
('cf60bf2c-4b62-4dda-ac15-7e47b542617d','醉後贈人','白居易','唐','唐诗','tang','','[]','香毬趂拍回環匼，花醆拋巡取次飛。',32,'全唐诗/poet.tang.23000.json','["香毬趂拍回環匼，花醆拋巡取次飛。", "自入春來未同醉，那能夜去獨先歸。"]'),
('774ee8de-9b2a-4baa-b4c7-e5a03e56bbe8','初除尚書郎脫刺史緋','白居易','唐','唐诗','tang','','[]','親賓相賀問何如，服色恩光盡反初。',64,'全唐诗/poet.tang.23000.json','["親賓相賀問何如，服色恩光盡反初。", "頭白喜拋黃草峽，眼明驚拆紫泥書。", "便留朱紱還鈴閣，却著青袍侍玉除。", "無奈嬌癡三歲女，繞腰啼哭覓金魚。"]'),
('789f4bc8-dbeb-4367-a69e-4bdeb29e7ae2','留題開元寺上方','白居易','唐','唐诗','tang','','[]','東寺臺閣好，上方風景清。',48,'全唐诗/poet.tang.23000.json','["東寺臺閣好，上方風景清。", "數來猶未厭，長別豈無情。", "戀水多臨坐，辭花剩繞行。", "最憐新岸柳，手種未全成。"]'),
('f99e08b5-1880-4618-949b-c1b40fbdeb35','別種東坡花樹兩絕 一','白居易','唐','唐诗','tang','','[]','三年留滯在江城，草樹禽魚盡有情。',32,'全唐诗/poet.tang.23000.json','["三年留滯在江城，草樹禽魚盡有情。", "何處殷勤重回首，東坡桃李種新成。"]'),
('a67d3f92-8695-4881-9d5b-3eef2d756f46','別種東坡花樹兩絕 二','白居易','唐','唐诗','tang','','[]','花林好住莫顦顇，春至但知依舊春。',32,'全唐诗/poet.tang.23000.json','["花林好住莫顦顇，春至但知依舊春。", "樓上明年新太守，不妨還是愛花人。"]'),
('acef4618-d2e4-40fb-a802-9fa6e9a25a62','別橋上竹','白居易','唐','唐诗','tang','','[]','穿橋迸竹不依行，恐礙行人被損傷。',32,'全唐诗/poet.tang.23000.json','["穿橋迸竹不依行，恐礙行人被損傷。", "我去自慙遺愛少，不教君得似甘棠。"]'),
('50884fc5-3378-4728-9b0f-ce654c8d4c49','發白狗峽次黃牛峽登高寺却望忠州','白居易','唐','唐诗','tang','','[]','白狗次黃牛，灘如竹節稠。',120,'全唐诗/poet.tang.23000.json','["白狗次黃牛，灘如竹節稠。", "路穿天地險，人續古今愁。", "忽見千花塔，因停一葉舟。", "畏途常迫促，靜境暫淹留。", "巴曲春全盡，巫陽雨半收。", "北歸雖引領，南望亦回頭。", "昔去悲殊俗，今來念舊遊。", "別僧山北寺，拋竹水西樓。", "郡樹花如雪，軍廚酒似油。", "時時大開口，自笑憶忠州。"]'),
('cc467fda-cdc8-47ba-b89f-a932ca621684','棣華驛見楊八題夢兄弟詩','白居易','唐','唐诗','tang','','[]','遙聞旅宿夢兄弟，應爲郵亭名棣華。',32,'全唐诗/poet.tang.23000.json','["遙聞旅宿夢兄弟，應爲郵亭名棣華。", "名作棣華來早晚，自題詩後屬楊家。"]'),
('073dff76-9531-4c09-b574-784871d90982','商山路有感','白居易','唐','唐诗','tang','','[]','萬里路長在，六年身始歸。',24,'全唐诗/poet.tang.23000.json','["萬里路長在，六年身始歸。", "所經多舊館，大半主人非。"]'),
('ab777923-6495-41fd-9e1c-6b1991f8384b','商山路驛桐樹昔與微之前後題名處','白居易','唐','唐诗','tang','','[]','與君前後多遷謫，五度經過此路隅。',32,'全唐诗/poet.tang.23000.json','["與君前後多遷謫，五度經過此路隅。", "笑問中庭老桐樹，這回歸去免來無。"]'),
('adf32673-d262-4386-a085-6da843b47136','惻惻吟','白居易','唐','唐诗','tang','','[]','惻惻復惻惻，逐臣返鄉國。',56,'全唐诗/poet.tang.23000.json','["惻惻復惻惻，逐臣返鄉國。", "前事難重論，少年不再得。", "泥塗絳老頭班白，炎瘴靈均面黎黑。", "六年不死却歸來，道著姓名人不識。"]'),
('8a851893-3a56-4c0c-8252-ab34c95847ed','德宗皇帝挽歌詞四首 一','白居易','唐','唐诗','tang','','[]','執象宗玄祖，貽謀啓孝孫。',48,'全唐诗/poet.tang.23000.json','["執象宗玄祖，貽謀啓孝孫。", "文高柏梁殿，禮薄霸陵原。", "宮仗辭天闕，朝儀出國門。", "生成不可報，二十七年恩。"]'),
('bb19b082-1994-4bab-9db2-ebbfb48b14b7','德宗皇帝挽歌詞四首 二','白居易','唐','唐诗','tang','','[]','虞帝南巡後，殷宗諒闇中。',48,'全唐诗/poet.tang.23000.json','["虞帝南巡後，殷宗諒闇中。", "初辭鑄鼎地，已閉望仙宮。", "曉落當陵月，秋生滿斾風。", "前星承帝座，不使北辰空。"]'),
('5d9ad877-fe82-4f2d-826f-77bb1536b359','德宗皇帝挽歌詞四首 三','白居易','唐','唐诗','tang','','[]','業大承宗祖，功成付子孫。',48,'全唐诗/poet.tang.23000.json','["業大承宗祖，功成付子孫。", "睿文詩播樂，遺訓史標言。", "節表中和德，方垂廣利恩。", "懸知千載後，理代數貞元。"]'),
('188af25f-b5f4-483a-b3e9-94a90c4cb49f','德宗皇帝挽歌詞四首 四','白居易','唐','唐诗','tang','','[]','夢減三齡壽，哀延七月期。',48,'全唐诗/poet.tang.23000.json','["夢減三齡壽，哀延七月期。", "寢園愁望遠，宮仗哭行遲。", "雲日添寒慘，笳簫向晚悲。", "因山有遺詔，如葬漢文時。"]'),
('e0320acf-26c6-4029-9157-befdc1296a24','昭德皇后挽歌詞','白居易','唐','唐诗','tang','','[]','仙去逍遙境，詩留窈窕章。',48,'全唐诗/poet.tang.23000.json','["仙去逍遙境，詩留窈窕章。", "春歸金屋少，夜入壽宮長。", "鳳引曾辭輦，蠶休昔採桑。", "陰靈何處感，沙麓月無光。"]'),
('53335b5e-4476-4002-9725-8ed46a2df124','太平樂詞二首 一','白居易','唐','唐诗','tang','','[]','歲豐仍節儉，時泰更銷兵。',24,'全唐诗/poet.tang.23000.json','["歲豐仍節儉，時泰更銷兵。", "聖念長如此，何憂不太平。"]'),
('25ebf58d-7074-4496-bfed-650631544f59','太平樂詞二首 二','白居易','唐','唐诗','tang','','[]','湛露浮堯酒，薰風起舜歌。',24,'全唐诗/poet.tang.23000.json','["湛露浮堯酒，薰風起舜歌。", "願同堯舜意，所樂在人和。"]'),
('fc29c5b0-842d-4b1c-9df5-3390a4e604a9','小曲新詞二首 一','白居易','唐','唐诗','tang','','[]','霽色鮮宮殿，秋聲脆管弦。',24,'全唐诗/poet.tang.23000.json','["霽色鮮宮殿，秋聲脆管弦。", "聖明千歲樂，歲歲似今年。"]'),
('165f9c55-7045-45a9-9ffc-c4f7f32e7379','小曲新詞二首 二','白居易','唐','唐诗','tang','','[]','紅裾明月夜，碧簟早秋時。',24,'全唐诗/poet.tang.23000.json','["紅裾明月夜，碧簟早秋時。", "好向昭陽宿，天涼玉漏遲。"]'),
('9255d903-0ca1-46b3-b84c-0b696aff0da7','閨怨詞三首 一','白居易','唐','唐诗','tang','','[]','朝憎鶯百囀，夜妒燕雙棲。',24,'全唐诗/poet.tang.23000.json','["朝憎鶯百囀，夜妒燕雙棲。", "不慣經春別，誰知到曉啼。"]'),
('7bb82fd9-23d7-44d9-96b0-66f1629b54d9','閨怨詞三首 二','白居易','唐','唐诗','tang','','[]','珠箔籠寒月，紗窗背曉燈。',24,'全唐诗/poet.tang.23000.json','["珠箔籠寒月，紗窗背曉燈。", "夜來巾上淚，一半是春冰。"]'),
('3d792328-badb-4110-83b1-98899c97cefa','閨怨詞三首 三','白居易','唐','唐诗','tang','','[]','關山征戍遠，閨閣別離難。',24,'全唐诗/poet.tang.23000.json','["關山征戍遠，閨閣別離難。", "苦戰應顦顇，寒衣不要寬。"]'),
('1a8a12bb-f9db-4413-9003-1db707f76c77','殘春曲','白居易','唐','唐诗','tang','','[]','禁苑殘鶯三四聲，景遲風慢暮春情。',32,'全唐诗/poet.tang.23000.json','["禁苑殘鶯三四聲，景遲風慢暮春情。", "日西無事牆陰下，閑蹋宮花獨自行。"]'),
('fde3383a-bdde-463e-af8c-4f7ef760c11f','長安春','白居易','唐','唐诗','tang','','["\u6625\u5929", "\u957f\u5b89"]','青門柳枝軟無力，東風吹作黃金色。',32,'全唐诗/poet.tang.23000.json','["青門柳枝軟無力，東風吹作黃金色。", "街東酒薄醉易醒，滿眼春愁銷不得。"]'),
('8b77a8b9-7fc8-44af-9c51-a6f71cf200d0','長樂坡送人賦得愁','白居易','唐','唐诗','tang','','[]','行人南北分征路，流水東西接御溝。',32,'全唐诗/poet.tang.23000.json','["行人南北分征路，流水東西接御溝。", "終日坡前恨離別，謾名長樂是長愁。"]'),
('65521bae-9523-451c-adea-8cf00d7112c6','獨眠吟二首 一','白居易','唐','唐诗','tang','','[]','夜長無睡起階前，寥落星河欲曙天。',32,'全唐诗/poet.tang.23000.json','["夜長無睡起階前，寥落星河欲曙天。", "十五年來明月夜，何曾一夜不孤眠。"]'),
('6d170c72-868d-49ce-be41-7c13bb3b3a4e','獨眠吟二首 二','白居易','唐','唐诗','tang','','[]','獨眠客，夜夜可憐長寂寂。',28,'全唐诗/poet.tang.23000.json','["獨眠客，夜夜可憐長寂寂。", "就中今夜最愁人，涼月清風滿牀席。"]'),
('0e33cdf8-81fa-49a3-8b1b-865be84e1f36','期不至','白居易','唐','唐诗','tang','','[]','紅燭清樽久延佇，出門入門天欲曙。',32,'全唐诗/poet.tang.23000.json','["紅燭清樽久延佇，出門入門天欲曙。", "星稀月落竟不來，煙柳朧朧鵲飛去。"]'),
('d93bace5-33ff-43ba-82b7-7eab3d95d23b','長洲苑','白居易','唐','唐诗','tang','','[]','春入長洲草又生，鷓鴣飛起少人行。',32,'全唐诗/poet.tang.23000.json','["春入長洲草又生，鷓鴣飛起少人行。", "年深不辨娃宮處，夜夜蘇臺空月明。"]'),
('c5cc9e9d-2185-4065-9708-0127df87b4bf','憶江柳','白居易','唐','唐诗','tang','','[]','曾栽楊柳江南岸，一別江南兩度春。',32,'全唐诗/poet.tang.23000.json','["曾栽楊柳江南岸，一別江南兩度春。", "遙憶青青江岸上，不知攀折是何人。"]'),
('7af526a7-954b-470a-acef-2d18b99b6c3f','南浦別','白居易','唐','唐诗','tang','','["\u9001\u522b", "\u60dc\u522b", "\u5199\u666f"]','南浦淒淒別，西風嫋嫋秋。',24,'全唐诗/poet.tang.23000.json','["南浦淒淒別，西風嫋嫋秋。", "一看腸一斷，好去莫回頭。"]'),
('ff415cf4-47c5-4096-9c99-a8bd5d5f1be2','三年別','白居易','唐','唐诗','tang','','[]','悠悠一別已三年，相望相思明月天。',32,'全唐诗/poet.tang.23000.json','["悠悠一別已三年，相望相思明月天。", "腸斷青天望明月，別來三十六回圓。"]'),
('41688542-8360-4b7f-add4-2d149566cf1e','傷春詞','白居易','唐','唐诗','tang','','[]','深淺簷花千萬枝，碧紗窗外囀黃鸝。',32,'全唐诗/poet.tang.23000.json','["深淺簷花千萬枝，碧紗窗外囀黃鸝。", "殘妝含淚下簾坐，盡日傷春春不知。"]'),
('549a5a94-a8f5-436e-bc9c-1253d01c1940','後宮詞','白居易','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u5bab\u6028"]','淚濕羅巾夢不成，夜深前殿按歌聲。',32,'全唐诗/poet.tang.23000.json','["淚濕羅巾夢不成，夜深前殿按歌聲。", "紅顏未老恩先斷，斜倚薰籠坐到明。"]'),
('1f2a429b-3f66-4400-91f6-52321af3e9ae','吟元郎中白鬚詩兼飲雪水茶因題壁上','白居易','唐','唐诗','tang','','[]','吟詠霜毛句，閑嘗雪水茶。',24,'全唐诗/poet.tang.23000.json','["吟詠霜毛句，閑嘗雪水茶。", "城中展眉處，只是有元家。"]'),
('914d8737-f588-475d-944e-f3a06e3f78bd','吳七郎中山人待制班中偶贈絕句','白居易','唐','唐诗','tang','','[]','金馬東門隻日開，漢庭待詔重仙才。',32,'全唐诗/poet.tang.23000.json','["金馬東門隻日開，漢庭待詔重仙才。", "第三松樹非華表，那得遼東鶴下來。"]'),
('7f1b722a-c327-453e-8365-2444fce63a33','和張十八祕書謝裴相公寄馬','白居易','唐','唐诗','tang','','[]','齒齊臕足毛頭膩，祕閣張郎叱撥駒。',64,'全唐诗/poet.tang.23000.json','["齒齊臕足毛頭膩，祕閣張郎叱撥駒。", "洗了頷花翻假錦，走時蹄汗蹋真珠。", "青衫乍見曾驚否，紅粟難賒得飽無。", "丞相寄來應有意，遣君騎去上雲衢。"]'),
('17e7e246-fdf9-443c-a374-2c8c5b40707b','荅山侶','白居易','唐','唐诗','tang','','[]','頷下髭鬚半是絲，光陰向後幾多時。',64,'全唐诗/poet.tang.23000.json','["頷下髭鬚半是絲，光陰向後幾多時。", "非無解挂簪纓意，未有支持伏臘資。", "冒熱衝寒徒自取，隨行逐隊欲何爲。", "更慙山侶頻傳語，五十歸來道未遲。"]'),
('7d60ceb8-4507-455c-96ed-f8ea5c2407a0','早朝思退居','白居易','唐','唐诗','tang','','[]','霜嚴月苦欲明天，忽憶閑居思浩然。',64,'全唐诗/poet.tang.23000.json','["霜嚴月苦欲明天，忽憶閑居思浩然。", "自問寒燈夜半起，何如暖被日高眠。", "唯慙老病披朝服，莫慮飢寒計俸錢。", "隨有隨無且歸去，擬求豐足是何年。"]'),
('e1de1860-2761-4c0b-9938-bf6c431dcd47','曲江亭晚望','白居易','唐','唐诗','tang','','[]','曲江岸北凭欄干，水面陰生日脚殘。',64,'全唐诗/poet.tang.23000.json','["曲江岸北凭欄干，水面陰生日脚殘。", "塵路行多綠袍故，風亭立久白鬚寒。", "詩成闇著閑心記，山好遙偷病眼看。", "不被馬前提省印，何人信道是郎官。"]'),
('13ef97d5-f79b-46d5-82f3-4b6c88bce845','初除主客郎中知制誥與王十一李七元九三舍人中書同宿話舊感懷','白居易','唐','唐诗','tang','','[]','閑宵靜話喜還悲，聚散窮通不自知。',64,'全唐诗/poet.tang.23000.json','["閑宵靜話喜還悲，聚散窮通不自知。", "已分雲泥行異路，忽驚雞鶴宿同枝。", "紫垣曹署榮華地，白髮郎官老醜時。", "莫怪不如君氣味，此中來校十年遲。"]'),
('3c68a211-b963-421a-8cb9-04a5040e32fa','西省對花憶忠州東坡新花樹因寄題東樓','白居易','唐','唐诗','tang','','[]','每看闕下丹青樹，不忘天邊錦繡林。',64,'全唐诗/poet.tang.23000.json','["每看闕下丹青樹，不忘天邊錦繡林。", "西掖垣中今日眼，南賓樓上去年心。", "花含春意無分別，物感人情有淺深。", "最憶東坡紅爛熳，野桃山杏水林檎。"]'),
('bc45b8e6-8555-4f89-ac9c-a8247307f116','寄題忠州小樓桃花','白居易','唐','唐诗','tang','','[]','再遊巫峽知何日，總是秦人說向誰。',32,'全唐诗/poet.tang.23000.json','["再遊巫峽知何日，總是秦人說向誰。", "長憶小樓風月夜，紅欄干上兩三枝。"]'),
('bedb5f30-e1df-4431-9aa2-bab94c0dff05','中書連直寒食不歸因懷元九','白居易','唐','唐诗','tang','','[]','去歲清明日，南巴古郡樓。',72,'全唐诗/poet.tang.23000.json','["去歲清明日，南巴古郡樓。", "今年寒食夜，西省鳳池頭。", "併上新人直，難隨舊伴遊。", "誠知視草貴，未免對花愁。", "鬢髮莖莖日，光陰寸寸流。", "經春不同宿，何異在忠州。"]'),
('8661a6e1-0cb2-4a02-971c-86388d68b6ca','春憶二林寺舊遊因寄朗滿晦三上人','白居易','唐','唐诗','tang','','[]','一別東林三度春，每春常似憶情親。',64,'全唐诗/poet.tang.23000.json','["一別東林三度春，每春常似憶情親。", "頭陀會裏爲逋客，供俸班中作老臣。", "清淨久辭香火伴，塵勞難索幻泡身。", "最慚僧社題橋處，十八人名空一人。"]'),
('131539b8-e2f5-4d1f-a943-920eb27ff997','和元少尹新授官','白居易','唐','唐诗','tang','','[]','官穩身應泰，春風信馬行。',48,'全唐诗/poet.tang.23000.json','["官穩身應泰，春風信馬行。", "縱忙無苦事，雖病有心情。", "厚祿兒孫飽，前驅道路榮。", "花時八入直，無暇賀元兄。"]'),
('5d6f2061-07b8-494c-94ce-f770bee69a0d','朝回和元少尹絕句','白居易','唐','唐诗','tang','','[]','朝客朝回回望好，盡紆朱紫佩金銀。',32,'全唐诗/poet.tang.23000.json','["朝客朝回回望好，盡紆朱紫佩金銀。", "此時獨與君爲伴，馬上青袍唯兩人。"]'),
('855c193e-1d9d-4457-abb5-167c47c0bf4d','重和元少尹','白居易','唐','唐诗','tang','','[]','鳳閣舍人京亞尹，白頭俱未著緋衫。',32,'全唐诗/poet.tang.23000.json','["鳳閣舍人京亞尹，白頭俱未著緋衫。", "南宫起請無消息，朝散何時得入銜。"]'),
('24884900-a8d3-49a3-b782-709dfb1b778d','中書夜直夢忠州','白居易','唐','唐诗','tang','','[]','閣下燈前夢，巴南城裏遊。',48,'全唐诗/poet.tang.23000.json','["閣下燈前夢，巴南城裏遊。", "覓花來渡口，尋寺到山頭。", "江色分明綠，猨聲依舊愁。", "禁鐘驚睡覺，唯不上東樓。"]'),
('7a91b234-4990-4786-a970-ad4aa0e5b06f','醉後','白居易','唐','唐诗','tang','','[]','酒後高歌且放狂，門前閑事莫思量。',32,'全唐诗/poet.tang.23000.json','["酒後高歌且放狂，門前閑事莫思量。", "猶嫌小戶長先醒，不得多時住醉鄉。"]'),
('6808ae74-f831-45e3-845c-70a036bffc63','待漏入閣書事奉贈元九學士閣老','白居易','唐','唐诗','tang','','[]','衙排宣政仗，門啓紫宸關。',120,'全唐诗/poet.tang.23000.json','["衙排宣政仗，門啓紫宸關。", "彩筆停書命，花甎趂立班。", "稀星點銀礫，殘月墮金環。", "暗漏猶傳水，明河漸下山。", "從東分地色，向北仰天顏。", "碧縷爐煙直，紅垂佩尾閑。", "綸闈慚並入，翰苑忝先攀。", "笑我青袍故，饒君茜綬殷。", "詩仙歸洞裏，酒病滯人間。", "好去鴛鸞侶，沖天便不還。"]'),
('6137093d-b7f7-465d-b028-e569da427e34','晚春重到集賢院','白居易','唐','唐诗','tang','','[]','官曹清切非人境，風月鮮明是洞天。',64,'全唐诗/poet.tang.23000.json','["官曹清切非人境，風月鮮明是洞天。", "滿砌荆花鋪紫毯，隔牆榆莢撒青錢。", "前時謫去三千里，此地辭來十四年。", "虛薄至今慚舊職，院名擡舉號爲賢。"]'),
('21beebc6-f2ca-41b1-b3f4-d5ce197fc2ac','紫薇花','白居易','唐','唐诗','tang','','[]','絲綸閣下文書靜，鐘鼓樓中刻漏長。',32,'全唐诗/poet.tang.23000.json','["絲綸閣下文書靜，鐘鼓樓中刻漏長。", "獨坐黃昏誰是伴，紫薇花對紫微郎。"]'),
('8fd85cdc-f91b-44a5-8a36-9c0c215d9c0b','後宮詞','白居易','唐','唐诗','tang','','[]','雨露由來一點恩，爭能徧布及千門。',32,'全唐诗/poet.tang.23000.json','["雨露由來一點恩，爭能徧布及千門。", "三千宮女胭脂面，幾箇春來無淚痕。"]'),
('16f79c36-604f-4bda-8c52-87f6dc41597e','卜居','白居易','唐','唐诗','tang','','[]','遊宦京都二十春，貧中無處可安貧。',64,'全唐诗/poet.tang.23000.json','["遊宦京都二十春，貧中無處可安貧。", "長羨蝸牛猶有舍，不如碩鼠解藏身。", "且求容立錐頭地，免似漂流木偶人。", "但道吾廬心便足，敢辭湫隘與囂塵。"]'),
('4bb161fd-a848-4b01-811d-2bb316e3bc54','題新居寄元八','白居易','唐','唐诗','tang','','[]','青龍岡北近西邊，移入新居便泰然。',64,'全唐诗/poet.tang.23000.json','["青龍岡北近西邊，移入新居便泰然。", "冷巷閉門無客到，暖簷移榻向陽眠。", "階庭寬窄纔容足，牆壁高低粗及肩。", "莫羨昇平元八宅，自思買用幾多錢。"]'),
('c8ae5c43-5f28-4428-857f-1883312ebf34','登龍尾道南望憶廬山舊隱','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','龍尾道邊來一望，香爐峰下去無因。',64,'全唐诗/poet.tang.23000.json','["龍尾道邊來一望，香爐峰下去無因。", "青山舉眼三千里，白髮平頭五十人。", "自笑形骸紆組綬，將何言語掌絲綸。", "君恩壯健猶難報，況被年年老逼身。"]'),
('eb254a23-dcdc-4496-93b3-c7a8ea740f27','馮閣老處見與嚴郎中酬和詩因戲贈絕句','白居易','唐','唐诗','tang','','[]','乍來天上宜清淨，不用回頭望故山。',32,'全唐诗/poet.tang.23000.json','["乍來天上宜清淨，不用回頭望故山。", "縱有舊遊君莫憶，塵心起即墮人間。"]'),
('1455ffa7-2db6-45b8-8f6d-06c3dab8011c','見于給事暇日上直寄南省諸郎官詩因以戲贈','白居易','唐','唐诗','tang','','[]','倚作天仙弄地仙，誇張一日抵千年。',64,'全唐诗/poet.tang.23000.json','["倚作天仙弄地仙，誇張一日抵千年。", "黃麻勅勝長生籙，白紵詞嫌內景篇。", "雲彩誤居青瑣地，風流合在紫微天。", "東曹漸去西垣近，鶴駕無妨更著鞭。"]'),
('66d53fac-8f27-470c-917f-b20d4ede6548','題新昌所居','白居易','唐','唐诗','tang','','[]','宅小人煩悶，泥深馬鈍頑。',48,'全唐诗/poet.tang.23000.json','["宅小人煩悶，泥深馬鈍頑。", "街東閑處住，日午熱時還。", "院窄難栽竹，牆高不見山。", "唯應方寸內，此地覓寬閑。"]'),
('9f52ca2f-d82a-4c85-9a3e-f632c8029aaf','西省北院新構小亭種竹開窗東通騎省與李常侍隔窗小飲各題四韻','白居易','唐','唐诗','tang','','[]','結託白鬚伴，因依青竹叢。',48,'全唐诗/poet.tang.23000.json','["結託白鬚伴，因依青竹叢。", "題詩新壁上，過酒小窗中。", "深院晚無白，虛簷涼有風。", "金貂醉好看，回首紫垣東。"]'),
('cf5a1a73-07fb-40c7-afa2-a4570aa59cf2','酬元郎中同制加朝散大夫書懷見贈','白居易','唐','唐诗','tang','','[]','命服雖同黃紙上，官班不共紫垣前。',80,'全唐诗/poet.tang.23000.json','["命服雖同黃紙上，官班不共紫垣前。", "青衫脫早差三日，白髮生遲校九年。", "曩者定交非勢利，老來同病是詩篇。", "終身擬作臥雲伴，逐月須收燒藥錢。", "五品足爲婚嫁主，緋袍著了好歸田。"]'),
('c63a8f28-4878-477b-afa3-e7b3e030af53','初著緋戲贈元九','白居易','唐','唐诗','tang','','[]','晚遇緣才拙，先衰被病牽。',48,'全唐诗/poet.tang.23000.json','["晚遇緣才拙，先衰被病牽。", "那知垂白日，始是著緋年。", "身外名徒爾，人間事偶然。", "我朱君紫綬，猶未得差肩。"]'),
('08c13479-f5ef-4392-b488-6426aa34a2ea','和韓侍郎苦雨','白居易','唐','唐诗','tang','','[]','潤氣凝柱礎，繁聲注瓦溝。',48,'全唐诗/poet.tang.23000.json','["潤氣凝柱礎，繁聲注瓦溝。", "闇留窗不曉，涼引簟先秋。", "葉濕蠶應病，泥稀燕亦愁。", "仍聞放朝夜，誤出到街頭。"]'),
('a7b17b89-547d-4964-89cc-77ae532d198c','連雨','白居易','唐','唐诗','tang','','[]','風雨闇蕭蕭，雞鳴暮復朝。',48,'全唐诗/poet.tang.23000.json','["風雨闇蕭蕭，雞鳴暮復朝。", "碎聲籠苦竹，冷翠落芭蕉。", "水鳥投簷宿，泥蛙入戶跳。", "仍聞蕃客見，明日欲追朝。"]'),
('76b961c0-53ba-4885-9a76-699000e35815','初加朝散大夫又轉上柱國','白居易','唐','唐诗','tang','','[]','紫微今日煙霄地，赤嶺前年泥土身。',64,'全唐诗/poet.tang.23000.json','["紫微今日煙霄地，赤嶺前年泥土身。", "得水魚還動鱗鬣，乘軒鶴亦長精神。", "且慙身忝官階貴，未敢家嫌活計貧。", "柱國勳成私自問，有何功德及生人。"]'),
('c7492a59-5cf5-4c37-9a93-62f1ad58d36a','行簡初授拾遺同早朝入閤因示十二韻','白居易','唐','唐诗','tang','','[]','夜色尚蒼蒼，槐陰夾路長。',144,'全唐诗/poet.tang.23000.json','["夜色尚蒼蒼，槐陰夾路長。", "聽鐘出長樂，傳鼓到新昌。", "宿雨沙隄潤，秋風樺燭香。", "馬驕欺地軟，人健得天涼。", "待漏排閶闔，停珂擁建章。", "爾隨黃閤老，吾次紫微郎。", "並入連稱籍，齊趨對折方。", "鬬班花接萼，綽立雁分行。", "近職誠爲美，微才豈合當。", "綸言難下筆，諫紙易盈箱。", "老去何僥倖，時來不料量。", "唯求殺身地，相誓荅恩光。"]'),
('d6fa1532-8037-4aa3-9e9f-6596662419be','立秋日登樂遊園','白居易','唐','唐诗','tang','','[]','獨行獨語曲江頭，回馬遲遲上樂遊。',32,'全唐诗/poet.tang.23000.json','["獨行獨語曲江頭，回馬遲遲上樂遊。", "蕭颯涼風與衰鬢，誰教計會一時秋。"]'),
('60536ade-c1ce-4e82-8f11-ef049f6c37e5','新秋早起有懷元少尹','白居易','唐','唐诗','tang','','[]','秋來轉覺此身衰，晨起臨階盥漱時。',66,'全唐诗/poet.tang.23000.json','["秋來轉覺此身衰，晨起臨階盥漱時。", "漆匣鏡明頭盡白，銅缾水冷齒先知。", "光陰縱惜[留難]住，官職雖榮得已遲。", "老去相逢無別計，強開笑口展愁眉。"]'),
('2a3e62d3-cba2-4707-88f0-eaf2aa882f05','夜箏','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u5f39\u7434", "\u6708\u591c"]','紫袖紅弦明月中，自彈自感闇低容。',32,'全唐诗/poet.tang.23000.json','["紫袖紅弦明月中，自彈自感闇低容。", "弦凝指咽聲停處，別有深情一萬重。"]'),
('ed4342c0-64a4-4b45-a289-2bea11d46f41','妻初授邑號告身','白居易','唐','唐诗','tang','','[]','弘農舊縣授新封，鈿軸金泥誥一通。',64,'全唐诗/poet.tang.23000.json','["弘農舊縣授新封，鈿軸金泥誥一通。", "我轉官階常自媿，君加邑號有何功。", "花箋印了排窠濕，錦褾裝來耀手紅。", "倚得身名便慵墮，日高猶睡綠窗中。"]'),
('6f2cc3cd-06e7-4d70-9ef9-faf3486ae0ed','送客南遷','白居易','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','我說南中事，君應不願聽。',144,'全唐诗/poet.tang.23000.json','["我說南中事，君應不願聽。", "曾經身困苦，不覺語叮嚀。", "燒處愁雲夢，波時憶洞庭。", "春畬煙勃勃，秋瘴露冥冥。", "蚊蚋經冬活，魚龍欲雨腥。", "水蟲能射影，山鬼解藏形。", "穴掉巴蛇尾，林飄鴆鳥翎。", "颶風千里黑，䕭草四時青。", "客似驚弦雁，舟如委浪萍。", "誰人勸言笑，何計慰漂零。", "慎勿琴離膝，長須酒滿瓶。", "大都從此去，宜醉不宜醒。"]'),
('693eabfa-e169-4bdb-9486-ef2d7b48ab83','暮歸','白居易','唐','唐诗','tang','','[]','不覺百年半，何曾一日閑。',48,'全唐诗/poet.tang.23000.json','["不覺百年半，何曾一日閑。", "朝隨燭影出，暮趂鼓聲還。", "甕裏非無酒，牆頭亦有山。", "歸來長困臥，早晚得開顏。"]'),
('d419d675-7604-451a-9f2a-e0c17fa34a63','寄遠','白居易','唐','唐诗','tang','','[]','欲忘忘未得，欲去去無由。',48,'全唐诗/poet.tang.23000.json','["欲忘忘未得，欲去去無由。", "兩腋不生翅，二毛空滿頭。", "坐看新落葉，行上最高樓。", "暝色無邊際，茫茫盡眼愁。"]'),
('42ba31e0-7cf8-43ef-a6ea-f61ae9b8db3b','舊房','白居易','唐','唐诗','tang','','[]','遠壁秋聲蟲絡絲，入簷新影月低眉。',32,'全唐诗/poet.tang.23000.json','["遠壁秋聲蟲絡絲，入簷新影月低眉。", "牀帷半故簾旌斷，仍是初寒欲夜時。"]'),
('09f7c55c-bb77-4171-b463-7e4b320e17a6','錢侍郎使君以題廬山草堂詩見寄因酬之','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','殷勤江郡守，悵望掖垣郎。',48,'全唐诗/poet.tang.23000.json','["殷勤江郡守，悵望掖垣郎。", "慙見新瓊什，思歸舊草堂。", "事隨心未得，名與道相妨。", "若不休官去，人間到老忙。"]'),
('18306ead-a219-4ba1-88af-1d5ce04f953c','寄山僧','白居易','唐','唐诗','tang','','[]','眼看過半百，早晚掃巖扉。',48,'全唐诗/poet.tang.23000.json','["眼看過半百，早晚掃巖扉。", "白首誰能住，青山自不歸。", "百千萬劫障，四十九年非。", "會擬抽身去，當風斗擻衣。"]'),
('0139aae9-7565-4426-a4f9-51f0d500abd6','慈恩寺有感','白居易','唐','唐诗','tang','','[]','自問有何惆悵事，寺門臨入却遲迴。',32,'全唐诗/poet.tang.23000.json','["自問有何惆悵事，寺門臨入却遲迴。", "李家哭泣元家病，柿葉紅時獨自來。"]'),
('f2e3a7eb-939c-4b1e-a544-0cd6f4e9aff8','酬嚴十八郎中見示','白居易','唐','唐诗','tang','','[]','口厭含香握厭蘭，紫微青瑣舉頭看。',64,'全唐诗/poet.tang.23000.json','["口厭含香握厭蘭，紫微青瑣舉頭看。", "忽驚鬢後蒼浪髮，未得心中本分官。", "夜酌滿容花色暖，秋吟切骨玉聲寒。", "承明長短君應入，莫憶家江七里灘。"]'),
('69e4ee28-52d5-4958-b8da-8ee83235f93d','寄王祕書','白居易','唐','唐诗','tang','','[]','霜菊花萎日，風梧葉碎時。',24,'全唐诗/poet.tang.23000.json','["霜菊花萎日，風梧葉碎時。", "怪來秋思苦，緣詠秘書詩。"]'),
('4da1007c-e9d4-43ab-bf8d-36064a850aa2','中書寓直','白居易','唐','唐诗','tang','','[]','繚繞宮牆圍禁林，半開閶闔曉沈沈。',64,'全唐诗/poet.tang.23000.json','["繚繞宮牆圍禁林，半開閶闔曉沈沈。", "天晴更覺南山近，月出方知西掖深。", "病對詞頭慚彩筆，老看鏡面媿華簪。", "自嫌野物將何用，土木形骸麋鹿心。"]'),
('e658fbc2-e861-44ec-8064-907bf4b8fc60','自問','白居易','唐','唐诗','tang','','[]','黑花滿眼絲滿頭，早衰因病病因愁。',32,'全唐诗/poet.tang.23000.json','["黑花滿眼絲滿頭，早衰因病病因愁。", "宦途氣味已諳盡，五十不休何日休。"]'),
('1cba0bc8-479b-4d43-821b-8edbe55d3428','曲江獨行招張十八','白居易','唐','唐诗','tang','','[]','曲江新歲後，冰與水相和。',48,'全唐诗/poet.tang.23000.json','["曲江新歲後，冰與水相和。", "南岸猶殘雪，東風未有波。", "偶遊身獨自，相憶意如何。", "莫待春深去，花時鞍馬多。"]'),
('285e4c2b-d8e8-4105-bedb-7b26d7892082','新居早春二首 一','白居易','唐','唐诗','tang','','[]','靜巷無來客，深居不出門。',48,'全唐诗/poet.tang.23000.json','["靜巷無來客，深居不出門。", "鋪沙蓋苔面，掃雪擁松根。", "漸暖宜閑步，初晴愛小園。", "覓花都未有，唯覺樹枝繁。"]'),
('f588be62-fe07-4e8e-9a3f-fb0ee2149a1a','新居早春二首 二','白居易','唐','唐诗','tang','','[]','地潤東風暖，閑行蹋草芽。',48,'全唐诗/poet.tang.23000.json','["地潤東風暖，閑行蹋草芽。", "呼童遣移竹，留客伴嘗茶。", "霤滴簷冰盡，塵浮隟日斜。", "新居未曾到，鄰里是誰家。"]'),
('43c45f08-8844-43f7-8a1f-fe8b2ffe7f77','新昌新居書事四十韻因寄元郎中張博士','白居易','唐','唐诗','tang','','[]','冒寵已三遷，歸期始二年。',288,'全唐诗/poet.tang.23000.json','["冒寵已三遷，歸期始二年。", "囊中貯餘俸，園外買閑田。", "狐兔同三逕，蒿萊共一壥。", "新園聊剗穢，舊屋且扶顛。", "簷漏移傾瓦，梁欹換蠹椽。", "平治遶臺路，整頓近階甎。", "巷狹開容駕，牆低壘過肩。", "門閭堪駐蓋，堂室可鋪筵。", "丹鳳樓當後，青龍寺在前。", "市街塵不到，宮樹影相連。", "省史嫌坊遠，豪家笑地偏。", "敢勞賓客訪，或望子孫傳。", "不覓他人愛，唯將自性便。", "等閑栽樹木，隨分占風煙。", "逸致因心得，幽期遇境牽。", "松聲疑澗底，草色勝河邊。", "虛潤冰銷地，晴和日出天。", "苔行滑如簟，莎坐軟於綿。", "簾每當山卷，帷多帶月褰。", "籬東花掩映，窗北竹嬋娟。", "跡慕青門隱，名慙紫禁仙。", "假歸思晚沐，朝去戀春眠。", "拙薄才無取，疎慵職不專。", "題牆書命筆，沽酒率分錢。"]'),
('193f709a-20b4-4305-9e4a-d0c33127aa8f','喜敏中及第偶示所懷','白居易','唐','唐诗','tang','','[]','自知羣從爲儒少，豈料詞場中第頻。',64,'全唐诗/poet.tang.23000.json','["自知羣從爲儒少，豈料詞場中第頻。", "桂折一枝先許我，楊穿三葉盡驚人。", "轉於文墨須留意，貴向煙霄早致身。", "莫學爾兄年五十，蹉跎始得掌絲綸。"]'),
('3621c22b-77e6-4285-b85e-e9dc08bd3c9e','久不見韓侍郎戲題四韻以寄之','白居易','唐','唐诗','tang','','[]','近來韓閤老，疎我我心知。',48,'全唐诗/poet.tang.23000.json','["近來韓閤老，疎我我心知。", "戶大嫌甜酒，才高笑小詩。", "靜吟乖月夜，閑醉曠花時。", "還有愁同處，春風滿鬢絲。"]'),
('2bd0c9f3-2e19-4065-a5cc-f5474f4c4213','寄白頭陀','白居易','唐','唐诗','tang','','[]','近見頭陀伴，云師老更慵。',48,'全唐诗/poet.tang.23000.json','["近見頭陀伴，云師老更慵。", "性靈閑似鶴，顏狀古於松。", "山裏猶難覓，人間豈易逢。", "仍聞移住處，太白最高峰。"]'),
('4bf38de7-7305-4a44-808b-e17ef42d0f4a','和韓侍郎題楊舍人林池見寄','白居易','唐','唐诗','tang','','[]','渠水暗流春凍解，風吹日炙不成凝。',32,'全唐诗/poet.tang.23000.json','["渠水暗流春凍解，風吹日炙不成凝。", "鳳池冷暖君諳在，二月因何更有冰。"]'),
('22d9b870-f0dd-4ec1-b768-a25265cc9d3a','勤政樓西老柳','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u67f3"]','半朽臨風樹，多情立馬人。',24,'全唐诗/poet.tang.23000.json','["半朽臨風樹，多情立馬人。", "開元一株柳，長慶二年春。"]'),
('8e8e98d7-eee5-4045-8d25-e3feabff1733','偶題閤下廳','白居易','唐','唐诗','tang','','[]','靜愛青苔院，深宜白鬢翁。',48,'全唐诗/poet.tang.23000.json','["靜愛青苔院，深宜白鬢翁。", "貌將松共瘦，心與竹俱空。", "暖有低簷日，春多颺幕風。", "平生閑境界，盡在五言中。"]'),
('53ad96ef-e5b3-44ad-9975-830791f8d48e','予與故刑部李侍郎早結道友以藥術爲事與故京兆元尹晚爲詩侶有林泉之期周歲之間二君長逝李住曲江北元居昇平西追感舊遊因貽同志','白居易','唐','唐诗','tang','','[]','從哭李來傷道氣，自亡元後減詩情。',64,'全唐诗/poet.tang.23000.json','["從哭李來傷道氣，自亡元後減詩情。", "金丹同學都無益，水竹鄰居竟不成。", "月夜若爲遊曲水，花時那忍到昇平。", "如年七十身猶在，但恐傷心無處行。"]'),
('d6bca58e-99de-4155-9f0f-ad85b75ed9ff','送馮舍人閤老往襄陽','白居易','唐','唐诗','tang','','[]','紫微閤底送君回，第二廳簾下不開。',32,'全唐诗/poet.tang.23000.json','["紫微閤底送君回，第二廳簾下不開。", "莫戀漢南風景好，峴山花盡早歸來。"]'),
('cef6c19e-1d08-4ffc-862d-45d61422d57a','莫走柳條詞送別','白居易','唐','唐诗','tang','','[]','南陌傷心別，東風滿把春。',24,'全唐诗/poet.tang.23000.json','["南陌傷心別，東風滿把春。", "莫欺楊柳弱，勸酒勝於人。"]'),
('5a11ca98-133e-4971-b9eb-ac481a710aad','酬韓侍郎張博士雨後遊曲江見寄','白居易','唐','唐诗','tang','','[]','小園新種紅櫻樹，閑遶花行便當遊。',32,'全唐诗/poet.tang.23000.json','["小園新種紅櫻樹，閑遶花行便當遊。", "何必更隨鞍馬隊，衝泥蹋雨曲江頭。"]'),
('b78fa0aa-6a93-4102-8b93-d99cddb3ea52','元家花','白居易','唐','唐诗','tang','','[]','今日元家宅，櫻桃發幾枝。',36,'全唐诗/poet.tang.23000.json','["今日元家宅，櫻桃發幾枝。", "稀稠與顏色，一似去年時。", "失却東園主，春風可得知。"]'),
('60c7a810-7f8a-4279-b025-a42897e2e71c','代人贈王員外','白居易','唐','唐诗','tang','','[]','好在王員外，平生記得不。',48,'全唐诗/poet.tang.23000.json','["好在王員外，平生記得不。", "共賒黃叟酒，同上莫愁樓。", "靜接殷勤語，狂隨爛熳遊。", "那知今日眼，相見冷於秋。"]'),
('7c737519-042d-4afd-946b-d4e3cb8f4828','惜小園花','白居易','唐','唐诗','tang','','[]','曉來紅萼凋零盡，但見空枝四五株。',32,'全唐诗/poet.tang.23000.json','["曉來紅萼凋零盡，但見空枝四五株。", "前日狂風昨夜雨，殘芳更合得存無。"]'),
('852ec0af-b6ee-40b7-8605-a0b42ea0eda0','蕭相公宅遇自遠禪師有感而贈','白居易','唐','唐诗','tang','','[]','宦途堪笑不勝悲，昨日榮華今日衰。',64,'全唐诗/poet.tang.23000.json','["宦途堪笑不勝悲，昨日榮華今日衰。", "轉似秋蓬無定處，長於春夢幾多時。", "半頭白髮慙蕭相，滿面紅塵問遠師。", "應是世間緣未盡，欲拋官去尚遲疑。"]'),
('eb73ed46-e1f4-41e1-9cd3-08c0df663b5f','草詞畢遇芍藥初開因詠小謝紅藥當階翻詩以爲一句未盡其狀偶成十六韻','白居易','唐','唐诗','tang','','[]','罷草紫泥詔，起吟紅藥詩。',192,'全唐诗/poet.tang.23000.json','["罷草紫泥詔，起吟紅藥詩。", "詞頭封送後，花口拆開時。", "坐對鉤簾久，行觀步履遲。", "兩三叢爛熳，十二葉參差。", "背日房微歛，當階朵旋欹。", "釵葶抽碧股，粉蘂撲黃絲。", "動蕩情無限，低斜力不支。", "周迴看未足，比諭語難爲。", "句漏丹砂裏，僬僥火燄旗。", "彤雲賸根蒂，絳幘欠纓緌。", "況有晴風度，仍兼宿露垂。", "疑香薰罨畫，似淚著胭脂。", "有意留連我，無言怨思誰。", "應愁明日落，如恨隔年期。", "菡萏泥連萼，玫瑰刺繞枝。", "等量無勝者，唯眼與心知。"]'),
('035b287d-9a07-4082-819f-cebee0988cf9','喜張十八博士除水部員外郎','白居易','唐','唐诗','tang','','[]','老何歿後吟聲絕，雖有郎官不愛詩。',64,'全唐诗/poet.tang.23000.json','["老何歿後吟聲絕，雖有郎官不愛詩。", "無復篇章傳道路，空流風月在曹司。", "長嗟博士官猶屈，亦恐騷人道漸衰。", "今日聞君除水部，喜於身得省郎時。"]'),
('b18e52d9-a647-499b-a759-bca7c250393f','與沈楊二舍人閤老同食勅賜櫻桃翫物感恩因成十四韻','白居易','唐','唐诗','tang','','[]','清曉趨丹禁，紅纓降紫宸。',168,'全唐诗/poet.tang.23000.json','["清曉趨丹禁，紅纓降紫宸。", "驅禽養得熟，和葉摘來新。", "圓轉盤傾玉，鮮明籠透銀。", "內園題兩字，西掖賜三臣。", "熒惑晶華赤，醍醐氣味真。", "如珠未穿孔，似火不燒人。", "杏俗難爲對，桃頑詎可倫。", "肉嫌盧橘厚，皮笑荔枝皴。", "瓊液酸甜足，金丸大小勻。", "偷須防曼倩，惜莫擲安仁。", "手擘纔離核，匙抄半是津。", "甘爲舌上露，暖作腹中春。", "已懼長尸祿，仍驚數食珍。", "最慙恩未報，飽餧不才身。"]'),
('612c88e9-f922-45d6-9c58-cb60f14c05a6','送嚴大夫赴桂州','白居易','唐','唐诗','tang','','[]','地壓坤方重，官兼憲府雄。',48,'全唐诗/poet.tang.23000.json','["地壓坤方重，官兼憲府雄。", "桂林無瘴氣，柏署有清風。", "山水衙門外，旌旗艛艓中。", "大夫應絕席，詩酒與誰同。"]'),
('24731f5f-02ae-412e-9a96-29503e7d30da','春夜宿直','白居易','唐','唐诗','tang','','[]','三月十四夜，西垣東北廊。',48,'全唐诗/poet.tang.23000.json','["三月十四夜，西垣東北廊。", "碧梧葉重疊，紅藥樹低昂。", "月砌漏幽影，風簾飄闇香。", "禁中無宿客，誰伴紫微郎。"]'),
('d91dec3a-ac37-4874-9097-cc1f77c71148','夏夜宿直','白居易','唐','唐诗','tang','','[]','人少庭宇曠，夜涼風露清。',48,'全唐诗/poet.tang.23000.json','["人少庭宇曠，夜涼風露清。", "槐花滿院氣，松子落堦聲。", "寂寞挑燈坐，沈吟蹋月行。", "年衰自無趣，不是厭承明。"]'),
('7e2c25d3-8609-4633-a580-75399192cb18','七言十二句贈駕部吳郎中七兄','白居易','唐','唐诗','tang','','[]','四月天氣和且清，綠槐陰合沙堤平。',96,'全唐诗/poet.tang.23000.json','["四月天氣和且清，綠槐陰合沙堤平。", "獨騎善馬銜鐙穩，初著單衣肢體輕。", "退朝下直少徒侶，歸舍閉門無送迎。", "風生竹夜窗間臥，月照松時臺上行。", "春酒冷嘗三數醆，曉琴閑弄十餘聲。", "幽懷靜境何人別，唯有南宮老駕兄。"]'),
('d949bec5-34ee-44c3-a70c-ecfa7cb36b0c','玉真張觀主下小女冠阿容','白居易','唐','唐诗','tang','','[]','綽約小天仙，生來十六年。',48,'全唐诗/poet.tang.23000.json','["綽約小天仙，生來十六年。", "姑山半峰雪，瑤水一枝蓮。", "晚院花留立，春窗月伴眠。", "迴眸雖欲語，阿母在傍邊。"]'),
('727ff0bc-60c0-4009-acd2-d06333b9ae2d','龍花寺主家小尼','白居易','唐','唐诗','tang','','[]','頭青眉眼細，十四女沙彌。',48,'全唐诗/poet.tang.23000.json','["頭青眉眼細，十四女沙彌。", "夜靜雙林怕，春深一食飢。", "步慵行道困，起晚誦經遲。", "應似仙人子，花宮未嫁時。"]'),
('038cebb7-90b8-4172-8ca1-dc93704eb92e','訪陳二','白居易','唐','唐诗','tang','','[]','曉垂朱綬帶，晚著白綸巾。',48,'全唐诗/poet.tang.23000.json','["曉垂朱綬帶，晚著白綸巾。", "出去爲朝客，歸來是野人。", "兩飱聊過日，一榻足容身。", "此外皆閑事，時時訪老陳。"]'),
('81499466-4759-4ff1-a11e-b8c5cf1e9c5f','晚亭逐涼','白居易','唐','唐诗','tang','','[]','送客出門後，移牀下砌初。',48,'全唐诗/poet.tang.23000.json','["送客出門後，移牀下砌初。", "趂涼行繞竹，引睡臥看書。", "老更爲官拙，慵多向事疎。", "松窗倚藤杖，人道似僧居。"]'),
('8182e114-f033-42a0-a3bd-bbfbd59b3d8c','曲江憶李十一','白居易','唐','唐诗','tang','','[]','李君歿後共誰遊，柳岸荷亭兩度秋。',32,'全唐诗/poet.tang.23000.json','["李君歿後共誰遊，柳岸荷亭兩度秋。", "獨繞曲江行一匝，依前還立水邊愁。"]'),
('5629410e-ebc1-4c32-91d7-5dcf761044f1','江亭翫春','白居易','唐','唐诗','tang','','[]','江亭乘曉閱衆芳，春妍景麗草樹光。',64,'全唐诗/poet.tang.23000.json','["江亭乘曉閱衆芳，春妍景麗草樹光。", "日消石桂綠嵐氣，風墜木蘭紅露漿。", "水蒲漸展書帶葉，山榴半含琴軫房。", "何物春風吹不變，愁人依舊鬢蒼蒼。"]'),
('04bbd54b-333c-422e-8d36-371790765f4f','聞夜砧','白居易','唐','唐诗','tang','','[]','誰家思婦秋擣帛，月苦風淒砧杵悲。',48,'全唐诗/poet.tang.23000.json','["誰家思婦秋擣帛，月苦風淒砧杵悲。", "八月九日正長夜，千聲萬聲無了時。", "應到天明頭盡白，一聲添得一莖絲。"]'),
('9d727790-0c3d-43ee-91ab-fcbe771d51f5','板橋路','白居易','唐','唐诗','tang','','[]','梁苑城西二十里，一渠春水柳千條。',48,'全唐诗/poet.tang.23000.json','["梁苑城西二十里，一渠春水柳千條。", "若爲此路今重過，十五年前舊板橋。", "曾共玉顏橋上別，不知消息到今朝。"]'),
('6bccae71-a0bf-44cd-afb5-5c485871a348','青門柳','白居易','唐','唐诗','tang','','[]','青青一樹傷心色，曾入幾人離恨中。',32,'全唐诗/poet.tang.23000.json','["青青一樹傷心色，曾入幾人離恨中。", "爲近都門多送別，長條折盡減春風。"]'),
('027bd68f-e4fa-4564-a2cd-f18352352932','梨園弟子','白居易','唐','唐诗','tang','','[]','白頭垂淚話梨園，五十年前雨露恩。',32,'全唐诗/poet.tang.23000.json','["白頭垂淚話梨園，五十年前雨露恩。", "莫問華清今日事，滿山紅葉鏁宮門。"]'),
('e87ae63c-8907-4e88-aa9e-dde22133a25e','暮江吟','白居易','唐','唐诗','tang','','["\u957f\u6c5f", "\u63cf\u5199\u6c34", "\u5199\u666f", "\u6c34", "\u5199\u6c34"]','一道殘陽鋪水中，半江瑟瑟半江紅。',32,'全唐诗/poet.tang.23000.json','["一道殘陽鋪水中，半江瑟瑟半江紅。", "可憐九月初三夜，露似真珠月似弓。"]'),
('57912825-8435-4ced-8429-a8c3289760e3','思婦眉','白居易','唐','唐诗','tang','','[]','春風搖蕩自東來，折盡櫻桃綻盡梅。',32,'全唐诗/poet.tang.23000.json','["春風搖蕩自東來，折盡櫻桃綻盡梅。", "惟餘思婦愁眉結，無限春風吹不開。"]'),
('ef97caf7-f721-4804-aa1c-9e6b0f140859','怨詞','白居易','唐','唐诗','tang','','[]','奪寵心那慣，尋思倚殿門。',24,'全唐诗/poet.tang.23000.json','["奪寵心那慣，尋思倚殿門。", "不知移舊愛，何處作新恩。"]'),
('5dfef0e5-cfff-4872-91a2-d7144083c7dc','空閨怨','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u95fa\u6028", "\u5199\u666f"]','寒月沈沈洞房靜，真珠簾外梧桐影。',32,'全唐诗/poet.tang.23000.json','["寒月沈沈洞房靜，真珠簾外梧桐影。", "秋霜欲下手先知，燈底裁縫剪刀冷。"]'),
('c1609932-3ac6-4498-b3c2-947f29fd3534','秋房夜','白居易','唐','唐诗','tang','','[]','雲露青天月漏光，中庭立久却歸房。',32,'全唐诗/poet.tang.23000.json','["雲露青天月漏光，中庭立久却歸房。", "水窗席冷未能臥，挑盡殘燈秋夜長。"]'),
('685928fd-174e-4f7a-9071-b7ad0e08531e','採蓮曲','白居易','唐','唐诗','tang','','["\u5973\u5b50", "\u7231\u60c5", "\u8377\u82b1"]','菱葉縈波荷颭風，荷花深處小船通。',32,'全唐诗/poet.tang.23000.json','["菱葉縈波荷颭風，荷花深處小船通。", "逢郎欲語低頭笑，碧玉搔頭落水中。"]'),
('aa6f2053-e89b-4646-bba0-ee73a5a7ae83','鄰女','白居易','唐','唐诗','tang','','["\u5199\u4eba", "\u5973\u5b50", "\u5199\u4eba\u8bd7"]','娉婷十五勝天仙，白日姮娥旱地蓮。',32,'全唐诗/poet.tang.23000.json','["娉婷十五勝天仙，白日姮娥旱地蓮。", "何處閑教鸚鵡語，碧紗窗下繡牀前。"]'),
('2b753e63-ff9b-40b7-84a2-96585829de93','閨婦','白居易','唐','唐诗','tang','','[]','斜凭繡牀愁不動，紅綃帶緩綠鬟低。',32,'全唐诗/poet.tang.23000.json','["斜凭繡牀愁不動，紅綃帶緩綠鬟低。", "遼陽春盡無消息，夜合花前日又西。"]'),
('9a2a4783-4021-4dd2-bfe8-eddbc2e310d2','移牡丹栽','白居易','唐','唐诗','tang','','[]','金錢買得牡丹栽，何處辭叢別主來？紅芳堪惜還堪恨，百處移將百處開。',32,'全唐诗/poet.tang.23000.json','["金錢買得牡丹栽，何處辭叢別主來？紅芳堪惜還堪恨，百處移將百處開。"]'),
('9c1ef330-51d5-4760-8610-41e4ffefb3d2','聽夜箏有感','白居易','唐','唐诗','tang','','[]','江州去日聽箏夜，白髮新生不願聞。',32,'全唐诗/poet.tang.23000.json','["江州去日聽箏夜，白髮新生不願聞。", "如今格是頭成雪，彈到天明亦任君。"]'),
('d0d98a3c-29ca-4fa7-9e72-52a0b35bba45','代謝好妓荅崔員外','白居易','唐','唐诗','tang','','[]','青娥小謝娘，白髮老崔郎。',40,'全唐诗/poet.tang.23000.json','["青娥小謝娘，白髮老崔郎。", "謾愛胸前雪，其如頭上霜。", "別後曹家碑背上，思量好字斷君腸。"]'),
('db34f6ae-f096-4ec3-b18d-9d6c45e8e337','琵琶','白居易','唐','唐诗','tang','','[]','弦清撥剌語錚錚，背却殘燈就月明。',32,'全唐诗/poet.tang.23000.json','["弦清撥剌語錚錚，背却殘燈就月明。", "賴是心無惆悵事，不然爭奈子弦聲。"]'),
('a7a82abf-71bd-424f-a01c-4242c19c60b9','和殷協律琴思','白居易','唐','唐诗','tang','','[]','秋水蓮冠春草帬，依稀風調似文君。',32,'全唐诗/poet.tang.23000.json','["秋水蓮冠春草帬，依稀風調似文君。", "煩君玉指分明語，知是琴心佯不聞。"]'),
('80b73847-cefd-4f94-93de-abe7e8782097','寄李蘇州兼示楊瓊','白居易','唐','唐诗','tang','','[]','真娘墓頭春草碧，心奴鬢上秋霜白。',48,'全唐诗/poet.tang.23000.json','["真娘墓頭春草碧，心奴鬢上秋霜白。", "爲問蘇臺酒席中，使君歌笑與誰同。", "就中猶有楊瓊在，堪上東山伴謝公。"]'),
('7dd8ed3c-25b4-4912-9d04-2c1de3103b93','聽彈湘妃怨','白居易','唐','唐诗','tang','','[]','玉軫朱弦瑟瑟徽，吳娃徵調奏湘妃。',32,'全唐诗/poet.tang.23000.json','["玉軫朱弦瑟瑟徽，吳娃徵調奏湘妃。", "分明曲裏愁雲雨，似道蕭蕭郎不歸。"]'),
('d0f4c5ca-8340-4ef6-9e62-c100b93581c4','閑坐','白居易','唐','唐诗','tang','','[]','暖擁紅爐火，閑搔白髮頭。',48,'全唐诗/poet.tang.23000.json','["暖擁紅爐火，閑搔白髮頭。", "百年慵裏過，萬事醉中休。", "有室同摩詰，無兒比鄧攸。", "莫論身在日，身後亦無憂。"]'),
('ecf3f642-514b-4638-9b9f-aae8c6df82b0','不睡','白居易','唐','唐诗','tang','','[]','燄短寒缸盡，聲長曉漏遲。',24,'全唐诗/poet.tang.23000.json','["燄短寒缸盡，聲長曉漏遲。", "年衰自無睡，不是守三尸。"]'),
('f04f5531-0fc4-4a0f-9724-d806fc269ad0','初罷中書舍人','白居易','唐','唐诗','tang','','[]','自慙拙宦叨清貴，還有癡心怕素餐。',64,'全唐诗/poet.tang.23000.json','["自慙拙宦叨清貴，還有癡心怕素餐。", "或望君臣相獻替，可圖妻子免飢寒。", "性疎豈合承恩久，命薄元知濟事難。", "分寸寵光酬未得，不休更擬覓何官。"]'),
('a740a7b6-321a-47de-adf4-30c88c0d966a','宿陽城驛對月','白居易','唐','唐诗','tang','','[]','親故尋回駕，妻孥未出關。',24,'全唐诗/poet.tang.23000.json','["親故尋回駕，妻孥未出關。", "鳳皇池上月，送我過商山。"]'),
('c25a03fa-1d6b-4aa9-844b-5c2da11a8643','商山路有感','白居易','唐','唐诗','tang','','[]','憶昨徵還日，三人歸路同。',48,'全唐诗/poet.tang.23000.json','["憶昨徵還日，三人歸路同。", "此生都是夢，前事旋成空。", "杓直泉埋玉，虞平燭過風。", "唯殘樂天在，頭白向江東。"]'),
('e1b76599-d265-4d7c-883a-4f965f2dad11','重感','白居易','唐','唐诗','tang','','[]','停驂歇路隅，重感一長吁。',48,'全唐诗/poet.tang.23000.json','["停驂歇路隅，重感一長吁。", "擾擾生還死，紛紛榮又枯。", "困支青竹杖，閑捋白髭鬚。", "莫歎身衰老，交遊半已無。"]'),
('c9383dcc-342c-48b5-8809-f45671db940d','逢張十八員外籍','白居易','唐','唐诗','tang','','[]','旅思正茫茫，相逢此道傍。',48,'全唐诗/poet.tang.23000.json','["旅思正茫茫，相逢此道傍。", "曉嵐林葉暗，秋露草花香。", "白髮江城守，青衫水部郎。", "客亭同宿處，忽似夜歸鄉。"]'),
('36c285bf-fbcf-4657-b32b-901c53d098de','赴杭州重宿棣華驛見楊八舊詩感題一絕','白居易','唐','唐诗','tang','','[]','往恨今愁應不殊，題詩梁下又踟躕。',32,'全唐诗/poet.tang.23000.json','["往恨今愁應不殊，題詩梁下又踟躕。", "羨君猶夢見兄弟，我到天明睡亦無。"]'),
('54f275b3-385d-445e-a1b7-48e351b15024','寓言題僧','白居易','唐','唐诗','tang','','[]','劫風火起燒荒宅，苦海波生蕩破船。',32,'全唐诗/poet.tang.23000.json','["劫風火起燒荒宅，苦海波生蕩破船。", "力小無因救焚溺，清涼山下且安禪。"]'),
('3a4f1ece-f865-4f95-b64a-5d15b3b5215f','內鄉村路作','白居易','唐','唐诗','tang','','[]','日下風高野路涼，緩驅疲馬闇思鄉。',32,'全唐诗/poet.tang.23000.json','["日下風高野路涼，緩驅疲馬闇思鄉。", "渭村秋物應如此，棗赤梨紅稻穗黃。"]'),
('21d57fc8-d3de-4614-a670-9607d84059ce','路上寄銀匙與阿龜','白居易','唐','唐诗','tang','','[]','謫宦心都慣，辭鄉去不難。',48,'全唐诗/poet.tang.23000.json','["謫宦心都慣，辭鄉去不難。", "緣留龜子住，涕淚一闌干。", "小子須嬌養，鄒婆爲好看。", "銀匙封寄汝，憶我即加餐。"]'),
('7489c7ee-947d-4be6-8893-67d892ab5ded','山泉煎茶有懷','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u8336"]','坐酌泠泠水，看煎瑟瑟塵。',24,'全唐诗/poet.tang.23000.json','["坐酌泠泠水，看煎瑟瑟塵。", "無由持一盌，寄與愛茶人。"]'),
('81f43b56-6530-4c34-9a3f-c72a5316c2b2','郢州贈別王八使君','白居易','唐','唐诗','tang','','[]','昔是詩狂客，今爲酒病夫。',48,'全唐诗/poet.tang.23000.json','["昔是詩狂客，今爲酒病夫。", "強飲翻悵望，縱醉不歡娛。", "鬢髮三分白，交親一半無。", "郢城君莫厭，猶校近京都。"]'),
('8855fa61-e035-43d5-a56c-3ce75e1a6f60','吉祥寺見錢侍郎題名','白居易','唐','唐诗','tang','','[]','雲雨三年別，風波萬里行。',24,'全唐诗/poet.tang.23000.json','["雲雨三年別，風波萬里行。", "愁來正蕭索，況見古人名。"]'),
('70aab002-7296-4b6e-9246-593eb3c193f1','重到江州感舊遊題郡樓十一韻','白居易','唐','唐诗','tang','','[]','掌綸知是忝，剖竹信爲榮。',132,'全唐诗/poet.tang.23000.json','["掌綸知是忝，剖竹信爲榮。", "才薄官仍重，恩深責尚輕。", "昔徵從典午，今出自承明。", "鳳詔休揮翰，漁歌欲濯纓。", "還乘小艛艓，却到古湓城。", "醉客臨江待，禪僧出郭迎。", "青山滿眼在，白髮半頭生。", "又校三年老，何曾一事成。", "重過蕭寺宿，再上庾樓行。", "雲水新秋思，閭閻舊日情。", "郡民猶認得，司馬詠詩聲。"]'),
('376f2118-9397-4526-a77e-9fddf40977a1','贈江州李十使君員外十二韻','白居易','唐','唐诗','tang','','[]','我本江湖上，悠悠任運身。',144,'全唐诗/poet.tang.23000.json','["我本江湖上，悠悠任運身。", "朝隨賣藥客，暮伴釣魚人。", "跡爲燒丹隱，家緣嗜酒貧。", "經過剡谿雪，尋覓武陵春。", "豈有疎狂性，堪爲侍從臣。", "仰頭驚鳳闕，下口觸龍鱗。", "劒佩辭天上，風波向海濱。", "非賢虛偶聖，無屈感求伸。", "昔去曾同日，今來即後塵。", "中年俱白髮，左宦各朱輪。", "長短才雖異，榮枯事略均。", "殷勤李員外，不合不相親。"]'),
('1f643fc9-0c65-4ecb-b9a7-27aca9b1f568','題別遺愛草堂兼呈李十使君','白居易','唐','唐诗','tang','','[]','曾住爐峰下，書堂對藥臺。',72,'全唐诗/poet.tang.23000.json','["曾住爐峰下，書堂對藥臺。", "斬新蘿徑合，依舊竹窗開。", "砌水親開決，池荷手自栽。", "五年方暫至，一宿又須回。", "縱未長歸得，猶勝不到來。", "君家白鹿洞，聞道亦生苔。"]'),
('8ccd74a8-9ecb-4203-aea1-aa3dd9038a4c','重題','白居易','唐','唐诗','tang','','[]','泉石尚依依，林疎僧亦稀。',48,'全唐诗/poet.tang.23000.json','["泉石尚依依，林疎僧亦稀。", "何年辭水閣，今夜宿雲扉。", "謾獻長楊賦，虛拋薜荔衣。", "不能成一事，贏得白頭歸。"]'),
('4d960d13-781b-4b27-9799-dc60da3233d2','夜泊旅望','白居易','唐','唐诗','tang','','[]','少睡多愁客，中宵起望鄉。',48,'全唐诗/poet.tang.23000.json','["少睡多愁客，中宵起望鄉。", "沙明連浦月，帆白滿船霜。", "近海江彌闊，迎秋夜更長。", "煙波三十宿，猶未到錢唐。"]'),
('3ff110dd-424e-4ea4-8916-375d3ce5ac62','九江北岸遇風雨','白居易','唐','唐诗','tang','','[]','黃梅縣邊黃梅雨，白頭浪裏白頭翁。',48,'全唐诗/poet.tang.23000.json','["黃梅縣邊黃梅雨，白頭浪裏白頭翁。", "九江闊處不見岸，五月盡時多惡風。", "人間穩路應無限，何事拋身在此中。"]'),
('f2131f14-c029-4f4c-8a38-bdd68153babd','舟中晚起','白居易','唐','唐诗','tang','','[]','日高猶掩水窗眠，枕簟清涼八月天。',64,'全唐诗/poet.tang.23000.json','["日高猶掩水窗眠，枕簟清涼八月天。", "泊處或依沽酒店，宿時多伴釣魚船。", "退身江海應無用，憂國朝廷自有賢。", "且向錢唐湖上去，冷吟閑醉二三年。"]'),
('e07757a2-e6b7-48d0-acc0-203710238a17','秋寒','白居易','唐','唐诗','tang','','[]','雪鬢年顏老，霜庭景氣秋。',48,'全唐诗/poet.tang.23000.json','["雪鬢年顏老，霜庭景氣秋。", "病看妻檢藥，寒遣婢梳頭。", "身外名何有，人間事且休。", "澹然方寸內，唯擬學虛舟。"]'),
('1cc98f90-ddb4-4374-bf1c-a84afdc144dd','初到郡齋寄錢湖州李蘇州','白居易','唐','唐诗','tang','','[]','俱來滄海郡，半作白頭翁。',72,'全唐诗/poet.tang.23000.json','["俱來滄海郡，半作白頭翁。", "謾道風煙接，何曾笑語同。", "吏稀秋稅畢，客散晚庭空。", "霽後當樓月，潮來滿座風。", "霅溪殊冷僻，茂苑太繁雄。", "唯此錢唐郡，閑忙恰得中。"]'),
('02912820-2b68-49c7-8402-8e4d6bdb81cc','對酒自勉','白居易','唐','唐诗','tang','','[]','五十江城守，停杯一自思。',72,'全唐诗/poet.tang.23000.json','["五十江城守，停杯一自思。", "頭仍未盡白，官亦不全卑。", "榮寵尋過分，歡娛已校遲。", "肺傷雖怕酒，心健尚誇詩。", "夜舞吳娘袖，春歌蠻子詞。", "猶堪三五歲，相伴醉花時。"]'),
('e3757438-1bd8-4f1b-9611-9012976af1ef','郡樓夜宴留客','白居易','唐','唐诗','tang','','[]','北客勞相訪，東樓爲一開。',48,'全唐诗/poet.tang.23000.json','["北客勞相訪，東樓爲一開。", "褰簾待月出，把火看潮來。", "豔聽竹枝曲，香傳蓮子杯。", "寒天殊未曉，歸騎却遲迴。"]'),
('674b4f66-eff3-40da-b0ee-5fcd8c6835aa','醉題候仙亭','白居易','唐','唐诗','tang','','[]','蹇步垂朱綬，華纓映白鬚。',48,'全唐诗/poet.tang.23000.json','["蹇步垂朱綬，華纓映白鬚。", "何因駐衰老，只有且歡娛。", "酒興還應在，詩情可便無。", "登山與臨水，猶未要人扶。"]'),
('1a5255e6-2371-451e-b267-6ea908a33fc2','東院','白居易','唐','唐诗','tang','','[]','松下軒廊竹下房，暖簷晴日滿繩牀。',64,'全唐诗/poet.tang.23000.json','["松下軒廊竹下房，暖簷晴日滿繩牀。", "淨名居士經三卷，榮啓先生琴一張。", "老去齒衰嫌橘醋，病來肺渴覺茶香。", "有時閑酌無人伴，獨自騰騰入醉鄉。"]'),
('d52e6dc6-1be0-4bab-868d-a314a334dce7','虛白堂','白居易','唐','唐诗','tang','','[]','虛白堂前衙退後，更無一事到中心。',32,'全唐诗/poet.tang.23000.json','["虛白堂前衙退後，更無一事到中心。", "移牀就日簷間臥，臥詠閑詩側枕琴。"]'),
('38f35a5a-1753-4a12-9cf1-149413cad59b','閑夜詠懷因招周協律劉薛二秀才','白居易','唐','唐诗','tang','','[]','世名檢束爲朝士，心性疎慵是野夫。',64,'全唐诗/poet.tang.23000.json','["世名檢束爲朝士，心性疎慵是野夫。", "高置寒燈如客店，深藏夜火似僧爐。", "香濃酒熟能嘗否，冷澹詩成肯和無。", "若厭雅吟須俗飲，妓筵勉力爲君鋪。"]'),
('3738039c-e15b-4cc0-bf84-9308b5882c58','晚興','白居易','唐','唐诗','tang','','[]','極浦收殘雨，高城駐落暉。',48,'全唐诗/poet.tang.23000.json','["極浦收殘雨，高城駐落暉。", "山明虹半出，松闇鶴雙歸。", "將吏隨衙散，文書入務稀。", "閑吟倚新竹，筠粉汙朱衣。"]'),
('579cbfcf-f48f-47e2-a748-f95bf180084d','衰病','白居易','唐','唐诗','tang','','[]','老與病相仍，華簪髮不勝。',48,'全唐诗/poet.tang.23000.json','["老與病相仍，華簪髮不勝。", "行多朝散藥，睡少夜停燈。", "祿食分供鶴，朝衣減施僧。", "性多移不得，郡政謾如繩。"]'),
('4f001170-3421-4882-8c16-e4e7a32e8043','病中對病鶴','白居易','唐','唐诗','tang','','[]','同病病夫憐病鶴，精神不損翅翎傷。',64,'全唐诗/poet.tang.23000.json','["同病病夫憐病鶴，精神不損翅翎傷。", "未堪再舉摩霄漢，只合相隨覓稻粱。", "但作悲吟和嘹唳，難將俗貌對昂藏。", "唯應一事宜爲伴，我髮君毛俱似霜。"]'),
('3aa778f1-1020-4bdc-a218-8529b764caf6','夜歸','白居易','唐','唐诗','tang','','[]','半醉閑行湖岸東，馬鞭敲鐙轡瓏璁。',64,'全唐诗/poet.tang.23000.json','["半醉閑行湖岸東，馬鞭敲鐙轡瓏璁。", "萬株松樹青山上，十里沙堤明月中。", "樓角漸移當路影，潮頭欲過滿江風。", "歸來未放笙歌散，畫戟門開蠟燭紅。"]'),
('a93ecf08-48a0-47b3-8e72-392be8c1287b','臘後歲前遇景詠意','白居易','唐','唐诗','tang','','[]','海梅半日柳微黃，凍水初融日欲長。',64,'全唐诗/poet.tang.23000.json','["海梅半日柳微黃，凍水初融日欲長。", "度臘都無苦霜霰，迎春先有好風光。", "郡中起晚聽衙鼓，城上行慵倚女牆。", "公事漸閑身且健，使君殊未厭餘杭。"]'),
('810df757-20bc-4d13-b66d-be2c9cc79bed','白髮','白居易','唐','唐诗','tang','','[]','雪髮隨梳落，霜毛繞鬢垂。',48,'全唐诗/poet.tang.23000.json','["雪髮隨梳落，霜毛繞鬢垂。", "加添老氣味，改變舊容儀。", "不肯長如漆，無過總作絲。", "最憎明鏡裏，黑白半頭時。"]'),
('47a4d5bd-ce1e-49b5-8b0f-f8bd583f7e01','錢湖州以箬下酒李蘇州以五酘酒相次寄到無因飲聊詠所懷','白居易','唐','唐诗','tang','','[]','勞將箬下忘憂物，寄與江城愛酒翁。',64,'全唐诗/poet.tang.23000.json','["勞將箬下忘憂物，寄與江城愛酒翁。", "鐺脚三州何處會，甕頭一醆幾時同。", "傾如竹葉盈樽綠，飲作桃花上面紅。", "莫怪殷勤醉相憶，曾陪西省與南宮。"]'),
('87025b76-1907-41b2-bcc4-791fb2635cda','花樓望雪命宴賦詩','白居易','唐','唐诗','tang','','[]','連天際海白皚皚，好上高樓望一回。',128,'全唐诗/poet.tang.23000.json','["連天際海白皚皚，好上高樓望一回。", "何處更能分道路，此時兼不認池臺。", "萬重雲樹山頭翠，百尺花樓江畔開。", "素壁聯題分韻句，紅爐巡飲暖寒杯。", "冰鋪湖水銀爲面，風卷汀沙玉作堆。", "絆惹舞人春豔曳，句留醉客夜裴回。", "輸將虛白堂前鶴，失却樟亭驛後梅。", "別有故情偏憶得，曾經窮苦照書來。"]'),
('d945e94c-f439-4bbf-bc37-3a103396d2e7','晚歲','白居易','唐','唐诗','tang','','[]','壯歲忽已去，浮榮何足論。',96,'全唐诗/poet.tang.23000.json','["壯歲忽已去，浮榮何足論。", "身爲百口長，官是一州尊。", "不覺白雙鬢，徒言朱兩轓。", "病難施郡政，老未荅君恩。", "歲暮別兄弟，年衰無子孫。", "惹愁諳世網，治苦賴空門。", "擥帶知腰瘦，看燈覺眼昏。", "不緣衣食繫，尋合返丘園。"]'),
('e1d4d6ab-3f90-483e-b3a8-7c23246ba3b1','宿竹閣','白居易','唐','唐诗','tang','','[]','晚坐松簷下，宵眠竹閣間。',48,'全唐诗/poet.tang.23000.json','["晚坐松簷下，宵眠竹閣間。", "清虛當服藥，幽獨抵歸山。", "巧未能勝拙，忙應不及閑。", "無勞別修道，即此是玄關。"]'),
('5a7dbd31-1761-4e66-8f34-df7edcaee4b9','歲暮枉衢州張使君書並詩因以長句報之','白居易','唐','唐诗','tang','','[]','西州彼此意何如，官職蹉跎歲欲除。',64,'全唐诗/poet.tang.23000.json','["西州彼此意何如，官職蹉跎歲欲除。", "浮石潭邊停五馬，望濤樓上得雙魚。", "萬言舊手才難敵，五字新題思有餘。", "貧薄詩家無好物，反投桃李報瓊琚。"]'),
('3e046bc6-cc22-4226-90f8-5d8793fb343e','和薛秀才尋梅花同飲見贈','白居易','唐','唐诗','tang','','[]','忽驚林下發寒梅，便試花前飲冷杯。',64,'全唐诗/poet.tang.23000.json','["忽驚林下發寒梅，便試花前飲冷杯。", "白馬走迎詩客去，紅筵鋪待舞人來。", "歌聲怨處微微落，酒氣熏時旋旋開。", "若到歲寒無雨雪，猶應醉得兩三回。"]'),
('28568f92-dde2-49f0-ab98-741d0f59db01','與諸客空腹飲','白居易','唐','唐诗','tang','','[]','隔宿書招客，平明飲暖寒。',72,'全唐诗/poet.tang.23000.json','["隔宿書招客，平明飲暖寒。", "麴神寅日合，酒聖卯時歡。", "促膝纔飛白，酡顏已渥丹。", "碧籌攢米盌，紅袖拂骰盤。", "醉後歌尤異，狂來舞不難。", "拋杯語同坐，莫作老人看。"]'),
('91b17b98-529d-4330-bef5-7147e90c1b07','小歲日對酒吟錢湖州所寄詩','白居易','唐','唐诗','tang','','[]','獨酌無多興，閑吟有所思。',48,'全唐诗/poet.tang.23000.json','["獨酌無多興，閑吟有所思。", "一杯新歲酒，兩句故人詩。", "楊柳初黃日，髭鬚半白時。", "蹉跎春氣味，彼此老心知。"]'),
('32021394-9342-4eb9-b5c0-f98c6e3beece','錢唐湖春行','白居易','唐','唐诗','tang','','["\u6625\u5929", "\u5c71\u6c34", "\u5199\u666f", "\u897f\u6e56", "\u4e03\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5185)", "\u521d\u4e2d\u53e4\u8bd7"]','孤山寺北賈亭西，水面初平雲脚低。',64,'全唐诗/poet.tang.23000.json','["孤山寺北賈亭西，水面初平雲脚低。", "幾處早鶯爭暖樹，誰家新燕啄春泥。", "亂花漸欲迷人眼，淺草纔能沒馬蹄。", "最愛湖東行不足，綠楊陰裏白沙堤。"]'),
('10856231-1f48-4a64-867a-8bfed73394ef','題靈隱寺紅辛夷花戲酬光上人','白居易','唐','唐诗','tang','','[]','紫粉筆含尖火燄，紅胭脂染小蓮花。',32,'全唐诗/poet.tang.23000.json','["紫粉筆含尖火燄，紅胭脂染小蓮花。", "芳情鄉思知多少，惱得山僧悔出家。"]'),
('c5b750c2-412d-41c8-b56b-c2e46863c16e','重向火','白居易','唐','唐诗','tang','','[]','火銷灰復死，疎棄已經旬。',48,'全唐诗/poet.tang.23000.json','["火銷灰復死，疎棄已經旬。", "豈是人情薄，其如天氣春。", "風寒忽再起，手冷重相親。", "却就紅爐坐，心如逢故人。"]'),
('c26f958a-2a78-473a-a7c3-aabd98c57e35','候仙亭同諸客醉作','白居易','唐','唐诗','tang','','[]','謝安山下空攜妓，柳惲洲邊只賦詩。',32,'全唐诗/poet.tang.23000.json','["謝安山下空攜妓，柳惲洲邊只賦詩。", "爭及湖亭今日會，嘲花詠水贈蛾眉。"]'),
('86b751d9-67c9-409f-9cbb-4edbae21e7e3','城上','白居易','唐','唐诗','tang','','[]','城上鼕鼕鼓，朝衙復晚衙。',24,'全唐诗/poet.tang.23000.json','["城上鼕鼕鼓，朝衙復晚衙。", "爲君慵不出，落盡遶城花。"]'),
('295a3685-e53b-4b54-975b-f0eba9a4dd5f','早行林下','白居易','唐','唐诗','tang','','[]','披衣未冠櫛，晨起入前林。',48,'全唐诗/poet.tang.23000.json','["披衣未冠櫛，晨起入前林。", "宿露殘花氣，朝光新葉陰。", "傍松人跡少，隔竹鳥聲深。", "閑倚小橋立，傾頭時一吟。"]'),
('6b3354d3-9562-4837-b0fa-5715cefcf286','送李校書趂寒食歸義興山居','白居易','唐','唐诗','tang','','[]','大見騰騰詩酒客，不憂生計似君稀。',32,'全唐诗/poet.tang.23000.json','["大見騰騰詩酒客，不憂生計似君稀。", "到舍將何作寒食，滿船唯載樹陰歸。"]'),
('4bea25d5-1cef-483d-923d-bc9c50c7bbe5','題孤山寺山石榴花示諸僧衆','白居易','唐','唐诗','tang','','[]','山榴花似結紅巾，容豔新妍占斷春。',48,'全唐诗/poet.tang.23000.json','["山榴花似結紅巾，容豔新妍占斷春。", "色相故關行道地，香塵擬觸坐禪人。", "瞿曇弟子君知否，恐是天魔女化身。"]'),
('37554f86-f5f1-41ab-9407-acb72aef1907','獨行','白居易','唐','唐诗','tang','','[]','闇誦黃庭經在口，閑攜青竹杖隨身。',32,'全唐诗/poet.tang.23000.json','["闇誦黃庭經在口，閑攜青竹杖隨身。", "晚花新筍堪爲伴，獨入林行不要人。"]'),
('00c7cf86-e8a2-445c-9282-a84da1d2f419','二月五日花下作','白居易','唐','唐诗','tang','','[]','二月五日花如雪，五十二人頭似霜。',64,'全唐诗/poet.tang.23000.json','["二月五日花如雪，五十二人頭似霜。", "聞有酒時須笑樂，不關身事莫思量。", "羲和趂日沈西海，鬼伯驅人葬北邙。", "只有且來花下醉，從人笑道老顛狂。"]'),
('beab80c0-4c45-437c-823f-b208b32ffd0a','戲題木蘭花','白居易','唐','唐诗','tang','','[]','紫房日照胭脂拆，素豔風吹膩粉開。',32,'全唐诗/poet.tang.23000.json','["紫房日照胭脂拆，素豔風吹膩粉開。", "怪得獨饒脂粉態，木蘭曾作女郎來。"]'),
('aba3da6e-6977-421e-9d5d-08cb726edbe7','清明日觀妓舞聽客詩','白居易','唐','唐诗','tang','','[]','看舞顏如玉，聽詩韻似金。',48,'全唐诗/poet.tang.23000.json','["看舞顏如玉，聽詩韻似金。", "綺羅從許笑，弦管不妨吟。", "可惜春風老，無嫌酒醆深。", "辭花送寒食，併在此時心。"]'),
('8c37cdbb-74bd-4eea-b15e-2237a6d7eaf1','西湖晚歸回望孤山寺贈諸客','白居易','唐','唐诗','tang','','["\u897f\u6e56", "\u79bb\u522b", "\u5bfa\u5e99"]','柳湖松島蓮花寺，晚動歸橈出道場。',64,'全唐诗/poet.tang.23000.json','["柳湖松島蓮花寺，晚動歸橈出道場。", "盧橘子低山雨重，棕櫚葉戰水風涼。", "煙波澹蕩搖空碧，樓殿參差倚夕陽。", "到岸請君回首望，蓬萊宮在海中央。"]'),
('360ee1d1-7a76-469b-ac69-9f53ce9d048e','湖中自照','白居易','唐','唐诗','tang','','[]','重重照影看容鬢，不見朱顏見白絲。',32,'全唐诗/poet.tang.23000.json','["重重照影看容鬢，不見朱顏見白絲。", "失却少年無處覓，泥他湖水欲何爲。"]'),
('75d222ba-746d-4f0a-b994-70f88a107347','贈蘇鍊師','白居易','唐','唐诗','tang','','[]','兩鬢蒼然心浩然，松窗深處藥爐前。',64,'全唐诗/poet.tang.23000.json','["兩鬢蒼然心浩然，松窗深處藥爐前。", "攜將道士通宵語，忘却花時盡日眠。", "明鏡嬾開長在匣，素琴欲弄半無弦。", "猶嫌莊子多詞句，只讀逍遙六七篇。"]'),
('f495483b-ff37-4ee5-9e03-4c887f1f1e7a','杭州春望','白居易','唐','唐诗','tang','','["\u6625\u5929"]','望海樓明照曙霞，護江堤白蹋晴沙。',64,'全唐诗/poet.tang.23000.json','["望海樓明照曙霞，護江堤白蹋晴沙。", "濤聲夜入伍員廟，柳色春藏蘇小家。", "紅袖織綾誇柿蒂，青旗沽酒趂梨花。", "誰開湖寺西南路，草綠帬腰一道斜。"]'),
('60454e4c-357c-41ea-a88a-6f1a32f88b91','飲散夜歸贈諸客','白居易','唐','唐诗','tang','','[]','鞍馬夜紛紛，香街起暗塵。',48,'全唐诗/poet.tang.23000.json','["鞍馬夜紛紛，香街起暗塵。", "回鞭招飲妓，分火送歸人。", "風月應堪惜，杯觴莫厭頻。", "明朝三月盡，忍不送殘春。"]'),
('0a205e13-5f5f-466c-879d-375a7f9cae31','湖亭晚歸','白居易','唐','唐诗','tang','','[]','盡日湖亭臥，心閑事亦稀。',48,'全唐诗/poet.tang.23000.json','["盡日湖亭臥，心閑事亦稀。", "起因殘醉醒，坐待晚涼歸。", "松雨飄藤帽，江風透葛衣。", "柳堤行不厭，沙軟絮霏霏。"]'),
('8b699fb7-58fd-4453-b219-1d61ca830a05','東樓南望八韻','白居易','唐','唐诗','tang','','[]','不厭東南望，江樓對海門。',96,'全唐诗/poet.tang.23000.json','["不厭東南望，江樓對海門。", "風濤生有信，天水合無痕。", "鷁帶雲帆動，鷗和雪浪翻。", "魚鹽聚爲市，煙火起成村。", "日脚金波碎，峰頭鈿點繁。", "送秋千里雁，報暝一聲猿。", "已豁煩襟悶，仍開病眼昏。", "郡中登眺處，無勝此東軒。"]'),
('13d44d27-9a10-4a69-b3a5-36dcbf8c08f0','醉中酬殷協律','白居易','唐','唐诗','tang','','[]','泗水亭邊一分散，浙江樓上重遊陪。',64,'全唐诗/poet.tang.23000.json','["泗水亭邊一分散，浙江樓上重遊陪。", "揮鞭二十年前別，命駕三千里外來。", "醉袖放狂相向舞，愁眉和笑一時開。", "留君夜住非無分，且盡青娥紅燭臺。"]'),
('18a2aaed-39a3-4ec2-a730-4479ec0b94ec','孤山寺遇雨','白居易','唐','唐诗','tang','','[]','拂波雲色重，灑葉雨聲繁。',48,'全唐诗/poet.tang.23000.json','["拂波雲色重，灑葉雨聲繁。", "水鷺雙飛起，風荷一向翻。", "空濛連北岸，蕭颯入東軒。", "或擬湖中宿，留船在寺門。"]'),
('e1d929e5-752a-4723-b714-ac04d9b4300c','樟亭雙櫻樹','白居易','唐','唐诗','tang','','[]','南館西軒兩樹櫻，春條長足夏陰成。',32,'全唐诗/poet.tang.23000.json','["南館西軒兩樹櫻，春條長足夏陰成。", "素華朱實今雖盡，碧葉風來別有情。"]'),
('cd169b45-630e-4245-a827-dc7686757ea6','湖上夜飲','白居易','唐','唐诗','tang','','[]','郭外迎人月，湖邊醒酒風。',24,'全唐诗/poet.tang.23000.json','["郭外迎人月，湖邊醒酒風。", "誰留使君飲，紅燭在舟中。"]'),
('ce1aad4b-0a73-4672-ac3e-462570f25c04','贈沙鷗','白居易','唐','唐诗','tang','','[]','老逼教垂白，官科遣著緋。',48,'全唐诗/poet.tang.23000.json','["老逼教垂白，官科遣著緋。", "形骸雖有累，方寸却無機。", "遇酒多先醉，逢山愛晚歸。", "沙鷗不知我，猶被隼旟飛。"]'),
('29f31f28-0d0d-4624-be9a-e4e07527ef1a','餘杭形勝','白居易','唐','唐诗','tang','','[]','餘杭形勝四方無，州傍青山縣枕湖。',64,'全唐诗/poet.tang.23000.json','["餘杭形勝四方無，州傍青山縣枕湖。", "遶郭荷花三十里，拂城松樹一千株。", "夢兒亭古傳名謝，教妓樓新道姓蘇。", "獨有使君年太老，風光不稱白髭鬚。"]'),
('502123e7-040b-44d3-9c88-a942f97af3c4','江樓夕望招客','白居易','唐','唐诗','tang','','["\u590f\u5929", "\u5199\u666f"]','海天東望夕茫茫，山勢川形闊復長。',64,'全唐诗/poet.tang.23000.json','["海天東望夕茫茫，山勢川形闊復長。", "燈火萬家城四畔，星河一道水中央。", "風吹古木晴天雨，月照平沙夏夜霜。", "能就江樓銷暑否，比君茅舍較清涼。"]'),
('5e611466-4338-4f75-9f42-f49b2633e08b','新秋病起','白居易','唐','唐诗','tang','','[]','一葉落梧桐，年光半又空。',72,'全唐诗/poet.tang.23000.json','["一葉落梧桐，年光半又空。", "秋多上階日，涼足入懷風。", "病瘦形如鶴，愁焦鬢似蓬。", "損心詩思裏，伐性酒狂中。", "華蓋何曾惜，金丹不致功。", "猶須自慙媿，得作白頭翁。"]'),
('054fbc43-a17f-4617-862b-404d5aff0887','木芙蓉花下招客飲','白居易','唐','唐诗','tang','','[]','晚涼思飲兩三杯，召得江頭酒客來。',32,'全唐诗/poet.tang.23000.json','["晚涼思飲兩三杯，召得江頭酒客來。", "莫怕秋無伴醉物，水蓮花盡木蓮開。"]'),
('68ecc7bb-ca4b-4086-a5e2-c0c67278dd8c','悲歌','白居易','唐','唐诗','tang','','[]','白頭新洗鏡新磨，老逼身來不奈何。',64,'全唐诗/poet.tang.23000.json','["白頭新洗鏡新磨，老逼身來不奈何。", "耳裏頻聞故人死，眼前唯覺少年多。", "塞鴻遇暖猶回翅，江水因潮亦反波。", "獨有衰顏留不得，醉來無計但悲歌。"]'),
('d3f24d39-65c7-4348-973b-f8b7db595abc','江樓晚眺景物鮮奇吟翫成篇寄水部張員外','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u5199\u666f", "\u53cb\u60c5"]','澹煙疎雨間斜陽，江色鮮明海氣涼。',64,'全唐诗/poet.tang.23000.json','["澹煙疎雨間斜陽，江色鮮明海氣涼。", "蜃散雲收破樓閣，虹殘水照斷橋梁。", "風翻白浪花千片，雁點青天字一行。", "好著丹青圖畫取，題詩寄與水曹郎。"]'),
('b1b7bd80-f49d-42c6-a7cd-e69a89a6c046','夜招周協律兼荅所贈','白居易','唐','唐诗','tang','','[]','滿眼雖多客，開眉復向誰。',48,'全唐诗/poet.tang.23000.json','["滿眼雖多客，開眉復向誰。", "少年非我伴，秋夜與君期。", "落魄俱耽酒，殷勤共愛詩。", "相憐別有意，彼此老無兒。"]'),
('17e344ad-78f0-40e3-b093-4d078af1ec1a','重酬周判官','白居易','唐','唐诗','tang','','[]','秋愛冷吟春愛醉，詩家眷屬酒家仙。',32,'全唐诗/poet.tang.23000.json','["秋愛冷吟春愛醉，詩家眷屬酒家仙。", "若教早被浮名繫，可得閑遊三十年。"]'),
('116156e7-0b24-453c-9911-5b5eccdc875c','飲後夜醒','白居易','唐','唐诗','tang','','[]','黃昏飲散歸來臥，夜半人扶強起行。',64,'全唐诗/poet.tang.23000.json','["黃昏飲散歸來臥，夜半人扶強起行。", "枕上酒容和睡醒，樓前海月伴潮生。", "將歸梁燕還重宿，欲滅窗燈却復明。", "直至曉來猶妄想，耳中如有管弦聲。"]'),
('1737bbea-3ef5-4ac2-8bb8-781f0e4e3ca4','代賣薪女贈諸妓','白居易','唐','唐诗','tang','','[]','亂蓬爲鬢布爲巾，曉蹋寒山自負薪。',32,'全唐诗/poet.tang.23000.json','["亂蓬爲鬢布爲巾，曉蹋寒山自負薪。", "一種錢唐江畔女，著紅騎馬是何人。"]'),
('39bc30ef-ec3d-440c-8d6e-43a6dbdc42cf','奉和李大夫題新詩二首各六韻 因嚴亭','白居易','唐','唐诗','tang','','[]','箕潁人窮獨，蓬壺路阻難。',72,'全唐诗/poet.tang.23000.json','["箕潁人窮獨，蓬壺路阻難。", "何如兼吏隱，復得事躋攀。", "巖樹羅階下，江雲貯棟間。", "似移天目石，疑入武丘山。", "清景徒堪賞，皇恩肯放閑。", "遙知興未足，即被詔徵還。"]'),
('a65310a3-4f4a-4b39-bbd4-1c751654ac39','奉和李大夫題新詩二首各六韻 忘筌亭','白居易','唐','唐诗','tang','','[]','翠巘公門對，朱軒野徑連。',72,'全唐诗/poet.tang.23000.json','["翠巘公門對，朱軒野徑連。", "只開新戶牖，不改舊風煙。", "虛室閑生白，高情澹入玄。", "酒容同座勸，詩借屬城傳。", "自笑滄江畔，遙思絳帳前。", "亭臺隨處有，爭敢比忘筌。"]'),
('6726404c-7943-436f-94e1-febc9e898e49','予以長慶二年冬十月到杭州明年秋九月始與范陽盧賈汝南周元範蘭陵蕭悅清河崔求東萊劉方輿同遊恩德寺之泉洞竹石籍甚久矣及茲目擊果愜心期因自嗟云到郡周歲方來入寺半日復去俯視朱綬仰睇白雲有媿於心遂留絕句','白居易','唐','唐诗','tang','','[]','雲水埋藏恩德洞，簪裾束縛使君身。',32,'全唐诗/poet.tang.23000.json','["雲水埋藏恩德洞，簪裾束縛使君身。", "暫來不宿歸州去，應被山呼作俗人。"]'),
('5119931a-5ad3-4103-9df7-e0ca52472021','早冬','白居易','唐','唐诗','tang','','["\u51ac\u5929"]','十月江南天氣好，可憐冬景似春華。',64,'全唐诗/poet.tang.23000.json','["十月江南天氣好，可憐冬景似春華。", "霜經未殺萋萋草，日暖初乾漠漠沙。", "老柘葉黃如嫩樹，寒櫻枝白是狂花。", "此時却羨閑人醉，五馬無由入酒家。"]'),
('d9a78065-4fda-4aa6-b6b2-4596333bbbec','歲假內命酒贈周判官蕭協律','白居易','唐','唐诗','tang','','[]','共知欲老流年急，且喜新正假日頻。',64,'全唐诗/poet.tang.23000.json','["共知欲老流年急，且喜新正假日頻。", "聞健此時相勸醉，偷閑何處共尋春？", "脚隨周叟行猶疾，頭比蕭翁白未勻。", "歲酒先拈辭不得，被君推作少年人。"]'),
('66652d2e-dd84-451f-a266-0250675171d1','與諸客攜酒尋去年梅花有感','白居易','唐','唐诗','tang','','[]','馬上同攜今日杯，湖邊共覓去春梅。',64,'全唐诗/poet.tang.23000.json','["馬上同攜今日杯，湖邊共覓去春梅。", "年年只是人空老，處處何曾花不開。", "詩思又牽吟詠發，酒酣閑喚管弦來。", "樽前百事皆依舊，點檢惟無薛秀才。"]'),
('3e32e20e-eb28-4c84-9a5f-8509f83d1411','醉送李協律赴湖南辟命因寄沈八中丞','白居易','唐','唐诗','tang','','[]','富陽山底樟亭畔，立馬停舟飛酒盂。',64,'全唐诗/poet.tang.23000.json','["富陽山底樟亭畔，立馬停舟飛酒盂。", "曾共中丞情繾綣，暫留協律語踟躕。", "紫微星北承恩去，青草湖南稱意無。", "不羨君官羨君幕，幕中收得阮元瑜。"]'),
('29796e17-81d6-422e-bc49-8f13079457e0','內道場永讙上人就郡見訪善說維摩經臨別請詩因以此贈','白居易','唐','唐诗','tang','','[]','五夏登壇內殿師，水爲心地玉爲儀。',64,'全唐诗/poet.tang.23000.json','["五夏登壇內殿師，水爲心地玉爲儀。", "正傳金粟如來偈，何用錢唐太守詩。", "苦海出來應有路，靈山別後可無期。", "他生莫忘今朝會，虛白亭中法樂時。"]'),
('5a851e03-7de2-4c26-b4d1-6530858b6f31','見李蘇州示男阿武詩自感成詠','白居易','唐','唐诗','tang','','[]','遙羨青雲裏，祥鸞正引雛。',24,'全唐诗/poet.tang.23000.json','["遙羨青雲裏，祥鸞正引雛。", "自憐滄海伴，老蚌不生珠。"]'),
('4b754193-709e-428d-8704-8c6cd415febe','正月十五日夜月','白居易','唐','唐诗','tang','','[]','歲熟人心樂，朝遊復夜遊。',48,'全唐诗/poet.tang.23000.json','["歲熟人心樂，朝遊復夜遊。", "春風來海上，明月在江頭。", "燈火家家市，笙歌處處樓。", "無妨思帝里，不合厭杭州。"]'),
('7efc4040-d15d-4bf1-a767-4dc3d5745b5c','題州北路傍老柳樹','白居易','唐','唐诗','tang','','[]','皮枯緣受風霜久，條短爲應攀折頻。',64,'全唐诗/poet.tang.23000.json','["皮枯緣受風霜久，條短爲應攀折頻。", "但見半衰當此路，不知初種是何人。", "雪花零碎逐年減，煙葉稀疎隨分新。", "莫道老株芳意少，逢春猶勝不逢春。"]'),
('2b404fd3-9687-4ffa-9a21-e72fe0c6dc84','題清頭陀','白居易','唐','唐诗','tang','','[]','頭陀獨宿寺西峰，百尺禪菴半夜鐘。',32,'全唐诗/poet.tang.23000.json','["頭陀獨宿寺西峰，百尺禪菴半夜鐘。", "煙月蒼蒼風瑟瑟，更無雜樹對山松。"]'),
('4a6ae469-5456-4d91-ad2e-7e7a918243a9','自歎二首 一','白居易','唐','唐诗','tang','','[]','形羸自覺朝飡減，睡少偏知夜漏長。',32,'全唐诗/poet.tang.23000.json','["形羸自覺朝飡減，睡少偏知夜漏長。", "實事漸消虛事在，銀魚金帶遶腰光。"]'),
('1ec261d7-2f6e-487f-bc1f-4fe450e9e3f2','自歎二首 二','白居易','唐','唐诗','tang','','[]','二毛曉落梳頭嬾，兩眼春昏點藥頻。',32,'全唐诗/poet.tang.23000.json','["二毛曉落梳頭嬾，兩眼春昏點藥頻。", "唯有閑行猶得在，心情未到不如人。"]'),
('14d67e42-0340-4c29-8fd4-0beddfe1dc2a','湖上醉中代諸妓寄嚴郎中','白居易','唐','唐诗','tang','','["\u897f\u6e56"]','笙歌杯酒正歡娛，忽憶仙郎望帝都。',64,'全唐诗/poet.tang.23000.json','["笙歌杯酒正歡娛，忽憶仙郎望帝都。", "借問連宵直南省，何如盡日醉西湖。", "蛾眉別久心知否，雞舌含多口厭無。", "還有些些惆悵事，春來山路見蘼蕪。"]'),
('3a6a3da1-4cfd-462b-825b-96d5c69fe639','自詠','白居易','唐','唐诗','tang','','[]','悶發每吟詩引興，興來兼酌酒開顏。',64,'全唐诗/poet.tang.23000.json','["悶發每吟詩引興，興來兼酌酒開顏。", "欲逢假日先招客，正對衙時亦望山。", "句檢簿書多鹵莽，隄防官吏少機關。", "誰能頭白勞心力，人道無才也是閑。"]'),
('399cc2c0-7e2b-459e-8b0a-d2b3cd7c1714','晚興','白居易','唐','唐诗','tang','','[]','草淺馬翩翩，新晴薄暮天。',48,'全唐诗/poet.tang.23000.json','["草淺馬翩翩，新晴薄暮天。", "柳條春拂面，衫袖醉垂鞭。", "立語花堤上，行吟水寺前。", "等閑消一日，不覺過三年。"]'),
('82923c39-3a2b-42b3-9c25-7ba78cf2d029','早興','白居易','唐','唐诗','tang','','["\u6625\u5929", "\u751f\u6d3b", "\u5199\u666f", "\u6109\u60a6"]','晨光出照屋梁明，初打開門鼓一聲。',64,'全唐诗/poet.tang.23000.json','["晨光出照屋梁明，初打開門鼓一聲。", "犬上階眠知地濕，鳥臨窗語報天晴。", "半銷宿酒頭仍重，新脫冬衣體乍輕。", "睡覺心空思想盡，近來鄉夢不多成。"]'),
('996d0ffe-0b6f-429a-91d8-ed1fc00ac74f','竹樓宿','白居易','唐','唐诗','tang','','[]','小書樓下千竿竹，深火爐前一醆燈。',32,'全唐诗/poet.tang.23000.json','["小書樓下千竿竹，深火爐前一醆燈。", "此處與誰相伴宿，燒丹道士坐禪僧。"]'),
('9a4f5c72-2294-417e-9d69-127fb8bde4f7','湖上招客送春汎舟','白居易','唐','唐诗','tang','','[]','欲送殘春招酒伴，客中誰最有風情。',64,'全唐诗/poet.tang.23000.json','["欲送殘春招酒伴，客中誰最有風情。", "兩瓶箬下新開得，一曲霓裳初教成。", "排比管弦行翠袖，指麾船舫點紅旌。", "慢牽好向湖心去，恰似菱花鏡上行。"]'),
('6be59980-3bcc-4976-88ba-dd76d086c5ee','戲醉客','白居易','唐','唐诗','tang','','[]','莫言魯國書生懦，莫把杭州刺史欺。',32,'全唐诗/poet.tang.23000.json','["莫言魯國書生懦，莫把杭州刺史欺。", "醉客請君開眼望，綠楊風下有紅旗。"]'),
('d45a54cc-97ab-47b1-aeee-61723a6b2966','紫陽花','白居易','唐','唐诗','tang','','[]','何年植向仙壇上，早晚移栽到梵家。',32,'全唐诗/poet.tang.23000.json','["何年植向仙壇上，早晚移栽到梵家。", "雖在人間人不識，與君名作紫陽花。"]'),
('34ec193e-d946-435a-bb89-5a9db0fc951e','郡齋旬假始命宴呈座客示郡寮','白居易','唐','唐诗','tang','','[]','公門日兩衙，公假月三旬。',192,'全唐诗/poet.tang.23000.json','["公門日兩衙，公假月三旬。", "衙用決簿領，旬以會親賓。", "公多及私少，勞逸常不均。", "況爲劇郡長，安得閑宴頻。", "下車已二月，開筵始今晨。", "初黔軍廚突，一拂郡蹋塵。", "既備獻酬禮，亦具水陸珍。", "萍醅箬溪醑，水鱠松江鱗。", "侑食樂懸動，佐懽妓席陳。", "風流吳中客，佳麗江南人。", "歌節點隨袂，舞香遺在茵。", "清奏凝未闋，酡顏氣已春。", "衆賓勿遽起，羣寮且逡巡。", "無輕一日醉，用犒九日勤。", "微彼九日勤，何以治吾民。", "微此一日醉，何以樂吾身。"]'),
('0faab0ad-3d5f-49d1-9dc7-ca38c747f2bd','題西亭','白居易','唐','唐诗','tang','','[]','朝亦視簿書，暮亦視簿書。',168,'全唐诗/poet.tang.23000.json','["朝亦視簿書，暮亦視簿書。", "簿書視未竟，蟋蟀鳴座隅。", "始覺芳歲晚，復嗟塵務拘。", "西園景多暇，可以少躊躇。", "池鳥澹容與，橋柳高扶疎。", "煙蔓嫋青薜，水花披白蕖。", "何人造茲亭，華敞綽有餘。", "四簷軒鳥翅，複屋羅蜘蛛。", "直廊抵曲房，𥦖窱深且虛。", "修竹夾左右，清風來徐徐。", "此宜宴佳賓，鼓瑟吹笙竽。", "荒淫即不可，廢曠將何如。", "幸有酒與樂，及時歡且娛。", "忽其解郡印，他人來此居。"]'),
('1b185715-c371-4523-8c8c-6df2f414647e','郡中西園','白居易','唐','唐诗','tang','','[]','閑園多芳草，春夏香靡靡。',96,'全唐诗/poet.tang.23000.json','["閑園多芳草，春夏香靡靡。", "深樹足佳禽，旦暮鳴不已。", "院門閉松竹，庭徑穿蘭芷。", "愛彼池上橋，獨來聊徙倚。", "魚依藻長樂，鷗見人暫起。", "有時舟隨風，盡日蓮照水。", "誰知郡府內，景物閑如此。", "始悟諠靜緣，何嘗繫遠邇。"]'),
('1acf07e1-878e-4677-9e25-2fa7b3b4a4a3','北亭臥','白居易','唐','唐诗','tang','','[]','樹綠晚陰合，池涼朝氣清。',60,'全唐诗/poet.tang.23000.json','["樹綠晚陰合，池涼朝氣清。", "蓮開有佳色，鶴唳無凡聲。", "唯此閑寂境，愜我幽獨情。", "病假十五日，十日臥茲亭。", "明朝吏呼起，還復視黎甿。"]'),
('fcf6c22d-0c07-4dfb-852c-43e7e0a2206b','一葉落','白居易','唐','唐诗','tang','','[]','煩暑鬱未退，涼飆潛已起。',48,'全唐诗/poet.tang.23000.json','["煩暑鬱未退，涼飆潛已起。", "寒溫與盛衰，遰相爲表裏。", "蕭蕭秋林下，一葉忽先委。", "勿言微搖落，搖落從此始。"]'),
('03880586-a91e-4125-a989-63af0eb6b343','崔湖州贈紅石琴薦煥如錦文無以荅之以詩酬謝','白居易','唐','唐诗','tang','','[]','頳錦支綠綺，韻同相感深。',48,'全唐诗/poet.tang.23000.json','["頳錦支綠綺，韻同相感深。", "千年古澗石，八月秋堂琴。", "引出山水思，助成金玉音。", "人間無可比，比我與君心。"]'),
('4d170a23-8d7f-402e-bd3e-203d5d2b9e6b','九日宴集醉題郡樓兼呈周殷二判官','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','前年九日餘杭郡，呼賓命宴虛白堂。',384,'全唐诗/poet.tang.23000.json','["前年九日餘杭郡，呼賓命宴虛白堂。", "去年九日到東洛，今年九日來吳鄉。", "兩邊蓬鬢一時白，三處菊花同色黃。", "一日日知添老病，一年年覺惜重陽。", "江南九月未搖落，柳青蒲綠稻穟香。", "姑蘇臺榭倚蒼靄，太湖山水含清光。", "可憐假日好天色，公門吏靜風景涼。", "榜舟鞭馬取賓客，掃樓拂席排壺觴。", "胡琴錚鏦指撥刺，吳娃美麗眉眼長。", "笙歌一曲思凝絕，金鈿再拜光低昂。", "日脚欲落備燈燭，風頭漸高加酒漿。", "觥醆豔飜菡萏葉，舞鬟擺落茱萸房。", "半酣憑檻起四顧，七堰八門六十坊。", "遠近高低寺間出，東西南北橋相望。", "水道脉分櫂鱗次，里閭碁布城冊方。", "人煙樹色無隙罅，十里一片青茫茫。", "自問有何才與政，高廳大館居中央。", "銅魚今乃澤國節，刺史是古吳都王。", "郊無戎馬郡無事，門有棨戟腰有章。", "盛時儻來合慚媿，壯歲忽去還感傷。", "從事醒歸應不可，使君醉倒亦何妨。", "請君停杯聽我語，此語真實非虛狂。", "五旬已過不爲夭，七十爲期蓋是常。", "須知菊酒登高會，從此多無二十場。"]'),
('31fbf86c-ad15-4c12-9f7a-b39f87c82109','同微之贈別郭虛舟鍊師五十韻','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','我爲江司馬，君爲荆判司。',288,'全唐诗/poet.tang.23000.json','["我爲江司馬，君爲荆判司。", "俱當愁悴日，始識虛舟師。", "師年三十餘，白皙好容儀。", "專心在鉛汞，餘力工琴碁。", "靜彈弦數聲，閑飲酒一巵。", "因指塵土下，蜉蝣良可悲。", "不聞姑射上，千歲冰雪肌。", "不見遼城外，古今塚纍纍。", "嗟我天地間，有術人莫知。", "得可逃死籍，不唯走三尸。", "授我參同契，其辭妙且微。", "六一閟扃鐍，子午守雄雌。", "我讀隨日悟，心中了無疑。", "黃芽與紫車，謂其坐致之。", "自負因自歎，人生號男兒。", "若不佩金印，即合翳玉芝。", "高謝人間世，深結山中期。", "泥壇方合矩，鑄鼎圓中䂓。", "鑪橐一以動，瑞氣紅輝輝。", "齋心獨歎拜，中夜偷一窺。", "二物正訢合，厥狀何怪奇。", "綢繆夫婦體，狎獵魚龍姿。", "簡寂館鐘後，紫霄峰曉時。", "心塵未淨潔，火候遂參差。"]'),
('b9a7a335-e9cc-4737-bfe8-ebb2775baabf','霓裳羽衣歌','白居易','唐','唐诗','tang','','[]','我昔元和侍憲皇，曾陪內宴宴昭陽。',384,'全唐诗/poet.tang.23000.json','["我昔元和侍憲皇，曾陪內宴宴昭陽。", "千歌百舞不可數，就中最愛霓裳舞。", "舞時寒食春風天，玉鉤欄下香案前。", "案前舞者顏如玉，不著人家俗衣服。", "虹裳霞帔步搖冠，鈿瓔纍纍佩珊珊。", "娉婷似不任羅綺，顧聽樂懸行復止。", "磬簫箏笛遰相攙，擊擫彈吹聲邐迤。", "散序六奏未動衣，陽臺宿雲慵不飛。", "中序擘騞初入拍，秋竹竿裂春冰拆。", "飄然轉旋迴雪輕，嫣然縱送游龍驚。", "小垂手後柳無力，斜曳裾時雲欲生。", "煙蛾歛略不勝態，風袖低昂如有情。", "上元點鬟招萼綠，王母揮袂別飛瓊。", "繁音急節十二徧，跳珠撼玉何鏗錚。", "翔鸞舞了却收翅，唳鶴曲終長引聲。", "當時乍見驚心目，凝視諦聽殊未足。", "一落人間八九年，耳冷不曾聞此曲。", "湓城但聽山魈語，巴峽唯聞杜鵑哭。", "移領錢唐第二年，始有心情問絲竹。", "玲瓏箜篌謝好箏，陳寵觱栗沈平笙。", "清弦脆管纖纖手，教得霓裳一曲成。", "虛白亭前湖水畔，前後祗應三度按。", "便除庶子拋却來，聞道如今各星散。", "今年五月至蘇州，朝鍾暮角催白頭。"]'),
('6069212b-7f17-4683-97a1-4cb09c318781','小童薛陽陶吹觱栗歌','白居易','唐','唐诗','tang','','[]','剪削乾蘆插寒竹，九孔漏聲五音足。',256,'全唐诗/poet.tang.23000.json','["剪削乾蘆插寒竹，九孔漏聲五音足。", "近來吹者誰得名，關璀老死李衮生。", "衮今又老誰其嗣，薛氏樂童年十二。", "指點之下師授聲，含嚼之間天與氣。", "潤州城高霜月明，吟霜思月欲發聲。", "山頭江底何悄悄，猨聲不喘魚龍聽。", "翕然聲作疑管裂，詘然聲盡疑刀截。", "有時婉軟無筋骨，有時頓挫生稜節。", "急聲圓轉促不斷，轢轢轔轔似珠貫。", "緩聲展引長有條，有條直直如筆描。", "下聲乍墜石沈重，高聲忽舉雲飄蕭。", "明旦公堂陳宴席，主人命樂娛賓客。", "碎絲細竹徒紛紛，宮調一聲雄出羣。", "衆音覼縷不落道，有如部伍隨將軍。", "嗟爾陽陶方稚齒，下手發聲已如此。", "若教頭白吹不休，但恐聲名壓關李。"]'),
('e8fc4251-86ae-4712-be3a-3de4ccfc3abd','啄木曲','白居易','唐','唐诗','tang','','[]','莫買寶剪刀，虛費千金直。',140,'全唐诗/poet.tang.23000.json','["莫買寶剪刀，虛費千金直。", "我有心中愁，知君剪不得。", "莫磨解結錐，徒勞人氣力。", "我有腸中結，知君解不得。", "莫染紅絲線，徒誇好顏色。", "我有雙淚珠，知君穿不得。", "莫近紅爐火，炎氣徒相逼。", "我有兩鬢霜，知君銷不得。", "刀不能剪心愁，錐不能解腸結。", "線不能穿淚珠，火不能銷鬢雪。", "不如飲此神聖桮，萬念千憂一時歇。"]'),
('35837658-9e8d-4dfc-bbb3-b3362ac22aac','題靈巖寺','白居易','唐','唐诗','tang','','[]','娃宮屧廊尋已傾，硯池香徑又欲平。',80,'全唐诗/poet.tang.23000.json','["娃宮屧廊尋已傾，硯池香徑又欲平。", "二三月時何草綠，幾百年來空月明。", "使君雖老頗多思，攜觴領妓處處行。", "今愁古恨入絲竹，一曲涼州無限情。", "直自當時到今日，中間歌吹更無聲。"]'),
('e460854e-8bcf-4271-a31f-34ae0b716b2c','雙石','白居易','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蒼然兩片石，厥狀怪且醜。',192,'全唐诗/poet.tang.23000.json','["蒼然兩片石，厥狀怪且醜。", "俗用無所堪，時人嫌不取。", "結從胚渾始，得自洞庭口。", "萬古遺水濱，一朝入吾手。", "擔舁來郡內，洗刷去泥垢。", "孔黑煙痕深，罅青苔色厚。", "老蛟蟠作足，古劍插爲首。", "忽疑天上落，不似人間有。", "一可支吾琴，一可貯吾酒。", "峭絕高數尺，坳泓容一斗。", "五弦倚其左，一桮置其右。", "窪樽酌未空，玉山頹已久。", "人皆有所好，物各求其偶。", "漸恐少年場，不容垂白叟。", "迴頭問雙石，能伴老夫否。", "石雖不能言，許我爲三友。"]'),
('3fca035d-c6cf-4342-9191-903ff8113012','宿東亭曉興','白居易','唐','唐诗','tang','','[]','溫溫土爐火，耿耿紗籠燭。',96,'全唐诗/poet.tang.23000.json','["溫溫土爐火，耿耿紗籠燭。", "獨抱一張琴，夜入東齋宿。", "窗聲度殘漏，簾影浮初旭。", "頭癢曉梳多，眼昏春睡足。", "負暄簷宇下，散步池塘曲。", "南雁去未迴，東風來何速。", "雪依瓦溝白，草遶牆根綠。", "何言萬戶州，太守常幽獨。"]'),
('fad447d7-f34f-4673-9968-c7ec213132e7','日漸長贈周殷二判官','白居易','唐','唐诗','tang','','[]','日漸長，春尚早。',88,'全唐诗/poet.tang.23000.json','["日漸長，春尚早。", "牆頭半露紅萼枝，池岸新鋪綠芽草。", "蹋草攀枝仰頭歎，何人知此春懷抱。", "年顏盛壯名未成，官職欲高身已老。", "萬莖白髮真堪恨，一片緋衫何足道。", "賴得君來勸一桮，愁開悶破心頭好。"]'),
('3b102030-e7b9-4d33-94a0-bc41b4b57526','花前歎','白居易','唐','唐诗','tang','','[]','前歲花前五十二，今年花前五十五。',96,'全唐诗/poet.tang.23000.json','["前歲花前五十二，今年花前五十五。", "歲課年功頭髮知，從霜成雪君看取。", "幾人得老莫自嫌，樊李吳韋盡成土。", "南州桃李北州梅，且喜年年作花主。", "花前置酒誰相勸，容坐唱歌滿起舞。", "欲散重拈花細看，爭知明日無風雨。"]'),
('1243b13b-e3f2-4734-a6a0-d677e48cea63','自詠五首 一','白居易','唐','唐诗','tang','','[]','朝亦隨羣動，暮亦隨羣動。',48,'全唐诗/poet.tang.23000.json','["朝亦隨羣動，暮亦隨羣動。", "榮華瞬息間，求得將何用。", "形骸與冠蓋，假合相戲弄。", "但異睡著人，不知夢是夢。"]'),
('fc8e0c30-ec02-462e-8601-c33e39bce50b','自詠五首 二','白居易','唐','唐诗','tang','','[]','一家五十口，一郡十萬戶。',48,'全唐诗/poet.tang.23000.json','["一家五十口，一郡十萬戶。", "出爲差科頭，入爲衣食主。", "水旱合心憂，飢寒須手撫。", "何異食蓼蟲，不知苦是苦。"]'),
('96680031-9b2b-4975-a4fa-8e34fd6de2d8','自詠五首 三','白居易','唐','唐诗','tang','','[]','公私頗多事，衰憊殊少歡。',48,'全唐诗/poet.tang.23000.json','["公私頗多事，衰憊殊少歡。", "迎送賓客嬾，鞭笞黎庶難。", "老耳倦聲樂，病口厭桮盤。", "既無可戀者，何以不休官。"]'),
('62b4b922-029c-4cfa-be6b-6b5808534542','自詠五首 四','白居易','唐','唐诗','tang','','[]','一日復一日，自問何留滯。',48,'全唐诗/poet.tang.23000.json','["一日復一日，自問何留滯。", "爲貧逐日俸，擬作歸田計。", "亦須隨豐約，可得無限劑。", "若待足始休，休官在何歲。"]'),
('a2983fa1-241f-4118-bf7f-503ab95bb217','自詠五首 五','白居易','唐','唐诗','tang','','[]','官舍非我廬，官園非我樹。',48,'全唐诗/poet.tang.23000.json','["官舍非我廬，官園非我樹。", "洛中有小宅，渭上有別墅。", "既無婚嫁累，幸有歸休處。", "歸去誠已遲，猶勝不歸去。"]'),
('cb87243a-ab3a-4081-a8bc-ad0bed60be31','和微之聽妻彈別鶴操因爲解釋其義依韻加四句','白居易','唐','唐诗','tang','','[]','義重莫若妻，生離不如死。',168,'全唐诗/poet.tang.23000.json','["義重莫若妻，生離不如死。", "誓將死同穴，其奈生無子。", "商陵追禮教，婦出不能止。", "舅姑明旦辭，夫妻中夜起。", "起聞雙鶴別，若與人相似。", "聽其悲唳聲，亦如不得已。", "青田八九月，遼城一萬里。", "裴回去住雲，嗚咽東西水。", "寫之在琴曲，聽者酸心髓。", "況當秋月彈，先入憂人耳。", "怨抑掩朱弦，沈吟停玉指。", "一聞無兒歎，相念兩如此。", "無兒雖薄命，有妻偕老矣。", "幸免生別離，猶勝商陵氏。"]'),
('7b636316-47cb-4262-868f-2bc1d3710d2e','題故元少尹集後二首 一','白居易','唐','唐诗','tang','','[]','黃壤詎知我，白頭徒憶君。',24,'全唐诗/poet.tang.23000.json','["黃壤詎知我，白頭徒憶君。", "唯將老年淚，一灑故人文。"]'),
('9de28326-8069-4765-abd6-9c86be1923f3','題故元少尹集後二首 二','白居易','唐','唐诗','tang','','[]','遺文三十軸，軸軸金玉聲。',24,'全唐诗/poet.tang.23000.json','["遺文三十軸，軸軸金玉聲。", "龍門原上土，埋骨不埋名。"]'),
('abb4fac6-9d48-4aa1-bd73-b77cfc32d3ce','和微之四月一日作','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u597d\u53cb"]','四月一日天，花稀葉陰薄。',96,'全唐诗/poet.tang.23000.json','["四月一日天，花稀葉陰薄。", "泥新燕影忙，蜜熟蜂聲樂。", "麥風低冉冉，稻水平漠漠。", "芳節或蹉跎，遊心稍牢落。", "春華信爲美，夏景亦未惡。", "颭浪嫩青荷，重欄晚紅藥。", "吳宮好風月，越郡多樓閣。", "兩地誠可憐，其奈久離索。"]'),
('fdb0138d-0417-4b47-b673-93c6c0c5c05b','吳中好風景二首 一','白居易','唐','唐诗','tang','','[]','吳中好風景，八月如三月。',72,'全唐诗/poet.tang.23000.json','["吳中好風景，八月如三月。", "水荇葉仍香，木蓮花未歇。", "海天微雨散，江郭纖埃滅。", "暑退衣服乾，潮生船舫活。", "兩衙漸多暇，亭午初無熱。", "騎吏語使君，正是遊時節。"]'),
('65ec322b-30a4-4cc5-8fdd-ab2f4941d16e','吳中好風景二首 二','白居易','唐','唐诗','tang','','[]','吳中好風景，風景無朝暮。',72,'全唐诗/poet.tang.23000.json','["吳中好風景，風景無朝暮。", "曉色萬家煙，秋聲八月樹。", "舟移管弦動，橋擁旌旗駐。", "改號齊雲樓，重開武丘路。", "況當豐歲熟，好是歡遊處。", "州民勸使君，且莫拋官去。"]'),
('2ffca73b-8558-4fef-8b64-a09bd89f09ce','荅劉禹錫白太守行','白居易','唐','唐诗','tang','','[]','吏滿六百石，昔賢輙去之。',144,'全唐诗/poet.tang.23000.json','["吏滿六百石，昔賢輙去之。", "秩登二千石，今我方罷歸。", "我秩訝已多，我歸慙已遲。", "猶勝塵土下，終老無休期。", "臥乞百日告，起吟五篇詩。", "朝與府吏別，暮與州民辭。", "去年到郡時，麥穗黃離離。", "今年去郡日，稻花白霏霏。", "爲郡已周歲，半歲罹旱飢。", "襦袴無一片，甘棠無一枝。", "何乃老與幼，泣別盡沾衣。", "下慙蘇人淚，上媿劉君辭。"]'),
('39b492bd-c1f4-49d4-9459-12faad8a0568','別蘇州','白居易','唐','唐诗','tang','','[]','浩浩姑蘇民，鬱鬱長洲城。',96,'全唐诗/poet.tang.23000.json','["浩浩姑蘇民，鬱鬱長洲城。", "來慙荷寵命，去媿無能名。", "青紫行將吏，班白列黎甿。", "一時臨水拜，十里隨舟行。", "餞筵猶未收，征櫂不可停。", "稍隔煙樹色，尚聞絲竹聲。", "悵望武丘路，沈吟滸水亭。", "還鄉信有興，去郡能無情。"]'),
('e7e6034d-edea-4c7b-9a37-131116c3b47b','卯時酒','白居易','唐','唐诗','tang','','[]','佛法讚醍醐，仙方誇沆瀣。',204,'全唐诗/poet.tang.23000.json','["佛法讚醍醐，仙方誇沆瀣。", "未如卯時酒，神速功力倍。", "一杯置掌上，三嚥入腹內。", "煦若春貫腸，暄如日炙背。", "豈獨肢體暢，仍加志氣大。", "當時遺形骸，竟日忘冠帶。", "似遊華胥國，疑反混元代。", "一性既完全，萬機皆破碎。", "半醒思往來，往來吁可怪。", "寵辱憂喜間，惶惶二十載。", "前年辭紫闥，今歲拋皂蓋。", "去矣魚返泉，超然蟬離蛻。", "是非莫分別，行止無疑礙。", "浩氣貯胸中，青雲委身外。", "捫心私自語，自語誰能會。", "五十年來心，未如今日泰。", "況茲杯中物，行坐長相對。"]'),
('4eb3bc13-a189-404c-a353-a3a707034079','自問行何遲','白居易','唐','唐诗','tang','','[]','前月發京口，今辰次淮涯。',120,'全唐诗/poet.tang.23000.json','["前月發京口，今辰次淮涯。", "二旬四百里，自問行何遲。", "還鄉無他計，罷郡有餘資。", "進不慕富貴，退未憂寒飢。", "以此易過日，騰騰何所爲。", "逢山輙倚櫂，遇寺多題詩。", "酒醒夜深後，睡足日高時。", "眼底一無事，心中百不知。", "想到京國日，嬾放亦如斯。", "何必冒風水，促促赴程歸。"]'),
('8d93743a-814e-4342-8ea0-9bbe2ee7e8d0','除日荅夢得同發楚州','白居易','唐','唐诗','tang','','[]','共作千里伴，俱爲一郡迴。',48,'全唐诗/poet.tang.23000.json','["共作千里伴，俱爲一郡迴。", "歲陰中路盡，鄉思先春來。", "山雪晚猶在，淮冰晴欲開。", "歸歟吟可作，休戀主人杯。"]'),
('a100cba0-f4f6-4b81-beda-c63e8122eda6','問楊瓊','白居易','唐','唐诗','tang','','[]','古人唱歌兼唱情，今人唱歌唯唱聲。',32,'全唐诗/poet.tang.23000.json','["古人唱歌兼唱情，今人唱歌唯唱聲。", "欲說向君君不會，試將此語問楊瓊。"]'),
('3b70d2d3-cffd-41d8-8951-3e628aacb75b','有感三首 一','白居易','唐','唐诗','tang','','[]','鬢髮已斑白，衣綬方朱紫。',108,'全唐诗/poet.tang.23000.json','["鬢髮已斑白，衣綬方朱紫。", "窮賤當壯年，富榮臨暮齒。", "車輿紅塵合，第宅青煙起。", "彼來此須去，品物之常理。", "第宅非吾廬，逆旅暫留止。", "子孫非我有，委蛻而已矣。", "有如蠶造繭，又似花生子。", "子結花暗凋，繭成蠶老死。", "悲哉可奈何，舉世皆如此。"]'),
('f3b44eb9-9ea9-46cf-8490-6472aa6f2560','有感三首 二','白居易','唐','唐诗','tang','','[]','莫養瘦馬駒，莫教小妓女。',72,'全唐诗/poet.tang.23000.json','["莫養瘦馬駒，莫教小妓女。", "後事在目前，不信君看取。", "馬肥快行走，妓長能歌舞。", "三年五歲間，已聞換一主。", "借問新舊主，誰樂誰辛苦。", "請君大帶上，把筆書此語。"]'),
('abd04263-0280-4bd1-9370-398063c33fc3','有感三首 三','白居易','唐','唐诗','tang','','[]','往事勿追思，追思多悲愴。',84,'全唐诗/poet.tang.23000.json','["往事勿追思，追思多悲愴。", "來事勿相迎，相迎已惆悵。", "不如兀然坐，不如塌然臥。", "食來即開口，睡來即合眼。", "二事最關身，安寢加餐飯。", "忘懷任行止，委命隨修短。", "更若有興來，狂歌酒一醆。"]'),
('e411612f-36c0-4f09-86fc-9198e906174c','宿滎陽','白居易','唐','唐诗','tang','','[]','生長在滎陽，少小辭鄉曲。',84,'全唐诗/poet.tang.23000.json','["生長在滎陽，少小辭鄉曲。", "迢迢四十載，復向滎陽宿。", "去時十一二，今年五十六。", "追思兒戲時，宛然猶在目。", "舊居失處所，故里無宗族。", "豈唯變市朝，兼亦遷陵谷。", "獨有溱洧水，無情依舊綠。"]'),
('8bb4038c-b181-490e-9627-4a94aed23caa','經溱洧','白居易','唐','唐诗','tang','','[]','落日駐行騎，沈吟懷古情。',36,'全唐诗/poet.tang.23000.json','["落日駐行騎，沈吟懷古情。", "鄭風變已盡，溱洧至今清。", "不見士與女，亦無芍藥名。"]'),
('17bd2d15-5c19-4167-b1ec-bb505ba35baf','就花枝','白居易','唐','唐诗','tang','','[]','就花枝，移酒海，今朝不醉明朝悔。',64,'全唐诗/poet.tang.23000.json','["就花枝，移酒海，今朝不醉明朝悔。", "且算歡娛逐日來，任他容鬢隨年改。", "醉翻衫袖拋小令，笑擲骰盤呼大采。", "自量氣力與心情，三五年間猶得在。"]'),
('ef1e6f8a-20e2-4b25-9447-302b49a02c0f','喜雨','白居易','唐','唐诗','tang','','[]','圃旱憂葵菫，農旱憂禾菽。',120,'全唐诗/poet.tang.23000.json','["圃旱憂葵菫，農旱憂禾菽。", "人各有所私，我旱憂松竹。", "松乾竹焦死，眷眷在心目。", "灑葉溉其根，汲水勞僮僕。", "油雲忽東起，涼雨淒相續。", "似面洗垢塵，如頭得膏沐。", "千柯習習潤，萬葉欣欣綠。", "千日澆灌功，不如一霢霂。", "方知宰生靈，何異活草木。", "所以聖與賢，同心調玉燭。"]'),
('32abc201-5322-4e16-8a4c-a47d6f320397','題道宗上人十韻','白居易','唐','唐诗','tang','','[]','如來說偈讚，菩薩著論議。',120,'全唐诗/poet.tang.23000.json','["如來說偈讚，菩薩著論議。", "是故宗律師，以詩爲佛事。", "一音無差別，四句有詮次。", "欲使第一流，皆知不二義。", "精潔霑戒體，閑淡藏禪味。", "從容恣語言，縹緲離文字。", "旁延邦國彥，上達王公貴。", "先以詩句牽，後令入佛智。", "人多愛師句，我獨知師意。", "不似休上人，空多碧雲思。"]'),
('7a9c3a9e-8c4a-4ff3-a270-8873f2ce6a7d','寄皇甫賓客','白居易','唐','唐诗','tang','','[]','名利既兩忘，形體方自遂。',60,'全唐诗/poet.tang.23000.json','["名利既兩忘，形體方自遂。", "臥掩羅雀門，無人驚我睡。", "睡足斗擻衣，閑步中庭地。", "食飽摩挲腹，心頭無一事。", "除却玄晏翁，何人知此味。"]'),
('20181589-0514-4ed8-8cd0-06fd225a9baa','寄庾侍郎','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','一雙華亭鶴，數片太湖石。',72,'全唐诗/poet.tang.23000.json','["一雙華亭鶴，數片太湖石。", "巉巉蒼玉峰，矯矯青雲翮。", "是時歲云暮，淡薄煙景夕。", "庭霜封石稜，池雪印鶴跡。", "幽致竟誰別，閑靜聊自適。", "懷哉庾順之，好是今宵客。"]'),
('0ee7118f-7650-4ee6-be57-85c0fc557345','寄崔少監','白居易','唐','唐诗','tang','','[]','微微西風生，稍稍東方明。',84,'全唐诗/poet.tang.23000.json','["微微西風生，稍稍東方明。", "入秋神骨爽，琴曉絲桐清。", "彈爲古宮調，玉水寒泠泠。", "自覺弦指下，不是尋常聲。", "須臾羣動息，掩琴坐空庭。", "直至日出後，猶得心和平。", "惜哉意未已，不使崔君聽。"]'),
('7e1c64df-ab10-4a8c-aa0c-482ce2fb3012','醉題沈子明壁','白居易','唐','唐诗','tang','','[]','不愛君池東十叢菊，不愛君池南萬竿竹。',50,'全唐诗/poet.tang.23000.json','["不愛君池東十叢菊，不愛君池南萬竿竹。", "愛君簾下唱歌人，色似芙蓉聲似玉。", "我有陽關君未聞，若聞亦應愁殺君。"]'),
('ab1aa115-629e-4d0f-80d4-505d97e5a098','勸酒','白居易','唐','唐诗','tang','','[]','勸君一醆君莫辭，勸君兩醆君莫疑，勸君三醆君始知。',123,'全唐诗/poet.tang.23000.json','["勸君一醆君莫辭，勸君兩醆君莫疑，勸君三醆君始知。", "面上今日老昨日，心中醉時勝醒時。", "天地迢遙自長久，白兔赤烏相趂走。", "身後堆金拄北斗，不如生前一樽酒。", "君不見春明門外天欲明，喧喧歌哭半死生。", "遊人駐馬出不得，白轝素車爭路行。", "歸去來，頭已白，典錢將用買酒喫。"]'),
('497b1535-d58d-4c5f-b7e9-7f96c30f7673','落花','白居易','唐','唐诗','tang','','[]','留春春不住，春歸人寂寞。',72,'全唐诗/poet.tang.23000.json','["留春春不住，春歸人寂寞。", "厭風風不定，風起花蕭索。", "既興風前歎，重命花下酌。", "勸君嘗綠醅，教人拾紅萼。", "桃飄火燄燄，梨墮雪漠漠。", "獨有病眼花，春風吹不落。"]'),
('98dcb9e7-8b94-49ef-8a47-5338e86a1eed','對鏡吟','白居易','唐','唐诗','tang','','[]','白頭老人照鏡時，掩鏡沈吟吟舊詩。',112,'全唐诗/poet.tang.23000.json','["白頭老人照鏡時，掩鏡沈吟吟舊詩。", "二十年前一莖白，如今變作滿頭絲。", "吟罷迴頭索杯酒，醉來屈指數親知。", "老於我者多窮賤，設使身存寒且飢。", "少於我者半爲土，墓樹已抽三五枝。", "我今幸得見頭白，祿俸不薄官不卑。", "眼前有酒心無苦，只合歡娛不合悲。"]'),
('2a58e801-2e85-4ff4-afbd-ee231d4180d5','耳順吟寄敦詩夢得','白居易','唐','唐诗','tang','','[]','三十四十五慾牽，七十八十百病纏。',96,'全唐诗/poet.tang.23000.json','["三十四十五慾牽，七十八十百病纏。", "五十六十卻不惡，恬淡清淨心安然。", "已過愛貪聲利後，猶在病羸昏耄前。", "未無筋力尋山水，尚有心情聽管弦。", "閑開新酒嘗數醆，醉憶舊詩吟一篇。", "敦詩夢得且相勸，不用嫌他耳順年。"]'),
('82383be1-51c0-4cec-8f85-1bf67cadf690','別氈帳火爐','白居易','唐','唐诗','tang','','[]','憶昨臘月天，北風三尺雪。',132,'全唐诗/poet.tang.23000.json','["憶昨臘月天，北風三尺雪。", "年老不禁寒，夜長安可徹。", "賴有青氈帳，風前自張設。", "復此紅火爐，雪中相暖熱。", "如魚入淵水，似兔藏深穴。", "婉軟蟄鱗蘇，溫燉凍肌活。", "方安陰慘夕，遽變陽和節。", "無奈時候遷，豈是恩情絕。", "毳䈴逐日卷，香燎隨灰滅。", "離恨屬三春，佳期在十月。", "但令此身健，不作多時別。"]'),
('a85be59c-7f0a-4ed0-8f8b-0a1c488a9c7a','六年春贈分司東都諸公','白居易','唐','唐诗','tang','','[]','我爲同州牧，內愧無才術。',192,'全唐诗/poet.tang.23000.json','["我爲同州牧，內愧無才術。", "忝擢恩已多，遭逢幸非一。", "偶當穀賤歲，適值民安日。", "郡縣獄空虛，鄉閭盜奔逸。", "其間最幸者，朝客多分秩。", "行接鴛鷺羣，坐成芝蘭室。", "時聯拜表騎，間動題詩筆。", "夜雪秉燭遊，春風攜榼出。", "花教鶯點檢，柳付風排比。", "法酒淡清漿，含桃嫋紅實。", "洛童調金管，盧女鏗瑤瑟。", "黛慘歌思深，腰凝舞拍密。", "每因同醉樂，自覺忘衰疾。", "始悟肘後方，不如杯中物。", "生涯隨日過，世事何時畢？", "老子苦乖慵，希君數牽率。"]'),
('466bfb48-8305-4336-abb8-b305f6d3ff70','九日代羅樊二妓招舒著作','白居易','唐','唐诗','tang','','[]','羅敷歛雙袂，樊姬獻一杯。',24,'全唐诗/poet.tang.23000.json','["羅敷歛雙袂，樊姬獻一杯。", "不見舒員外，秋菊爲誰開。"]'),
('87ae2fcf-ebac-4c7b-afff-a6e755458eb3','憶舊遊','白居易','唐','唐诗','tang','','[]','憶舊遊，舊遊安在哉。',154,'全唐诗/poet.tang.23000.json','["憶舊遊，舊遊安在哉。", "舊遊之人半白首，舊遊之地多蒼苔。", "江南舊遊凡幾處，就中最憶吳江隈。", "長洲苑綠柳萬樹，齊雲樓春酒一杯。", "閶門曉嚴旗鼓出，臯橋夕鬧船舫迴。", "修蛾慢臉燈下醉，急管繁弦頭上催。", "六七年前狂爛熳，三千里外思裴回。", "李娟張態一春夢，周五殷三歸夜臺。", "虎丘月色爲誰好，娃宮花枝應自開。", "賴得劉郎解吟詠，江山氣色合歸來。"]'),
('7701ea54-785c-4d66-9e3a-e5f2660bd7c7','荅崔賓客晦叔十二月四日見寄','白居易','唐','唐诗','tang','','[]','今歲日餘二十六，來歲年登六十二。',64,'全唐诗/poet.tang.23000.json','["今歲日餘二十六，來歲年登六十二。", "尚不能憂眼下身，因何更算人間事。", "居士忘筌默默坐，先生枕麴昏昏睡。", "早晚相從歸醉鄉，醉鄉去此無多地。"]'),
('e8112241-86ef-4590-8cac-e4e8c7122e05','勸我酒','白居易','唐','唐诗','tang','','[]','勸我酒，我不辭，請君歌，歌莫遲。',48,'全唐诗/poet.tang.23000.json','["勸我酒，我不辭，請君歌，歌莫遲。", "歌聲長，辭亦切，此辭聽者堪愁絕。", "洛陽女兒面似花，河南大尹頭如雪。"]'),
('43fd39da-bfaa-41d8-8f33-9fec8c6d3e0f','贈韋處士六年夏大熱旱','白居易','唐','唐诗','tang','','[]','驕陽連毒暑，動植皆枯槁。',72,'全唐诗/poet.tang.23000.json','["驕陽連毒暑，動植皆枯槁。", "旱日乾密雲，炎煙焦茂草。", "少壯猶困苦，況予病且老。", "脫無白栴檀，何以除熱惱。", "汗巾束頭鬢，羶食熏襟抱。", "始覺韋山人，休糧散髮好。"]'),
('6043d0cf-f6f4-4389-afe9-9947551528dd','和微之詩二十三首 和晨霞','白居易','唐','唐诗','tang','','[]','君歌仙氏真，我歌慈氏真。',144,'全唐诗/poet.tang.23000.json','["君歌仙氏真，我歌慈氏真。", "慈氏發真念，念此閻浮人。", "左命大迦葉，右召桓提因。", "千萬化菩薩，百億諸鬼神。", "上自非相頂，下及風水輪。", "胎卵濕化類，蠢蠢難具陳。", "弘願在救㧞，大悲忘辛勤。", "無論善不善，豈間冤與親。", "抉開生盲眼，擺去煩惱塵。", "燭以智慧日，洒之甘露津。", "千界一時度，萬法無與鄰。", "借問晨霞子，何如朝玉宸。"]'),
('abe80e63-1b33-433f-9b99-348a4fed3edf','和微之詩二十三首 和送劉道士遊天台','白居易','唐','唐诗','tang','','[]','聞君夢遊仙，輕舉超世雰。',240,'全唐诗/poet.tang.23000.json','["聞君夢遊仙，輕舉超世雰。", "握持尊皇節，統衛吏兵軍。", "靈旂星月象，天衣龍鳳紋。", "佩服交帶籙，諷吟蘂珠文。", "閬宮縹緲間，鈞樂依稀聞。", "齋心謁西母，暝拜朝東君。", "煙霏子晉裾，霞爛麻姑帬。", "倏忽別真侶，悵望隨歸雲。", "人生同大夢，夢與覺誰分。", "況此夢中夢，悠哉何足云。", "假如金闕頂，設使銀河濆。", "既未出三界，猶應在五蘊。", "飲嚥日月精，菇嚼沆瀣芬。", "尚是色香味，六塵之所熏。", "仙中有大仙，首出夢幻羣。", "慈光一照燭，奧法相絪緼。", "不知萬齡暮，不見三光曛。", "一性自了了，萬緣徒紛紛。", "苦海不能漂，劫火不能焚。", "此是竺乾教，先生垂典墳。"]'),
('80d4fe18-fb0c-482f-b811-52b3c1f38801','和微之詩二十三首 和櫛沐寄道友','白居易','唐','唐诗','tang','','[]','櫛沐事朝謁，中門初動關。',144,'全唐诗/poet.tang.23000.json','["櫛沐事朝謁，中門初動關。", "盛服去尚早，假寐須臾間。", "鐘聲發東寺，夜色藏南山。", "停驂待五漏，人馬同時閑。", "高星粲金粟，落月沈玉環。", "出門向關路，坦坦無阻艱。", "始出里北閈，稍轉市西闤。", "晨燭照朝服，紫爛復朱殷。", "由來朝廷士，一入多不還。", "因循擲白日，積漸凋朱顏。", "青雲已難致，碧落安能攀。", "但且知止足，尚可銷憂患。"]'),
('b990f3cd-8045-44c3-8065-83f6e6c08bbb','和微之詩二十三首 和祝蒼華','白居易','唐','唐诗','tang','','[]','日居復月諸，環迴照下土。',144,'全唐诗/poet.tang.23000.json','["日居復月諸，環迴照下土。", "使我玄雲髮，化爲素絲縷。", "稟質本羸劣，養生仍莽鹵。", "痛飲困連宵，悲吟飢過午。", "遂令頭上髮，種種無尺五。", "根稀比黍苗，梢細同釵股。", "豈是乏膏沐，非關櫛風雨。", "最爲悲傷多，心焦衰落苦。", "餘者能有幾，落者不可數。", "禿似鵲填河，墮如烏解羽。", "蒼華何用祝，苦辭亦休吐。", "匹如剃頭僧，豈要巾冠主。"]'),
('c2d59515-fff8-45cf-822e-8b39cf2b1936','和微之詩二十三首 和我年三首 一','白居易','唐','唐诗','tang','','[]','我年五十七，榮名得幾許。',48,'全唐诗/poet.tang.23000.json','["我年五十七，榮名得幾許。", "甲乙三道科，蘇杭兩州主。", "才能本淺薄，心力虛勞苦。", "可能隨衆人，終老於塵土。"]'),
('9028ca0d-bb90-4442-b2ac-de0009c8774f','和微之詩二十三首 和我年三首 二','白居易','唐','唐诗','tang','','[]','我年五十七，歸去誠已遲。',120,'全唐诗/poet.tang.23000.json','["我年五十七，歸去誠已遲。", "歷官十五政，數若珠纍纍。", "野萍始賓薦，場苗初縶維。", "因讀管蕭書，竊慕大有爲。", "及遭榮遇來，乃覺才力羸。", "黃紙詔頻草，朱輪車載脂。", "妻孥及僕使，皆免寒與飢。", "省躬私自媿，知我者微之。", "永懷山陰守，未遂嵩陽期。", "如何坐留滯，頭白江之湄。"]'),
('e392bb57-06bc-4c4f-946b-5423d9168e5e','和微之詩二十三首 和我年三首 三','白居易','唐','唐诗','tang','','[]','我年五十七，榮名得非少。',120,'全唐诗/poet.tang.23000.json','["我年五十七，榮名得非少。", "報國竟何如，謀身猶未了。", "昔嘗速官謗，恩大而懲小。", "一黜鶴辭軒，七年魚在沼。", "將枯鱗再躍，經鎩翮重矯。", "白日上昭昭，青雲高渺渺。", "平生頗同病，老大宜相曉。", "紫綬足可榮，白頭不爲夭。", "夙懷慕箕潁，晚節期松篠。", "何當闕下來，同拜陳情表。"]'),
('73b0a94b-f4cd-4d0e-bce0-98bd1ff8f5dc','和微之詩二十三首 和三月三十日四十韻','白居易','唐','唐诗','tang','','[]','送春君何在，君在山陰署。',288,'全唐诗/poet.tang.23000.json','["送春君何在，君在山陰署。", "憶我蘇杭時，春遊亦多處。", "爲君歌往事，豈敢辭勞慮。", "莫怪言語狂，須知酬荅遽。", "江南臘月半，水凍凝如瘀。", "寒景尚蒼茫，和風已吹噓。", "女牆城似竈，雁齒橋如鋸。", "魚尾上奫淪，草芽生沮洳。", "律遲太簇管，日緩羲和馭。", "布澤木龍催，迎春土牛助。", "雨師習習灑，雲將飄飄翥。", "四野萬里晴，千山一時曙。", "杭土麗且康，蘇民富而庶。", "善惡有懲勸，剛柔無吐茹。", "兩衙少辭牒，四境稀書疏。", "俗以勞倈安，政因閑暇著。", "仙亭日登眺，虎丘時遊豫。", "尋幽駐旌軒，選勝迴賓御。", "舟移溪鳥避，樂作林猨覰。", "池古莫耶沈，石奇羅剎踞。", "水苗泥易耨，畬粟灰難鋤。", "紫蕨抽出畦，白蓮埋在淤。", "萎花紅帶黯，濕葉黃含菸。", "鏡動波颭菱，雪迴風旋絮。"]'),
('823f66eb-a017-42ca-a666-67d2f2060aff','和微之詩二十三首 和寄樂天','白居易','唐','唐诗','tang','','[]','賢愚類相交，人情之大率。',266,'全唐诗/poet.tang.23000.json','["賢愚類相交，人情之大率。", "然自古今來，幾人號膠漆。", "近聞屈指數，元某與白乙。", "旁愛及弟兄，中權避家室。", "松筠與金石，未足喻堅密。", "在車如輪轅，在身如肘腋。", "又如風雲會，天使相召匹。", "不似勢利交，有名而無實。", "頃我在杭歲，值君之越日。", "望愁來儀遲，宴惜流景疾。", "坐耀黃金帶，酌酡頳玉質。", "酣歌口不停，狂舞衣相拂。", "平生賞心事，施展十未一。", "會笑始啞啞，離嗟乃唧唧。", "餞筵纔收拾，征櫂遽排[比]。", "後恨苦緜緜，前歡何卒卒。", "居人色慘淡，行子心紆鬱。", "風袂去時揮，雲帆望中失。", "宿酲和別思，目眩心忽忽。", "病魂黯然銷，老淚淒其出。", "別君只如昨，芳歲換六七。", "俱是官家身，後期難自必。"]'),
('84e6e181-9ec1-430d-b915-8ac3031ab5cb','和微之詩二十三首 和寄問劉白','白居易','唐','唐诗','tang','','[]','正與劉夢得，醉笑大開口。',96,'全唐诗/poet.tang.23000.json','["正與劉夢得，醉笑大開口。", "適值此詩來，歡喜君知否。", "遂令高卷幕，兼遣重添酒。", "起望會稽雲，東南一回首。", "愛君金玉句，舉世誰人有。", "功用隨日新，資材本天授。", "吟哦不能散，自午將及酉。", "遂留夢得眠，匡牀宿東牖。"]'),
('dc3432c5-e14a-4e74-b79d-0d14a56d0882','和微之詩二十三首 和新樓北園偶集從孫公度周巡官韓秀才盧秀才范處士小飲鄭侍御判官周劉二從事皆先歸','白居易','唐','唐诗','tang','','[]','聞君新樓宴，下對北園花。',240,'全唐诗/poet.tang.23000.json','["聞君新樓宴，下對北園花。", "主人既賢豪，賓客皆才華。", "初筵日未高，中飲景已斜。", "天地爲幕席，富貴如泥沙。", "嵇劉陶阮徒，不足置齒牙。", "臥甕鄙畢卓，落帽嗤孟嘉。", "芳草供枕藉，亂鶯助諠譁。", "醉鄉得道路，狂海無津涯。", "一歲春又盡，百年期不賒。", "同醉君莫辭，獨醒古所嗟。", "銷愁若沃雪，破悶如割瓜。", "稱觴起爲壽，此樂無以加。", "歌聲凝貫珠，舞袖飄亂麻。", "相公謂四座，今日非自誇。", "有奴善吹笙，有婢彈琵琶。", "十指纖若笋，雙鬟黳如鵶。", "履舃起交雜，杯盤散紛拏。", "歸去勿擁遏，倒載逃難遮。", "明日宴東武，後日遊若耶。", "豈獨相公樂，謳歌千萬家。"]'),
('11f3beb4-78c7-4a65-acf1-70e6da9b3c33','和微之詩二十三首 和除夜作','白居易','唐','唐诗','tang','','[]','君賦此詩夜，窮陰歲之餘。',240,'全唐诗/poet.tang.23000.json','["君賦此詩夜，窮陰歲之餘。", "我和此詩日，微和春之初。", "老知顏狀改，病覺肢體虛。", "頭上毛髮短，口中牙齒疎。", "一落老病界，難逃生死墟。", "況此促促世，與君多索居。", "君在浙江東，榮駕方伯輿。", "我在魏闕下，謬乘大夫車。", "妻孥常各飽，奴婢亦盈廬。", "唯是利人事，比君全不如。", "我統十郎官，君領百吏胥。", "我掌四曹局，君管十鄉閭。", "君爲父母君，大惠在資儲。", "我爲刀筆吏，小惡乃誅鋤。", "君提七郡籍，我按三尺書。", "俱已佩金印，嘗同趨玉除。", "外寵信非薄，中懷何不攄？", "恩光未報荅，日月空居諸。", "磊落嘗許君，跼促應笑予。", "所以自知分，欲先歌歸歟。"]'),
('8ae61364-f04d-49b7-84a8-3780c71767a4','和微之詩二十三首 和知非','白居易','唐','唐诗','tang','','[]','因君知非問，詮較天下事。',240,'全唐诗/poet.tang.23000.json','["因君知非問，詮較天下事。", "第一莫若禪，第二無如醉。", "禪能泯人我，醉可忘榮悴。", "與君次第言，爲我少留意。", "儒教重禮法，道家養神氣。", "重禮足滋彰，養神多避忌。", "不如學禪定，中有甚深味。", "曠廓了如空，澄凝勝於睡。", "屏除默默念，銷盡悠悠思。", "春無傷春心，秋無感秋淚。", "坐成真諦樂，如受空王賜。", "既得脫塵勞，兼應離慙媿。", "除禪其次醉，此說非無謂。", "一酌機即忘，三杯性咸遂。", "逐臣去室婦，降虜敗軍帥。", "思苦膏火煎，憂深扃鏁祕。", "須憑百杯沃，莫惜千金費。", "便似罩中魚，脫飛生兩翅。", "勸君雖老大，逢酒莫迴避。", "不然即學禪，兩途同一致。"]'),
('93b51226-9fc9-4701-9b47-91f36660f8d5','和微之詩二十三首 和望曉','白居易','唐','唐诗','tang','','[]','休吟稽山曉，聽詠秦城旦。',240,'全唐诗/poet.tang.23000.json','["休吟稽山曉，聽詠秦城旦。", "鳴雞初有聲，宿鳥猶未敢。", "丁丁漏向盡，鼕鼕鼓過半。", "南山青沈沈，東方白漫漫。", "街心若流水，城角如斷岸。", "星河稍隅落，宮闕方輪煥。", "朝車雷四合，騎火星一貫。", "赫奕冠蓋盛，熒煌朱紫爛。", "沙堤亘蟆池，市路遶龍斷。", "白日忽照耀，紅塵紛散亂。", "貴教過客避，榮任行人看。", "祥煙滿虛空，春色無邊畔。", "鵷行候晷刻，龍尾登霄漢。", "臺殿暖宜攀，風光晴可翫。", "草鋪地茵褥，雲卷天幃幔。", "鶯雜佩鏘鏘，花饒衣粲粲。", "何言終日樂，獨起臨風歎。", "歎我同心人，一別春七換。", "相望山隔礙，欲去官羇絆。", "何日到江東，超然似張翰。"]'),
('148444f1-0860-4e7f-81f9-580b5b13ff35','和微之詩二十三首 和李勢女','白居易','唐','唐诗','tang','','[]','減一分太短，增一分太長。',180,'全唐诗/poet.tang.23000.json','["減一分太短，增一分太長。", "不朱面若花，不粉肌如霜。", "色爲天下豔，心乃女中郎。", "自言重不幸，家破身未亡。", "人各有一死，此死職所當。", "忍將先人體，與主爲疣瘡。", "妾死主意快，從此兩無妨。", "願信赤心語，速即白刃光。", "南郡忽感激，却立捨鋒鋩。", "撫背稱阿姉，歸我如歸鄉。", "竟以恩信待，豈止猜妬忘。", "由來几上肉，不足揮干將。", "南郡死已久，骨枯墓蒼蒼。", "願於墓上頭，立石鐫此章。", "勸誡天下婦，不令陰勝陽。"]'),
('2da6f57d-2c94-499b-84a9-06fe3b710b29','和微之詩二十三首 和酬鄭侍御東陽春悶放懷追越遊見寄','白居易','唐','唐诗','tang','','[]','君得嘉魚置賓席，樂如南有嘉魚時。',320,'全唐诗/poet.tang.23000.json','["君得嘉魚置賓席，樂如南有嘉魚時。", "勁氣森爽竹竿竦，妍文煥爛芙蓉披。", "載筆在幕名已重，補衮於朝官尚卑。", "一緘疏入掩谷永，三都賦成排左思。", "自言拜辭主人後，離心蕩颺風前旗。", "東南門館別經歲，春眼悵望秋心悲。", "昨日嘉魚來訪我，方駕同出何所之。", "樂遊原頭春尚早，百舌新語聲椑椑。", "日趂花忙向南拆，風催柳急從東吹。", "流年惝怳不饒我，美景鮮妍來爲誰。", "紅塵三條界阡陌，碧草千里鋪郊畿。", "餘霞斷時綺幅裂，斜雲展處羅文紕。", "暮鐘遠近聲互動，暝鳥高下飛追隨。", "酒酣將歸未能去，悵然迴望天四垂。", "生何足養嵇著論，途何足泣楊漣洏。", "胡不花下伴春醉，滿酌綠酒聽黃鸝。", "嘉魚點頭時一歎，聽我此言不知疲。", "語終興盡各分散，東西軒騎分逶迤。", "此詩勿遣閑人見，見恐與他爲笑資。", "白首舊寮知我者，憑君一詠向周師。"]'),
('3e747be6-af37-404d-9769-10310ae6865a','和微之詩二十三首 和自勸二首 一','白居易','唐','唐诗','tang','','[]','稀稀疎疎遶籬竹，窄窄狹狹向陽屋。',112,'全唐诗/poet.tang.23000.json','["稀稀疎疎遶籬竹，窄窄狹狹向陽屋。", "屋中有一曝背翁，委置形骸如土木。", "日暮半爐麩炭火，夜深一醆紗籠燭。", "不知有益及民無，二十年來食官祿。", "就暖移盤簷下食，防寒擁被帷中宿。", "秋官月俸八九萬，豈徒遣爾身溫足。", "勤操丹筆念黃沙，莫使飢寒囚滯獄。"]'),
('a90ea65f-d444-4114-8a45-8e388d8f316f','和微之詩二十三首 和自勸二首 二','白居易','唐','唐诗','tang','','[]','急景凋年急於水，念此攬衣中夜起。',112,'全唐诗/poet.tang.23000.json','["急景凋年急於水，念此攬衣中夜起。", "門無宿客共誰言，暖酒挑燈對妻子。", "身飲數杯妻一醆，餘酌分張與兒女。", "微酣靜坐未能眠，風霰蕭蕭打窗紙。", "自問有何才與術，入爲丞郎出刺史。", "爭知壽命短復長，豈得營營心不止。", "請看韋孔與錢崔，半月之間四人死。"]'),
('0049ab5e-35b3-4b28-8ccb-d42953684733','和微之詩二十三首 和雨中花','白居易','唐','唐诗','tang','','[]','真宰倒持生殺柄，閑物命長人短命。',128,'全唐诗/poet.tang.23000.json','["真宰倒持生殺柄，閑物命長人短命。", "松枝上鶴蓍下龜，千年不死仍無病。", "人生不得似龜鶴，少去老來同旦暝。", "何異花開旦暝間，未落仍遭風雨橫。", "草得經年菜連月，唯花不與多時節。", "一年三百六十日，花能幾日供攀折。", "桃李無言難自訴，黃鶯解語憑君說。", "鶯雖爲說不分明，葉底枝頭謾饒舌。"]'),
('8d6b4a4c-4f96-4dd9-b7f1-260c3938e6c5','和微之詩二十三首 和晨興因報問龜兒','白居易','唐','唐诗','tang','','[]','冬旦寒慘澹，雲日無晶輝。',264,'全唐诗/poet.tang.23000.json','["冬旦寒慘澹，雲日無晶輝。", "當此歲暮感，見君晨興詩。", "君詩亦多苦，苦在兄遠離。", "我苦不在遠，纏綿肝與脾。", "西院病孀婦，後牀孤姪兒。", "黃昏一慟後，夜半十起時。", "病眼兩行血，衰鬢萬莖絲。", "咽絕五臟脉，瘦消百骸脂。", "雙目失一目，四肢斷兩肢。", "不如溘然逝，安用半活爲。", "誰謂荼蘗苦，荼蘗甘如飴。", "誰謂湯火熱，湯火冷如澌。", "前時君寄詩，憂念問阿龜。", "喉燥聲氣窒，經年無報辭。", "及覩晨興句，未吟先涕垂。", "因茲漣洳際，一吐心中悲。", "茫茫四海間，此苦唯君知。", "去我四千里，使我告訴誰。", "仰頭向青天，但見雁南飛。", "憑雁寄一語，爲我達微之。", "弦絕有續膠，樹斬可接枝。", "唯我中腸斷，應無連得期。"]'),
('21877b55-99a7-4cea-924a-6874a2d6f208','和微之詩二十三首 和朝回與王鍊師遊南山下','白居易','唐','唐诗','tang','','[]','藹藹春景餘，峨峨夏雲初。',132,'全唐诗/poet.tang.23000.json','["藹藹春景餘，峨峨夏雲初。", "躞蹀退朝騎，飄颻隨風裾。", "晨從四丞相，入拜白玉除。", "暮與一道士，出尋青谿居。", "吏隱本齊致，朝野孰云殊。", "道在有中適，機忘無外虞。", "但媿煙霄上，鸞鳳爲吾徒。", "又慙雲林間，鷗鶴不我疎。", "坐傾數杯酒，臥枕一卷書。", "興酣頭兀兀，睡覺心于于。", "以此送日月，問師爲何如。"]'),
('fe8abf15-d516-4526-b92b-4296e4a036b0','和微之詩二十三首 和嘗新酒','白居易','唐','唐诗','tang','','[]','空腹嘗新酒，偶成卯時醉。',72,'全唐诗/poet.tang.23000.json','["空腹嘗新酒，偶成卯時醉。", "醉來擁褐裘，直至齋時睡。", "睡酣不語笑，真寢無夢寐。", "殆欲妄形骸，詎知屬天地。", "醒餘和未散，起坐澹無事。", "舉臂一欠伸，引琴彈秋思。"]'),
('95495c6c-5817-4f98-a14d-67f7fe8f757f','和微之詩二十三首 和順之琴者','白居易','唐','唐诗','tang','','[]','陰陰花院月，耿耿蘭房燭。',48,'全唐诗/poet.tang.23000.json','["陰陰花院月，耿耿蘭房燭。", "中有弄琴人，聲貌俱如玉。", "清泠石泉引，雅澹風松曲。", "遂使君子心，不愛凡絲竹。"]'),
('e4357924-8175-4ffe-a067-84c3b8c2800e','感舊寫真','白居易','唐','唐诗','tang','','[]','李放寫我真，寫來二十載。',48,'全唐诗/poet.tang.23000.json','["李放寫我真，寫來二十載。", "莫問真何如，畫亦銷光彩。", "朱顏與玄鬢，日夜改復改。", "無嗟貌遽非，且喜身猶在。"]'),
('23b552dd-7625-4f7d-8732-5e40089c8014','授太子賓客歸洛','白居易','唐','唐诗','tang','','[]','南省去拂衣，東都來掩扉。',48,'全唐诗/poet.tang.23000.json','["南省去拂衣，東都來掩扉。", "病將老齊至，心與身同歸。", "白首外緣少，紅塵前事非。", "懷哉紫芝叟，千載心相依。"]'),
('286f5f2d-f4b4-41bf-917e-1e3b416dca7f','秋池二首 一','白居易','唐','唐诗','tang','','[]','身閑無所爲，心閑無所思。',72,'全唐诗/poet.tang.23000.json','["身閑無所爲，心閑無所思。", "況當故園夜，復此新秋池。", "岸闇鳥棲後，橋明月出時。", "菱風香散漫，桂露光參差。", "靜境多獨得，幽懷竟誰知。", "悠然心中語，自問來何遲。"]'),
('af61cc9f-2381-4655-819c-230c3365c515','秋池二首 二','白居易','唐','唐诗','tang','','[]','朝衣薄且健，晚簟清仍滑。',72,'全唐诗/poet.tang.23000.json','["朝衣薄且健，晚簟清仍滑。", "社近燕影稀，雨餘蟬聲歇。", "閑中得詩境，此境幽難說。", "露荷珠自傾，風竹玉相戛。", "誰能一同宿，共翫新秋月。", "暑退早涼歸，池邊好時節。"]'),
('13a460c7-575a-41e9-a0ca-2b8dcfeda075','中隱','白居易','唐','唐诗','tang','','[]','大隱住朝市，小隱入丘樊。',192,'全唐诗/poet.tang.23000.json','["大隱住朝市，小隱入丘樊。", "丘樊太冷落，朝市太囂諠。", "不如作中隱，隱在留司官。", "似出復似處，非忙亦非閑。", "不勞心與力，又免飢與寒。", "終歲無公事，隨月有俸錢。", "君若好登臨，城南有秋山。", "君若愛遊蕩，城東有春園。", "君若欲一醉，時出赴賓筵。", "洛中多君子，可以恣歡言。", "君若欲高臥，但自深掩關。", "亦無車馬客，造次到門前。", "人生處一世，其道難兩全。", "賤即苦凍餒，貴則多憂患。", "唯此中隱士，致身吉且安。", "窮通與豐約，正在四者間。"]'),
('3b19086c-7e7f-439a-8c37-e44593620e46','問秋光','白居易','唐','唐诗','tang','','[]','殷卿領北鎮，崔尹開南幕。',96,'全唐诗/poet.tang.23000.json','["殷卿領北鎮，崔尹開南幕。", "外事信爲榮，中懷未必樂。", "何如不才者，兀兀無所作。", "不引窗下琴，即舉池上酌。", "淡交唯對水，老伴無如鶴。", "自適頗從容，旁觀誠濩落。", "身心轉恬泰，煙景彌淡泊。", "迴首語秋光，東來應不錯。"]'),
('bf6984f5-c9e3-44b4-8f2a-b383d333e380','引泉','白居易','唐','唐诗','tang','','[]','一爲止足限，二爲衰疾牽。',96,'全唐诗/poet.tang.23000.json','["一爲止足限，二爲衰疾牽。", "邴罷不因事，陶歸非待年。", "歸來嵩洛下，閉戶何翛然。", "靜掃林下地，閑疏池畔泉。", "伊流狹似帶，洛石大如拳。", "誰教明月下，爲我聲濺濺。", "竟夕舟中坐，有時橋上眠。", "何用施屏障，水竹繞牀前。"]'),
('6c275866-8d4b-4d35-be47-b61e8b30ab21','知足吟','白居易','唐','唐诗','tang','','[]','不種一隴田，倉中有餘粟。',84,'全唐诗/poet.tang.23000.json','["不種一隴田，倉中有餘粟。", "不採一株桑，箱中有餘服。", "官閑離憂責，身泰無羈束。", "中人百戶稅，賓客一年祿。", "樽中不乏酒，籬下仍多菊。", "是物皆有餘，非心無所欲。", "吟君未貧作，因歌知足曲。"]'),
('d27f11de-c34f-4536-851f-4435568918fc','酬集賢劉郎中對月見寄兼懷元浙東','白居易','唐','唐诗','tang','','[]','月在洛陽天，天高淨如水。',48,'全唐诗/poet.tang.23000.json','["月在洛陽天，天高淨如水。", "下有白頭人，擥衣中夜起。", "思遠鏡亭上，光深書殿裏。", "眇然三處心，相去各千里。"]'),
('d7c02f7d-fa4f-4cdf-96bb-8a3dbd367ff8','太湖石','白居易','唐','唐诗','tang','','["\u5e90\u5c71", "\u592a\u6e56"]','遠望老嵯峨，近觀怪嶔崟。',120,'全唐诗/poet.tang.23000.json','["遠望老嵯峨，近觀怪嶔崟。", "纔高八九尺，勢若千萬尋。", "嵌空華陽洞，重疊匡山岑。", "邈矣仙掌迥，呀然劒門深。", "形質冠今古，氣色通晴陰。", "未秋已瑟瑟，欲雨先沈沈。", "天姿信爲異，時用非所任。", "磨刀不如礪，擣帛不如砧。", "何乃主人意，重之如萬金。", "豈伊造物者，獨能知我心。"]'),
('2764f524-86dd-401a-a2c9-1d0bd1f81599','偶作二首 一','白居易','唐','唐诗','tang','','[]','擾擾貪生人，幾何不夭閼。',168,'全唐诗/poet.tang.23000.json','["擾擾貪生人，幾何不夭閼。", "遑遑愛名人，幾何能貴達。", "伊余信多幸，拖紫垂白髮。", "身爲三品官，年已五十八。", "筋骸雖早衰，尚未苦羸惙。", "資產雖不豐，亦不甚貧竭。", "登山力猶在，遇酒興時發。", "無事日月長，不羈天地闊。", "安身有處所，適意無時節。", "解帶松下風，抱琴池上月。", "人間所重者，相印將軍鉞。", "謀慮繫安危，威權主生殺。", "焦心一身苦，炙手旁人熱。", "未必方寸間，得如吾快活。"]'),
('785590e7-17a4-4c7b-8033-42d16049d86e','偶作二首 二','白居易','唐','唐诗','tang','','[]','日出起盥櫛，振衣入道場。',168,'全唐诗/poet.tang.23000.json','["日出起盥櫛，振衣入道場。", "寂然無他念，但對一爐香。", "日高始就食，食亦非膏粱。", "精麤隨所有，亦足飽充腸。", "日午脫巾簪，燕息窗下牀。", "清風颯然至，臥可致羲皇。", "日西引杖屨，散步遊林塘。", "或飲茶一醆，或吟詩一章。", "日入多不食，有時唯命觴。", "何以送閑夜，一曲秋霓裳。", "一日分五時，作息率有常。", "自喜老後健，不嫌閑中忙。", "是非一以貫，身世交相忘。", "若問此何許，此是無何鄉。"]'),
('98bf9c38-4377-4d83-8a33-44da839c074b','葺池上舊亭','白居易','唐','唐诗','tang','','[]','池月夜淒涼，池風曉蕭颯。',72,'全唐诗/poet.tang.23000.json','["池月夜淒涼，池風曉蕭颯。", "欲入池上冬，先葺池上閤。", "向暖窗戶開，迎寒簾幕合。", "苔封舊瓦木，水照新朱蠟。", "軟火深土爐，香醪小瓷榼。", "中有獨宿翁，一燈對一榻。"]'),
('cc773646-1554-4f5e-85d4-c08bba91083a','崔十八新池','白居易','唐','唐诗','tang','','[]','愛君新小池，池色無人知。',36,'全唐诗/poet.tang.23000.json','["愛君新小池，池色無人知。", "見底月明夜，無波風定時。", "忽看不似水，一泊稀琉璃。"]'),
('eb69c926-d217-460d-8f8d-557bbf1e3d91','翫止水','白居易','唐','唐诗','tang','','[]','動者樂流水，靜者樂止水。',144,'全唐诗/poet.tang.23000.json','["動者樂流水，靜者樂止水。", "利物不如流，鑒形不如止。", "淒清早霜降，淅瀝微風起。", "中面紅葉開，四隅綠萍委。", "廣狹八九丈，灣環有涯涘。", "淺深三四尺，洞徹無表裏。", "淨分鶴翹足，澄見魚掉尾。", "迎眸洗眼塵，隔胷蕩心滓。", "定將禪不別，明與誠相似。", "清能律貪夫，淡可交君子。", "豈唯空狎翫，亦取相倫擬。", "欲識靜者心，心源只如此。"]'),
('ce224708-590d-41e5-8846-d64855cc0b31','聞崔十八宿予新昌弊宅時予亦宿崔家依仁新亭一宵偶同兩興暗合因而成詠聊以寫懷','白居易','唐','唐诗','tang','','[]','陋巷掩弊廬，高居敞華屋。',72,'全唐诗/poet.tang.23000.json','["陋巷掩弊廬，高居敞華屋。", "新昌七株松，依仁萬莖竹。", "松前月臺白，竹下風池綠。", "君向我齋眠，我在君亭宿。", "平生有微尚，彼此多幽獨。", "何必本主人，兩心聊自足。"]'),
('6deaf9da-b96e-448b-9801-60b08b08e3bb','日長','白居易','唐','唐诗','tang','','[]','日長晝加餐，夜短朝餘睡。',72,'全唐诗/poet.tang.23000.json','["日長晝加餐，夜短朝餘睡。", "春來寢食間，雖老猶有味。", "林塘得芳景，園曲生幽致。", "愛水多櫂舟，惜花不掃地。", "幸無眼下病，且向樽前醉。", "身外何足言，人間本無事。"]'),
('3c13a024-9fe0-4da2-bc52-466c4b128d81','三月三十日作','白居易','唐','唐诗','tang','','[]','今朝三月盡，寂寞春事畢。',72,'全唐诗/poet.tang.23000.json','["今朝三月盡，寂寞春事畢。", "黃鳥漸無聲，朱櫻新結實。", "臨風獨長歎，此歎意非一。", "半百過九年，豔陽殘一日。", "隨年減歡笑，逐日添衰疾。", "且遣花下歌，送此杯中物。"]'),
('18b621f6-9582-4d29-989f-18342c58e2be','慵不能','白居易','唐','唐诗','tang','','[]','架上非無書，眼慵不能看。',72,'全唐诗/poet.tang.23000.json','["架上非無書，眼慵不能看。", "匣中亦有琴，手慵不能彈。", "腰慵不能帶，頭慵不能冠。", "午後恣情寢，午時隨事餐。", "一餐終日飽，一寢至夜安。", "飢寒亦閑事，況乃不飢寒。"]'),
('c9115aa6-6422-43a0-bc70-af9f68718582','晨興','白居易','唐','唐诗','tang','','[]','宿鳥動前林，晨光上東屋。',60,'全唐诗/poet.tang.23000.json','["宿鳥動前林，晨光上東屋。", "銅爐添早香，紗籠滅殘燭。", "頭醒風稍愈，眼飽睡初足。", "起坐兀無思，叩齒三十六。", "何以解宿齋，一杯雲母粥。"]'),
('e8ed8c78-b5e4-4fc7-ae0b-04d477d98e38','朝課','白居易','唐','唐诗','tang','','[]','平甃白石渠，靜掃青苔院。',60,'全唐诗/poet.tang.23000.json','["平甃白石渠，靜掃青苔院。", "池上好風來，新荷大如扇。", "小亭中何有，素琴對黃卷。", "蘂珠諷數篇，秋思彈一徧。", "從容朝課畢，方與客相見。"]'),
('ea947281-09d2-4141-a645-d41ab8e32f8e','天竺寺七葉堂避暑','白居易','唐','唐诗','tang','','[]','鬱鬱復鬱鬱，伏熱何時畢？',48,'全唐诗/poet.tang.23000.json','["鬱鬱復鬱鬱，伏熱何時畢？", "行入七葉堂，煩暑隨步失。", "簷雨稍霏微，窗風正蕭瑟。", "清宵一覺睡，可以銷百疾。"]'),
('588afe78-35b7-4bb8-beb5-93c4682cf7a8','香山寺石樓潭夜浴','白居易','唐','唐诗','tang','','[]','炎光晝方熾，暑氣宵彌毒。',72,'全唐诗/poet.tang.23000.json','["炎光晝方熾，暑氣宵彌毒。", "搖扇風甚微，褰裳汗霢霂。", "起向月下行，來就潭中浴。", "平石爲浴牀，窪石爲浴斛。", "綃巾薄露頂，草屨輕乘足。", "清涼詠而歸，歸上石樓宿。"]'),
('47baa840-dc88-4eeb-be58-dff3923562dc','嗟髮落','白居易','唐','唐诗','tang','','[]','朝亦嗟髮落，暮亦嗟髮落。',96,'全唐诗/poet.tang.23000.json','["朝亦嗟髮落，暮亦嗟髮落。", "落盡誠可嗟，盡來亦不惡。", "既不勞洗沐，又不煩梳掠。", "最宜濕暑天，頭輕無髻縛。", "脫置垢巾幘，解去塵纓絡。", "銀瓶貯寒泉，當頂傾一勺。", "有如醍醐灌，坐受清涼樂。", "因悟自在僧，亦資於剃削。"]'),
('a4390519-9bc0-4e53-8f6b-9a9bd05da14d','安穩眠','白居易','唐','唐诗','tang','','[]','家雖日漸貧，猶未苦飢凍。',48,'全唐诗/poet.tang.23000.json','["家雖日漸貧，猶未苦飢凍。", "身雖日漸老，幸無急病痛。", "眼逢鬧處合，心向閑時用。", "既得安穩眠，亦無顛倒夢。"]'),
('4a81a664-d32f-4457-8437-33a956f0cab6','池上夜境','白居易','唐','唐诗','tang','','[]','晴空星月落池塘，澄鮮淨綠表裏光。',64,'全唐诗/poet.tang.23000.json','["晴空星月落池塘，澄鮮淨綠表裏光。", "露簟清瑩迎夜滑，風襟瀟灑先秋涼。", "無人驚處野禽下，新睡覺時幽草香。", "但問塵埃能去否，濯纓何必向滄浪。"]'),
('c11b09fb-df90-4d1a-b649-ec2b58aae1a1','書紳','白居易','唐','唐诗','tang','','[]','仕有職役勞，農有畎畮勤。',120,'全唐诗/poet.tang.23000.json','["仕有職役勞，農有畎畮勤。", "優哉分司叟，心力無苦辛。", "歲晚頭又白，自問何欣欣。", "新酒始開甕，舊穀猶滿囷。", "吾嘗靜自思，往往夜達晨。", "何以送吾老，何以安吾貧。", "歲計莫如穀，飽則不干人。", "日計莫如醉，醉則兼忘身。", "誠知有道理，未敢勸交親。", "恐爲人所哂，聊自書諸紳。"]'),
('11bb1d5d-bacd-473b-b40c-db87e238c2a3','秋遊平泉贈韋處士閑禪師','白居易','唐','唐诗','tang','','[]','秋景引閑步，山遊不知疲。',96,'全唐诗/poet.tang.23000.json','["秋景引閑步，山遊不知疲。", "杖藜捨輿馬，十里與僧期。", "昔嘗憂六十，四體不支持。", "今來已及此，猶未苦衰羸。", "心興遇境發，身力因行知。", "尋雲到起處，愛泉聽滴時。", "南村韋處士，西寺閑禪師。", "山頭與澗底，聞健且相隨。"]'),
('da5adcc3-327e-4fc0-aa4c-5da11168391e','遊坊口懸泉偶題石上','白居易','唐','唐诗','tang','','[]','濟源山水好，老尹知之久。',168,'全唐诗/poet.tang.23000.json','["濟源山水好，老尹知之久。", "常日聽人言，今秋入吾手。", "孔山刀劒立，沁水龍蛇走。", "危磴上懸泉，澄灣轉坊口。", "虛明見深底，淨綠無纖垢。", "仙櫂浪悠揚，塵纓風斗藪。", "巖寒松柏短，石古莓苔厚。", "錦坐纓高低，翠屏張左右。", "雖無安石妓，不乏文舉酒。", "談笑逐身來，管弦隨事有。", "時逢杖錫客，或值垂綸叟。", "相與澹忘歸，自辰將及酉。", "公門欲返駕，溪路猶迴首。", "早晚重來遊，心期罷官後。"]'),
('a00a1c19-38e6-48d5-9ebc-ddffc9bb2fc4','對火翫雪','白居易','唐','唐诗','tang','','[]','平生所心愛，愛火兼憐雪。',96,'全唐诗/poet.tang.23000.json','["平生所心愛，愛火兼憐雪。", "火是臘天春，雪爲陰夜月。", "鵝毛紛正墮，獸炭敲初折。", "盈尺白鹽寒，滿爐紅玉熱。", "稍宜杯酌動，漸引笙歌發。", "但識歡來由，不知醉時節。", "銀盤堆柳絮，羅袖摶瓊屑。", "共愁明日銷，便作經年別。"]'),
('8845e428-c238-4437-963f-5be4ac8c3653','六年寒食洛下宴遊贈馮李二少尹','白居易','唐','唐诗','tang','','[]','豐年寒食節，美景洛陽城。',132,'全唐诗/poet.tang.23000.json','["豐年寒食節，美景洛陽城。", "三尹皆強健，七日盡晴明。", "東郊蹋青草，南園攀紫荆。", "風拆海榴豔，露墜木蘭英。", "假開春未老，宴合日屢傾。", "珠翠混花影，管弦藏水聲。", "佳會不易得，良辰亦難幷。", "聽吟歌暫輟，看舞杯徐行。", "米價賤如土，酒味濃於餳。", "此時不盡醉，但恐負平生。", "殷勤二曹長，各捧一銀觥。"]'),
('8fcd22c4-5e50-4d5b-bead-c2d1ac8138fa','苦熱中寄舒員外','白居易','唐','唐诗','tang','','[]','何堪日衰病，復此時炎燠。',60,'全唐诗/poet.tang.23000.json','["何堪日衰病，復此時炎燠。", "厭對俗杯盤，倦聽凡絲竹。", "藤牀鋪晚雪，角枕截寒玉。", "安得清瘦人，新秋夜同宿。", "非君固不可，何夕枉高躅。"]'),
('90c5447c-3e7e-405f-90d4-a846a5f2a6e4','閑夕','白居易','唐','唐诗','tang','','[]','一聲早蟬發，數點新螢度。',72,'全唐诗/poet.tang.23000.json','["一聲早蟬發，數點新螢度。", "蘭釭耿無煙，筠簟清有露。", "未歸後房寢，且下前軒步。", "斜月入低廊，涼風滿高樹。", "放懷常自適，遇境多成趣。", "何法使之然，心中無細故。"]'),
('fd581e88-663e-43c2-9f46-3266c62f0b68','寄情','白居易','唐','唐诗','tang','','[]','灼灼早春梅，東南枝最早。',48,'全唐诗/poet.tang.23000.json','["灼灼早春梅，東南枝最早。", "持來翫未足，花向手中老。", "芳香銷掌握，悵望生懷抱。", "豈無後開花，念此先開好。"]'),
('0ed940e8-52a3-4e9b-92b3-4bcbd62f1ff7','舒員外遊香山寺數日不歸兼辱尺書大誇勝事時正值坐衙慮囚之際走筆題長句以贈之','白居易','唐','唐诗','tang','','[]','香山石樓倚天開，翠屏壁立波環迴。',128,'全唐诗/poet.tang.23000.json','["香山石樓倚天開，翠屏壁立波環迴。", "黃菊繁時好客到，碧雲合處佳人來。", "酡顏一笑夭桃綻，清吟數聲寒玉哀。", "軒騎逶遲櫂容與，留連三日不能迴。", "白頭老尹府中坐，早衙纔退暮衙催。", "庭前堦上何所有，纍囚成貫案成堆。", "豈無池塘長秋草，亦有絲竹生塵埃。", "今日清光昨夜月，竟無人來勸一杯。"]'),
('f5fc3434-3031-4ce8-8010-c0dfa1c1d5ff','早冬遊王屋自靈都抵陽臺上方望天壇偶吟成章寄溫谷周尊師中書李相公','白居易','唐','唐诗','tang','','[]','霜降山水清，王屋十月時。',168,'全唐诗/poet.tang.23000.json','["霜降山水清，王屋十月時。", "石泉碧漾漾，巖樹紅離離。", "朝爲靈都遊，暮有陽臺期。", "飄然世塵外，鸞鶴如可追。", "忽念公程盡，復慙身力衰。", "天壇在天半，欲上心遲遲。", "嘗聞此遊者，隱客與損之。", "各抱貴仙骨，俱非泥垢姿。", "二人相顧言，彼此稱男兒。", "若不爲松喬，即須作臯夔。", "今果如其語，光彩雙葳蕤。", "一人佩金印，一人翳玉芝。", "我來高其事，詠歡偶成詩。", "爲君題石上，欲使故山知。"]'),
('fa40a920-372d-4ccf-8844-ffa38509fddd','吳宮辭','白居易','唐','唐诗','tang','','[]','淡紅花帔淺檀蛾，睡臉初開似剪波。',32,'全唐诗/poet.tang.23000.json','["淡紅花帔淺檀蛾，睡臉初開似剪波。", "坐對珠籠閑理曲，琵琶鸚鵡語相和。"]'),
('ded78f78-5e74-4716-aaaa-4565c3e1fe20','元微之除浙東觀察使喜得杭越鄰州先贈長句','白居易','唐','唐诗','tang','','[]','稽山鏡水歡遊地，犀帶金章榮貴身。',64,'全唐诗/poet.tang.23000.json','["稽山鏡水歡遊地，犀帶金章榮貴身。", "官職比君雖校小，封疆與我且爲鄰。", "郡樓對翫千峰月，江界平分兩岸春。", "杭越風光詩酒主，相看更合與何人。"]'),
('d6cdd0b5-02c7-450b-a984-6eb12ddf4f2c','席上荅微之','白居易','唐','唐诗','tang','','[]','我住浙江西，君去浙江東。',40,'全唐诗/poet.tang.23000.json','["我住浙江西，君去浙江東。", "勿言一水隔，便與千里同。", "富貴無人勸君酒，今宵爲我盡杯中。"]'),
('c1608380-2072-4aaa-b9ba-6f190b410793','荅微之上船後留別','白居易','唐','唐诗','tang','','[]','燭下尊前一分手，舟中岸上兩迴頭。',32,'全唐诗/poet.tang.23000.json','["燭下尊前一分手，舟中岸上兩迴頭。", "歸來虛白堂中夢，合眼先應到越州。"]'),
('799957d2-965a-4a43-b092-7ecf796c3fa7','荅微之泊西陵驛見寄','白居易','唐','唐诗','tang','','[]','煙波盡處一點白，應是西陵古驛臺。',32,'全唐诗/poet.tang.23000.json','["煙波盡處一點白，應是西陵古驛臺。", "知在臺邊望不見，暮潮空送渡船迴。"]'),
('481e43b9-8bd0-4efe-98d9-db37aa4cd316','荅微之誇越州州宅','白居易','唐','唐诗','tang','','[]','賀上人回得報書，大誇州宅似仙居。',64,'全唐诗/poet.tang.23000.json','["賀上人回得報書，大誇州宅似仙居。", "厭看馮翊風沙久，喜見蘭亭煙景初。", "日出旌旗生氣色，月明樓閣在空虛。", "知君暗數江南郡，除却餘杭盡不如。"]'),
('25ec803a-7907-4ee4-8662-6119c8ea07af','微之重誇州居其落句有西州羅剎之謔因嘲茲石聊以寄懷','白居易','唐','唐诗','tang','','[]','君問西州城下事，醉中疊紙爲君書。',64,'全唐诗/poet.tang.23000.json','["君問西州城下事，醉中疊紙爲君書。", "嵌空石面標羅剎，壓捺潮頭敵子胥。", "神鬼曾鞭猶不動，波濤雖打欲何如。", "誰知太守心相似，抵滯堅頑兩有餘。"]'),
('16a4f4f3-da79-4613-9a35-65f699161663','張十八員外以新詩二十五首見寄郡樓月下吟翫通夕因題卷後封寄微之','白居易','唐','唐诗','tang','','[]','秦城南省清秋夜，江郡東樓明月時。',64,'全唐诗/poet.tang.23000.json','["秦城南省清秋夜，江郡東樓明月時。", "去我三千六百里，得君二十五篇詩。", "陽春曲調高難和，淡水交情老始知。", "坐到天明吟未足，重封轉寄與微之。"]'),
('e2275016-2b58-4e4a-ae21-63753a8c61d8','酬微之','白居易','唐','唐诗','tang','','[]','滿袠填箱唱和詩，少年爲戲老成悲。',64,'全唐诗/poet.tang.23000.json','["滿袠填箱唱和詩，少年爲戲老成悲。", "聲聲麗曲敲寒玉，句句妍辭綴色絲。", "吟翫獨當明月夜，傷嗟同是白頭時。", "由來才命相磨折，天遣無兒欲怨誰。"]'),
('e78a8c65-bd1e-4d45-a44a-4ef3ffe8ebab','餘思未盡加爲六韻重寄微之','白居易','唐','唐诗','tang','','[]','海內聲華併在身，篋中文字絕無倫。',96,'全唐诗/poet.tang.23000.json','["海內聲華併在身，篋中文字絕無倫。", "遙知獨對封章草，忽憶同爲獻納臣。", "走筆往來盈卷軸，除官遞互掌絲綸。", "制從長慶辭高古，詩到元和體變新。", "各有文姬才稚齒，俱無通子繼餘塵。", "琴書何必求王粲，與女猶勝與外人。"]'),
('e4b8f852-ff22-42b6-98ac-0728a7be6674','荅微之詠懷見寄','白居易','唐','唐诗','tang','','[]','閤中同直前春事，船裏相逢昨日情。',64,'全唐诗/poet.tang.23000.json','["閤中同直前春事，船裏相逢昨日情。", "分袂二年勞夢寐，並牀三宿話平生。", "紫微半畔辭宮闕，滄海西頭對郡城。", "聚散窮通何足道，醉來一曲放歌行。"]'),
('96abc157-d0c7-4419-95c9-0545585971b1','酬微之誇鏡湖','白居易','唐','唐诗','tang','','[]','我嗟身老歲方徂，君更官高興轉孤。',64,'全唐诗/poet.tang.23000.json','["我嗟身老歲方徂，君更官高興轉孤。", "軍門郡閤曾閑否，禹穴耶溪得到無。", "酒盞省陪波卷白，骰盤思共彩呼盧。", "一泓鏡水誰能羨，自有胷中萬頃湖。"]'),
('f81f0b9c-c9ac-4348-8d47-c18f03cba683','雪中即事荅微之','白居易','唐','唐诗','tang','','[]','連夜江雲黃慘澹，平明山雪白糢糊。',160,'全唐诗/poet.tang.23000.json','["連夜江雲黃慘澹，平明山雪白糢糊。", "銀河沙漲三千里，梅嶺花排一萬株。", "北市風生飄散麪，東樓日出照凝酥。", "誰家高士關門戶，何處行人失道途？", "舞鶴庭前毛稍定，擣衣碪上練新鋪。", "戲團稚女呵紅手，愁坐衰翁對白鬚。", "壓瘴一州除疾苦，呈豐萬井盡歡娛。", "潤含玉德懷君子，寒助霜威憶大夫。", "莫道煙波一水隔，何妨氣候兩鄉殊。", "越中地暖多成雨，還有瑤臺瓊樹無。"]'),
('347129be-1103-4e6f-a12e-65f682c0f1f2','醉封詩筒寄微之','白居易','唐','唐诗','tang','','[]','一生休戚與窮通，處處相隨事事同。',64,'全唐诗/poet.tang.23000.json','["一生休戚與窮通，處處相隨事事同。", "未死又憐滄海郡，無兒俱作白頭翁。", "展眉只仰三桮後，代面唯憑五字中。", "爲向兩州郵吏道，莫辭來去遞詩筒。"]'),
('e6b50f46-c838-4a76-9bc4-6c6122122943','除夜寄微之','白居易','唐','唐诗','tang','','[]','鬢毛不覺白毿毿，一事無成百不堪。',64,'全唐诗/poet.tang.23000.json','["鬢毛不覺白毿毿，一事無成百不堪。", "共惜盛時辭闕下，同嗟除夜在江南。", "家山泉石尋常憶，世路風波子細諳。", "老校於君合先退，明年半百又加三。"]'),
('02569320-a9bd-4f0d-bc99-d4a457c8032f','蘇州李中丞以元日郡齋感懷詩寄微之及予輙依來篇七言八韻走筆奉荅兼呈微之','白居易','唐','唐诗','tang','','[]','白首餘杭白太守，落魄拋名來已久。',128,'全唐诗/poet.tang.23000.json','["白首餘杭白太守，落魄拋名來已久。", "一辭渭北故園春，再把江南新歲酒。", "桮前笑歌徒勉強，鏡裏形容漸衰朽。", "領郡慙當潦倒年，鄰州喜得平生友。", "長洲草接松江岸，曲水花連鏡湖口。", "老去還能痛飲無，春來曾作閑遊否。", "憑鶯傳語報李六，倩鴈將書與元九。", "莫嗟一日日催人，且貴一年年入手。"]'),
('e9a7af99-eb7c-4977-bb08-833c8f32f7f9','早春西湖閑遊悵然興懷憶與微之同賞因思在越官重事殷鏡湖之遊或恐未暇偶成十八韻寄微之','白居易','唐','唐诗','tang','','["\u897f\u6e56"]','上馬復呼賓，湖邊景氣新。',216,'全唐诗/poet.tang.23000.json','["上馬復呼賓，湖邊景氣新。", "管弦三數事，騎從十餘人。", "立換登山屐，行攜漉酒巾。", "逢花看當妓，遇草坐爲茵。", "西日籠黃柳，東風蕩白蘋。", "小橋裝鴈齒，輕浪甃魚鱗。", "畫舫牽徐轉，銀船酌慢巡。", "野情遺世累，醉態任天真。", "彼此年將老，平生分最親。", "高天從所願，遠地得爲鄰。", "雲樹分三驛，煙波限一津。", "飜嗟寸步隔，却厭尺書頻。", "浙右稱雄鎮，山陰委重臣。", "貴垂長紫綬，榮駕大朱輪。", "出動刀槍隊，歸生道路塵。", "鴈驚弓易散，鷗怕鼓難馴。", "百吏瞻相面，千夫捧擁身。", "自然閑興少，應負鏡湖春。"]'),
('2e446233-0926-413f-a2b1-2d30d0ce9645','荅微之見寄','白居易','唐','唐诗','tang','','[]','可憐風景浙東西，先數餘杭次會稽。',64,'全唐诗/poet.tang.23000.json','["可憐風景浙東西，先數餘杭次會稽。", "禹廟未勝天竺寺，錢湖不羨若耶溪。", "擺塵野鶴春毛暖，拍水沙鷗濕翅低。", "更對雪樓君愛否，紅欄碧甃點銀泥。"]'),
('35927911-8c33-4e84-98eb-73578b5137ad','祭社宵興燈前偶作','白居易','唐','唐诗','tang','','[]','城頭傳鼓角，燈下整衣冠。',48,'全唐诗/poet.tang.23000.json','["城頭傳鼓角，燈下整衣冠。", "夜鏡藏鬚白，秋泉漱齒寒。", "欲將閑送老，須著病辭官。", "更待年終後，支持歸計看。"]'),
('75f0515a-200c-4382-a74a-65c85710eafc','閑臥','白居易','唐','唐诗','tang','','[]','盡日前軒臥，神閑境亦空。',48,'全唐诗/poet.tang.23000.json','["盡日前軒臥，神閑境亦空。", "有山當枕上，無事到心中。", "簾卷侵牀日，屏遮入座風。", "望春春未到，應在海門東。"]'),
('8f82f7a5-4af7-440b-b6ed-bd4ee2cd067a','新春江次','白居易','唐','唐诗','tang','','[]','浦乾潮未應，堤濕凍初銷。',48,'全唐诗/poet.tang.23000.json','["浦乾潮未應，堤濕凍初銷。", "粉片妝梅朵，金絲刷柳條。", "鴨頭新綠水，鴈齒小紅橋。", "莫怪珂聲碎，春來五馬驕。"]'),
('e6da9136-2585-4a83-ba38-a520cedb9163','春題湖上','白居易','唐','唐诗','tang','','["\u897f\u6e56", "\u6625\u5929"]','湖上春來似畫圖，亂峰圍繞水平鋪。',64,'全唐诗/poet.tang.23000.json','["湖上春來似畫圖，亂峰圍繞水平鋪。", "松排山面千重翠，月點波心一顆珠。", "碧毯線頭抽早稻，青羅帬帶展新蒲。", "未能拋得杭州去，一半句留是此湖。"]'),
('be6fa73f-2e42-486d-9c4b-99c4812015e0','早春憶微之','白居易','唐','唐诗','tang','','[]','昏昏老與病相和，感物思君歎復歌。',64,'全唐诗/poet.tang.23000.json','["昏昏老與病相和，感物思君歎復歌。", "聲早雞先知夜短，色濃柳最占春多。", "沙頭雨染斑斑草，水面風驅瑟瑟波。", "可道眼前光景惡，其如難見故人何。"]'),
('bddede5b-9f1b-4a61-8de8-6a9d8ec373aa','失鶴','白居易','唐','唐诗','tang','','[]','失爲庭前雪，飛因海上風。',48,'全唐诗/poet.tang.23000.json','["失爲庭前雪，飛因海上風。", "九霄應得侶，三夜不歸籠。", "聲斷碧雲外，影沈明月中。", "郡齋從此後，誰伴白頭翁。"]'),
('91e82c41-4fff-432b-b563-54322a7b27d9','自感','白居易','唐','唐诗','tang','','[]','宴遊寢食漸無味，桮酒管弦徒繞身。',32,'全唐诗/poet.tang.23000.json','["宴遊寢食漸無味，桮酒管弦徒繞身。", "賓客歡娛僮僕飽，始知官職爲它人。"]'),
('d243874e-e256-445c-8145-de2e5d2135b9','得湖州崔十八使君書喜與杭越鄰郡因成長句代賀兼寄微之','白居易','唐','唐诗','tang','','[]','三郡何因此結緣，貞元科第忝同年。',64,'全唐诗/poet.tang.23000.json','["三郡何因此結緣，貞元科第忝同年。", "故情歡喜開書後，舊事思量在眼前。", "越國封疆吞碧海，杭城樓閤入青煙。", "吳興卑小君應屈，爲是蓬萊最後仙。"]'),
('4957410d-a439-4612-aed7-015a7affae65','同諸客攜酒早看櫻桃花','白居易','唐','唐诗','tang','','[]','曉報櫻桃發，春攜酒客過。',48,'全唐诗/poet.tang.23000.json','["曉報櫻桃發，春攜酒客過。", "綠餳黏盞杓，紅雪壓枝柯。", "天色晴明少，人生事故多。", "停桮替花語，不醉擬如何。"]'),
('1627ee8c-6b17-4576-ae73-d0d10770432c','柳絮','白居易','唐','唐诗','tang','','[]','三月盡是頭白日，與春老別更依依。',32,'全唐诗/poet.tang.23000.json','["三月盡是頭白日，與春老別更依依。", "憑鶯爲向楊花道，絆惹春風莫放歸。"]'),
('5c10ee5f-3de1-42fe-a99e-95e27ce37aea','早飲湖州酒寄崔使君','白居易','唐','唐诗','tang','','[]','一榼扶頭酒，泓澄瀉玉壺。',72,'全唐诗/poet.tang.23000.json','["一榼扶頭酒，泓澄瀉玉壺。", "十分蘸甲酌，瀲豔滿銀盂。", "捧出光華動，嘗看氣味殊。", "手中稀琥珀，舌上冷醍醐。", "瓶裏有時盡，江邊無處沽。", "不知崔太守，更有寄來無。"]'),
('a55f0a43-a183-4b57-801e-dc01e5c4f375','病中書事','白居易','唐','唐诗','tang','','[]','三載臥山城，閑知節物情。',48,'全唐诗/poet.tang.23000.json','["三載臥山城，閑知節物情。", "鶯多過春語，蟬不待秋鳴。", "氣嗽因寒發，風痰欲雨生。", "病身無所用，唯解卜陰晴。"]'),
('2465bac8-dd49-43c2-800b-a615582a604c','與微之唱和來去常以竹筒貯詩陳協律美而成篇因以此荅','白居易','唐','唐诗','tang','','[]','揀得琅玕截作筒，緘題章句寫心胷。',64,'全唐诗/poet.tang.23000.json','["揀得琅玕截作筒，緘題章句寫心胷。", "隨風每喜飛如鳥，渡水常憂化作龍。", "粉節堅如太守信，霜筠冷稱大夫容。", "煩君讚詠心知愧，魚目驪珠同一封。"]'),
('ce3064d8-4f5f-46d7-a39f-c3343127b0cf','醉戲諸妓','白居易','唐','唐诗','tang','','[]','席上爭飛使君酒，歌中多唱舍人詩。',32,'全唐诗/poet.tang.23000.json','["席上爭飛使君酒，歌中多唱舍人詩。", "不知明日休官後，逐我東山去是誰。"]'),
('a76f1331-0b77-499e-9997-0165a811e32d','北院','白居易','唐','唐诗','tang','','[]','北院人稀到，東窗事最偏。',48,'全唐诗/poet.tang.23000.json','["北院人稀到，東窗事最偏。", "竹煙行竈上，石壁臥房前。", "性拙身多暇，心慵事少緣。", "還如病居士，唯置一牀眠。"]'),
('74da0e59-ff0f-4419-b1cb-42279860642a','酬周協律','白居易','唐','唐诗','tang','','[]','五十錢唐守，應爲送老官。',48,'全唐诗/poet.tang.23000.json','["五十錢唐守，應爲送老官。", "濫蒙辭客愛，猶作近臣看。", "鑿落愁須飲，琵琶悶遣彈。", "白頭雖強醉，不似少年歡。"]'),
('c2fe1cc6-94eb-4db4-8826-11b2fea098e6','題石山人','白居易','唐','唐诗','tang','','[]','騰騰兀兀在人間，貴賤賢愚盡往還。',64,'全唐诗/poet.tang.23000.json','["騰騰兀兀在人間，貴賤賢愚盡往還。", "羶膩筵中唯飲酒，歌鐘會處獨思山。", "存神不許三尸住，混俗無妨兩鬢斑。", "除却餘杭白太守，何人更解愛君閑。"]'),
('fb853f9a-92bd-42db-ba59-497e6a1a732e','詩解','白居易','唐','唐诗','tang','','[]','新篇日日成，不是愛聲名。',48,'全唐诗/poet.tang.23000.json','["新篇日日成，不是愛聲名。", "舊句時時改，無妨悅性情。", "但令長守郡，不覺却歸城。", "祗擬江湖上，吟哦過一生。"]'),
('3258fcfa-0850-446d-9d5d-a60c14e8b07c','潮','白居易','唐','唐诗','tang','','[]','早潮纔落晚潮來，一月周流六十回。',32,'全唐诗/poet.tang.23000.json','["早潮纔落晚潮來，一月周流六十回。", "不獨光陰朝復暮，杭州老去被潮催。"]'),
('a2aa3d4b-0bd6-40af-aece-c68cb66727dd','聞歌妓唱嚴郎中詩因以絕句寄之','白居易','唐','唐诗','tang','','[]','已留舊政布中和，又付新詞與豔歌。',32,'全唐诗/poet.tang.23000.json','["已留舊政布中和，又付新詞與豔歌。", "但是人家有遺愛，就中蘇小感恩多。"]'),
('621513da-b3f9-49a1-954b-355df194c264','柘枝妓','白居易','唐','唐诗','tang','','[]','平鋪一合錦筵開，連擊三聲畫鼓催。',64,'全唐诗/poet.tang.23000.json','["平鋪一合錦筵開，連擊三聲畫鼓催。", "紅蠟燭移桃葉起，紫羅衫動柘枝來。", "帶垂鈿胯花腰重，帽轉金鈴雪面迴。", "看即曲終留不住，雲飄雨送向陽臺。"]'),
('4756ef8a-5043-49c2-a8b4-becca1a3e599','急樂世辭','白居易','唐','唐诗','tang','','[]','正抽碧線繡紅羅，忽聽黃鶯歛翠蛾。',32,'全唐诗/poet.tang.23000.json','["正抽碧線繡紅羅，忽聽黃鶯歛翠蛾。", "秋思冬愁春悵望，大都不稱意時多。"]'),
('6a265bec-fb27-4a46-9477-a71bbf45b86f','天竺寺送堅上人歸廬山','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','錫杖登高寺，香爐憶舊峰。',48,'全唐诗/poet.tang.23000.json','["錫杖登高寺，香爐憶舊峰。", "偶來舟不繫，忽去鳥無蹤。", "豈要留離偈，寧勞動別容。", "與師俱是夢，夢裏暫相逢。"]'),
('0d84451b-011a-4985-ae1b-a133b973e046','除官赴闕留贈微之','白居易','唐','唐诗','tang','','[]','去年十月半，君來過浙東。',56,'全唐诗/poet.tang.23000.json','["去年十月半，君來過浙東。", "今年五月盡，我發向關中。", "兩鄉默默心相別，一水盈盈路不通。", "從此津人應省事，寂寥無復遞詩筒。"]'),
('090480e5-8b30-407b-aa2f-706e1fafff3b','留題郡齋','白居易','唐','唐诗','tang','','[]','吟山歌水嘲風月，便是三年官滿時。',48,'全唐诗/poet.tang.23000.json','["吟山歌水嘲風月，便是三年官滿時。", "春爲醉眠多閉閤，秋因晴望暫褰帷。", "更無一事移風俗，唯化州民解詠詩。"]'),
('cfe01469-19c6-4af0-a534-bbf4abda108c','別州民','白居易','唐','唐诗','tang','','["\u9001\u522b", "\u519c\u6c11"]','耆老遮歸路，壺漿滿別筵。',48,'全唐诗/poet.tang.23000.json','["耆老遮歸路，壺漿滿別筵。", "甘棠無一樹，那得淚潸然。", "稅重多貧戶，農饑足旱田。", "唯留一湖水，與汝救凶年。"]'),
('205f6034-6c03-49c7-ac26-e58aec9dfd08','留題天竺靈隱兩寺','白居易','唐','唐诗','tang','','[]','在郡六百日，入山十二回。',96,'全唐诗/poet.tang.23000.json','["在郡六百日，入山十二回。", "宿因月桂落，醉爲海榴開。", "黃紙除書到，青宮詔命催。", "僧徒多悵望，賓從亦裴回。", "寺闇煙埋竹，林香雨落梅。", "別橋憐白石，辭洞戀青苔。", "漸出松間路，猶飛馬上桮。", "誰教冷泉水，送我下山來。"]'),
('b2c9ad7d-19b9-4f75-8adf-ea9fcc4e1a84','西湖留別','白居易','唐','唐诗','tang','','["\u897f\u6e56"]','征途行色慘風煙，祖帳離聲咽管弦。',64,'全唐诗/poet.tang.23000.json','["征途行色慘風煙，祖帳離聲咽管弦。", "翠黛不須留五馬，皇恩只許住三年。", "綠藤陰下鋪歌席，紅藕花中泊妓船。", "處處回頭盡堪戀，就中難別是湖邊。"]'),
('dbb14279-9f5d-4557-8b43-357edb387344','重寄別微之','白居易','唐','唐诗','tang','','[]','憑仗江波寄一辭，不須惆悵報微之。',32,'全唐诗/poet.tang.23000.json','["憑仗江波寄一辭，不須惆悵報微之。", "猶勝往歲峽中別，灩澦堆邊招手時。"]'),
('995ccffe-1cc1-4102-9b0b-b5ea9ce70c1d','重題別東樓','白居易','唐','唐诗','tang','','[]','東樓勝事我偏知，氣象多隨昏旦移。',96,'全唐诗/poet.tang.23000.json','["東樓勝事我偏知，氣象多隨昏旦移。", "湖卷衣裳白重疊，山張屏障綠參差。", "海仙樓塔晴方出，江女笙簫夜始吹。", "春雨星攢尋蟹火，秋風霞颭弄濤旗。", "宴宜雲髻新梳後，曲愛霓裳未拍時。", "太守三年嘲不盡，郡齋空作百篇詩。"]'),
('0b33157e-8c3f-496e-a92c-3f8f6b036b6e','別周軍事','白居易','唐','唐诗','tang','','[]','主人頭白官仍冷，去後憐君是底人。',32,'全唐诗/poet.tang.23000.json','["主人頭白官仍冷，去後憐君是底人。", "試謁會稽元相去，不妨相見却殷勤。"]'),
('c8e7dc05-7a7a-4ef3-863d-3eaad085e694','看常州柘枝贈賈使君','白居易','唐','唐诗','tang','','[]','莫惜新衣舞柘枝，也從塵汚汗霑垂。',32,'全唐诗/poet.tang.23000.json','["莫惜新衣舞柘枝，也從塵汚汗霑垂。", "料君即却歸朝去，不見銀泥衫故時。"]'),
('4643f300-a544-4e9b-9203-85b9c8879912','汴河路有感','白居易','唐','唐诗','tang','','[]','三十年前路，孤舟重往還。',48,'全唐诗/poet.tang.23000.json','["三十年前路，孤舟重往還。", "繞身新眷屬，舉目舊鄉關。", "事去唯留水，人非但見山。", "啼襟與愁鬢，此日兩成斑。"]'),
('7bd95389-eff5-4e95-acc2-9fee3541a4af','埇橋舊業','白居易','唐','唐诗','tang','','[]','別業埇城北，拋來二十春。',48,'全唐诗/poet.tang.23000.json','["別業埇城北，拋來二十春。", "改移新徑路，變換舊村鄰。", "有稅田疇薄，無官弟姪貧。", "田園何用問，強半屬他人。"]'),
('634aa53c-6b31-40ad-81f3-eff422706793','茅城驛','白居易','唐','唐诗','tang','','[]','汴河無景思，秋日又淒淒。',48,'全唐诗/poet.tang.23000.json','["汴河無景思，秋日又淒淒。", "地薄桑麻瘦，村貧屋舍低。", "早苗多間草，濁水半和泥。", "最是蕭條處，茅城驛向西。"]'),
('7db9e6b9-a40a-40d0-a848-77aed248d8bd','河陰夜泊憶微之','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','憶君我正泊行舟，望我君應上郡樓。',32,'全唐诗/poet.tang.23000.json','["憶君我正泊行舟，望我君應上郡樓。", "萬里月明同此夜，黃河東面海西頭。"]'),
('f00ecdd7-7a93-4152-9947-90e068c37196','杭州迴舫','白居易','唐','唐诗','tang','','["\u897f\u6e56"]','自別錢塘山水後，不多飲酒嬾吟詩。',32,'全唐诗/poet.tang.23000.json','["自別錢塘山水後，不多飲酒嬾吟詩。", "欲將此意憑迴櫂，報與西湖風月知。"]'),
('b2953363-76ca-4760-b0e5-1ca0d11d400c','途中題山泉','白居易','唐','唐诗','tang','','[]','決決涌巖穴，濺濺出洞門。',48,'全唐诗/poet.tang.23000.json','["決決涌巖穴，濺濺出洞門。", "向東應入海，從此不歸源。", "似葉飄辭樹，如雲斷別根。", "吾身亦如此，何日返鄉園。"]'),
('7f6910e7-ae66-4cb9-90dc-3c895d3134b1','欲到東洛得楊使君書因以此報','白居易','唐','唐诗','tang','','[]','向公心切向財疎，淮上休官洛下居。',64,'全唐诗/poet.tang.23000.json','["向公心切向財疎，淮上休官洛下居。", "三郡政能從獨步，十年生計復何如。", "使君灘上久分手，別駕渡頭先得書。", "且喜平安又相見，其餘外事盡空虛。"]'),
('cfca731e-38b8-4b0f-bcef-63e52e0b2050','洛下寓居','白居易','唐','唐诗','tang','','[]','秋館清涼日，書因解悶看。',72,'全唐诗/poet.tang.23000.json','["秋館清涼日，書因解悶看。", "夜窗幽獨處，琴不爲人彈。", "遊宴慵多廢，趨朝老漸難。", "禪僧教斷酒，道士勸休官。", "渭曲莊猶在，錢唐俸尚殘。", "如能便歸去，亦不至飢寒。"]'),
('a2d24d41-5212-4383-b74d-bcf88c4c713a','味道','白居易','唐','唐诗','tang','','[]','叩齒晨興秋院靜，焚香冥坐晚窗深。',64,'全唐诗/poet.tang.23000.json','["叩齒晨興秋院靜，焚香冥坐晚窗深。", "七篇真誥論仙事，一卷檀經說佛心。", "此日盡知前境妄，多生曾被外塵侵。", "自嫌習性猶殘處，愛詠閑詩好聽琴。"]'),
('24624201-ea6d-4e7f-95c9-d6d4cc12371c','好聽琴','白居易','唐','唐诗','tang','','[]','本性好絲桐，塵機聞即空。',48,'全唐诗/poet.tang.23000.json','["本性好絲桐，塵機聞即空。", "一聲來耳裏，萬事離心中。", "清暢堪銷疾，恬和好養蒙。", "尤宜聽三樂，安慰白頭翁。"]'),
('73fafa61-fe56-4a8a-af06-c6b177b13d5e','愛詠詩','白居易','唐','唐诗','tang','','[]','辭章諷詠成千首，心行歸依向一乘。',32,'全唐诗/poet.tang.23000.json','["辭章諷詠成千首，心行歸依向一乘。", "坐倚繩牀閑自念，前生應是一詩僧。"]'),
('6cc9cc6b-be21-4039-a780-1eb61b58c2f5','酬皇甫庶子見寄','白居易','唐','唐诗','tang','','[]','掌綸不稱吾應笑，典郡無能我自知。',64,'全唐诗/poet.tang.23000.json','["掌綸不稱吾應笑，典郡無能我自知。", "別詔忽驚新命出，同寮偶與夙心期。", "春坊瀟灑優閑地，秋鬢蒼浪老大時。", "獨占二疏應未可，龍樓見擬覓分司。"]'),
('9355295c-7e8e-4687-85a1-b5c79705795d','臥疾','白居易','唐','唐诗','tang','','[]','閑官臥疾絕經過，居處蕭條近洛河。',32,'全唐诗/poet.tang.23000.json','["閑官臥疾絕經過，居處蕭條近洛河。", "水北水南秋月夜，管弦聲少杵聲多。"]'),
('f1514e7b-5d80-45c6-9aff-1d75883a26cd','遠師','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u8001\u5e08"]','東宮白庶子，南寺遠禪師。',24,'全唐诗/poet.tang.23000.json','["東宮白庶子，南寺遠禪師。", "何處遙相見，心無一事時。"]'),
('6c4e9f20-4fa4-4bce-83c0-ecd9633ee960','問遠師','白居易','唐','唐诗','tang','','[]','葷羶停夜食，吟詠散秋懷。',24,'全唐诗/poet.tang.23000.json','["葷羶停夜食，吟詠散秋懷。", "笑問東林老，詩應不破齋。"]'),
('98d668f1-fdc9-48e3-b99c-137ef8cc7ca8','小院酒醒','白居易','唐','唐诗','tang','','[]','酒醒閑獨步，小院夜深涼。',48,'全唐诗/poet.tang.23000.json','["酒醒閑獨步，小院夜深涼。", "一領新秋簟，三間明月廊。", "未收殘盞杓，初換熱衣裳。", "好是幽眠處，松陰六尺牀。"]'),
('f9e92bc3-4612-43d9-9d2e-dacf56b53d70','贈侯三郎中','白居易','唐','唐诗','tang','','[]','老愛東都好寄身，足泉多竹少埃塵。',64,'全唐诗/poet.tang.23000.json','["老愛東都好寄身，足泉多竹少埃塵。", "年豐最喜唯貧客，秋冷先知是瘦人。", "幸有琴書堪作伴，苦無田宅可爲鄰。", "洛中縱未長居得，且與蘇田遊過春。"]'),
('8566041d-25f1-414a-a121-36780925d4f2','求分司東都寄牛相公十韻','白居易','唐','唐诗','tang','','[]','忽忽心如夢，星星鬢似絲。',120,'全唐诗/poet.tang.23000.json','["忽忽心如夢，星星鬢似絲。", "縱貧長有酒，雖老未拋詩。", "儉薄身都慣，疎頑性頗宜。", "飯麤飱亦飽，被暖起常遲。", "萬里歸何得，三年伴是誰。", "華亭鶴不去，天竺石相隨。", "王尹貰將馬，田家賣與池。", "開門閑坐日，遶水獨行時。", "嬾慢交遊許，衰羸相府知。", "官寮幸無事，可惜不分司。"]'),
('9e976fb0-6ec8-409a-9587-f0258638d0b0','酬楊八','白居易','唐','唐诗','tang','','[]','君以曠懷宜靜境，我因蹇步稱閑官。',32,'全唐诗/poet.tang.23000.json','["君以曠懷宜靜境，我因蹇步稱閑官。", "閉門足病非高士，勞作雲心鶴眼看。"]'),
('b1233dea-586e-4945-9984-0a2f875aa64c','履道新居二十韻','白居易','唐','唐诗','tang','','[]','履道坊西角，官河曲北頭。',240,'全唐诗/poet.tang.23000.json','["履道坊西角，官河曲北頭。", "林園四鄰好，風景一家秋。", "門閉深沈樹，池通淺沮溝。", "拔青松直上，鋪碧水平流。", "籬菊黃金合，窗筠綠玉稠。", "疑連紫陽洞，似到白蘋洲。", "僧至多同宿，賓來輙少留。", "豈無詩引興，兼有酒銷憂。", "移榻臨平岸，攜茶上小舟。", "果穿聞鳥啄，萍破見魚遊。", "地與塵相遠，人將境共幽。", "汎潭菱點鏡，沈浦月生鉤。", "廚曉煙孤起，庭寒雨半收。", "老飢初愛粥，瘦冷早披裘。", "洛下招新隱，秦中忘舊遊。", "辭章留鳳閤，班籍寄龍樓。", "病愜官曹靜，閑慙俸祿憂。", "琴書中有得，衣食外何求。", "濟世才無取，謀身智不周。", "應須共心語，萬事一時休。"]'),
('3e47a09b-9b68-4f37-8002-0e853d7c6c67','九日思杭州舊遊寄周判官及諸客','白居易','唐','唐诗','tang','','[]','忽憶郡南山頂上，昔時同醉是今辰。',64,'全唐诗/poet.tang.23000.json','["忽憶郡南山頂上，昔時同醉是今辰。", "笙歌委曲聲延耳，金翠動搖光照身。", "風景不隨宮相去，歡娛應逐使君新。", "江山賓客皆如舊，唯是當筵換主人。"]'),
('9e20ace5-f41d-4f2d-9591-85c504fb553f','秋晚','白居易','唐','唐诗','tang','','[]','煙景澹濛濛，池邊微有風。',48,'全唐诗/poet.tang.23000.json','["煙景澹濛濛，池邊微有風。", "覺寒蛬近壁，知瞑鶴歸籠。", "長貌隨年改，衰情與物同。", "夜來霜厚薄，梨葉半低紅。"]'),
('d43748ea-2dd7-42ac-baa4-65546ef5a7ac','分司','白居易','唐','唐诗','tang','','[]','散秩留司殊有味，最宜病拙不才身。',64,'全唐诗/poet.tang.23000.json','["散秩留司殊有味，最宜病拙不才身。", "行香拜表爲公事，碧洛青嵩當主人。", "已出閑遊多到夜，却歸慵臥又經旬。", "錢唐五馬留三匹，還擬騎遊攪擾春。"]'),
('016db7b6-f1f3-46c4-a60b-cc84b1ea8332','河南王尹初到以詩代書先問之','白居易','唐','唐诗','tang','','[]','別來王閣老，三歲似須臾。',48,'全唐诗/poet.tang.23000.json','["別來王閣老，三歲似須臾。", "鬢上斑多少，桮前興有無。", "官從分緊慢，情莫問榮枯。", "許入朱門否，籃輿一病夫。"]'),
('9176ba4e-b14b-44af-a878-38bfdda4aeab','池西亭','白居易','唐','唐诗','tang','','[]','朱欄映晚樹，金魄落秋池。',24,'全唐诗/poet.tang.23000.json','["朱欄映晚樹，金魄落秋池。", "還似錢唐夜，西樓月出時。"]'),
('578fbe5b-aef5-40b7-96c5-6681d1b639e5','臨池閑臥','白居易','唐','唐诗','tang','','[]','小竹圍庭匝，平池與砌連。',48,'全唐诗/poet.tang.23000.json','["小竹圍庭匝，平池與砌連。", "閑多臨水坐，老愛向陽眠。", "營役拋身外，幽奇送枕前。", "誰家臥牀脚，解繫釣魚船。"]'),
('38286129-e8db-4e54-a107-fdd78c1fbdbb','吾廬','白居易','唐','唐诗','tang','','[]','吾廬不獨貯妻兒，自覺年侵身力衰。',64,'全唐诗/poet.tang.23000.json','["吾廬不獨貯妻兒，自覺年侵身力衰。", "眼下營求容足地，心中準擬挂冠時。", "新昌小院松當戶，履道幽居竹遶池。", "莫道兩都空有宅，林泉風月是家資。"]'),
('e41161ca-0328-4cc3-b4a6-5861050bc736','題新居寄宣州崔相公','白居易','唐','唐诗','tang','','[]','門庭有水巷無塵，好稱閑官作主人。',64,'全唐诗/poet.tang.23000.json','["門庭有水巷無塵，好稱閑官作主人。", "冷似雀羅雖少客，寬於蝸舍足容身。", "疎通竹徑將迎月，掃掠莎臺欲待春。", "濟世料君歸未得，南園北曲謾爲鄰。"]'),
('2247b3d2-8476-4f8a-be6e-d3f8276751d3','憶杭州梅花因敘舊遊寄蕭協律','白居易','唐','唐诗','tang','','[]','三年閑悶在餘杭，曾爲梅花醉幾場。',96,'全唐诗/poet.tang.23000.json','["三年閑悶在餘杭，曾爲梅花醉幾場。", "伍相廟邊繁似雪，孤山園裏麗如妝。", "蹋隨遊騎心長惜，折贈佳人手亦香。", "賞自初開直至落，歡因小飲便成狂。", "薛劉相次埋新壠，沈謝雙飛出故鄉。", "歌伴酒徒零散盡，唯殘頭白老蕭郎。"]'),
('0ebf1cb9-a364-4a45-9980-3c1a662158a3','病中辱張常侍題集賢院詩因以繼和','白居易','唐','唐诗','tang','','[]','天祿閣門開，甘泉侍從回。',48,'全唐诗/poet.tang.23000.json','["天祿閣門開，甘泉侍從回。", "圖書皆帝籍，寮友盡仙才。", "騎省通中掖，龍樓隔上臺。", "猶憐病宮相，詩寄洛陽來。"]'),
('d73a384e-e07c-4d3b-ae1a-3a4b4b6343a9','早春晚歸','白居易','唐','唐诗','tang','','[]','晚歸騎馬過天津，沙白橋紅返照新。',64,'全唐诗/poet.tang.23000.json','["晚歸騎馬過天津，沙白橋紅返照新。", "草色連延多隙地，鼓聲閑緩少忙人。", "還如南國饒溝水，不似西京足路塵。", "金谷風光依舊在，無人管領石家春。"]'),
('92527d47-0f5d-456d-991a-363e9845dea0','贈楊使君','白居易','唐','唐诗','tang','','[]','曾嗟放逐同巴峽，且喜歸還會洛陽。',64,'全唐诗/poet.tang.23000.json','["曾嗟放逐同巴峽，且喜歸還會洛陽。", "時命到來須作用，功名未立莫思量。", "銀銜叱撥欺風雪，金屑琵琶費酒漿。", "更待城東桃李發，共君沈醉兩三場。"]'),
('79d72d45-26fd-44f6-821c-7f5c73c4ca00','贈皇甫庶子','白居易','唐','唐诗','tang','','[]','何因散地共徘徊，人道君才我不才。',64,'全唐诗/poet.tang.23000.json','["何因散地共徘徊，人道君才我不才。", "騎少馬蹄生易蹶，用稀印鏁澀難開。", "妻知年老添衣絮，婢報天寒撥酒醅。", "更媿小胥諮拜表，單衫衝雪夜深來。"]'),
('75a701ee-d905-4fea-be70-fa585a8ab428','池上竹下作','白居易','唐','唐诗','tang','','[]','穿籬遶舍碧逶迤，十畮閑居半是池。',64,'全唐诗/poet.tang.23000.json','["穿籬遶舍碧逶迤，十畮閑居半是池。", "食飽窗間新睡後，脚輕林下獨行時。", "水能性淡爲吾友，竹解心虛即我師。", "何必悠悠人世上，勞心費目覓親知。"]'),
('6d35f833-1d08-4276-8524-11ac4828f19d','閑出覓春戲贈諸郎官','白居易','唐','唐诗','tang','','[]','年來數出覓風光，亦不全閑亦不忙。',64,'全唐诗/poet.tang.23000.json','["年來數出覓風光，亦不全閑亦不忙。", "放鞚體安騎穩馬，隔袍身暖照晴陽。", "迎春日日添詩思，送老時時放酒狂。", "除却髭鬚白一色，其餘未伏少年郎。"]'),
('01c67180-3672-49e4-b55d-f4ba7ef8e9c7','別春爐','白居易','唐','唐诗','tang','','[]','暖閣春初入，溫爐興稍闌。',48,'全唐诗/poet.tang.23000.json','["暖閣春初入，溫爐興稍闌。", "晚風猶冷在，夜火且留看。", "獨宿相依久，多情欲別難。", "誰能共天語，長遣四時寒。"]'),
('5953a152-5427-4815-90ee-a218cb25f3e8','汎小䑳二首 一','白居易','唐','唐诗','tang','','[]','水一塘，䑳一隻。',40,'全唐诗/poet.tang.23000.json','["水一塘，䑳一隻。", "䑳頭漾漾知風起，䑳背蕭蕭聞雨滴。", "醉臥船中欲醒時，忽疑身是江南客。"]'),
('9ee808e4-bc44-4fe1-950a-a37a3717743c','汎小䑳二首 二','白居易','唐','唐诗','tang','','[]','船緩進，水平流。',40,'全唐诗/poet.tang.23000.json','["船緩進，水平流。", "一莖竹篙剔船尾，兩幅青幕覆船頭。", "亞竹亂藤多照岸，如從鳳口向湖州。"]'),
('b9641f8f-5104-4c98-99b4-05ea5cedd5c3','夢行簡','白居易','唐','唐诗','tang','','[]','天氣妍和水色鮮，閑吟獨步小橋邊。',32,'全唐诗/poet.tang.23000.json','["天氣妍和水色鮮，閑吟獨步小橋邊。", "池塘草綠無佳句，虛臥春窗夢阿憐。"]'),
('5e4c5f0e-591e-4f99-9bf4-957369f10590','題新居呈王尹兼簡府中三掾','白居易','唐','唐诗','tang','','[]','弊宅須重葺，貧家乏羨財。',48,'全唐诗/poet.tang.23000.json','["弊宅須重葺，貧家乏羨財。", "橋憑川守造，樹倩府僚栽。", "朱板新猶濕，紅英暖漸開。", "仍期更攜酒，倚檻看花來。"]'),
('00221140-783c-414f-bfa8-0fe25d7ea4d7','雲和','白居易','唐','唐诗','tang','','[]','非琴非瑟亦非箏，撥柱推弦調未成。',32,'全唐诗/poet.tang.23000.json','["非琴非瑟亦非箏，撥柱推弦調未成。", "欲散白頭千萬恨，只消紅袖兩三聲。"]'),
('d3a03b20-7cbc-4482-8acf-1d9c2e26fbdc','春老','白居易','唐','唐诗','tang','','[]','欲隨年少強遊春，自覺風光不屬身。',32,'全唐诗/poet.tang.23000.json','["欲隨年少強遊春，自覺風光不屬身。", "歌舞屏風花障上，幾時曾畫白頭人。"]'),
('071751cb-48a7-4cd7-8442-34f361ce87ee','春雪過皇甫家','白居易','唐','唐诗','tang','','[]','晚來籃轝雪中回，喜遇君家門正開。',32,'全唐诗/poet.tang.23000.json','["晚來籃轝雪中回，喜遇君家門正開。", "唯要主人青眼待，琴詩談笑自將來。"]'),
('1216ebcc-fff9-40b6-b320-d74b06566f03','崔侍御以孩子三日示其所生詩見示因以二絕句和之 一','白居易','唐','唐诗','tang','','[]','洞房門上挂桑弧，香水盆中浴鳳雛。',32,'全唐诗/poet.tang.23000.json','["洞房門上挂桑弧，香水盆中浴鳳雛。", "還似初生三日魄，嫦娥滿月即成珠。"]'),
('e3a88e5f-4bcb-4835-9258-a07e4c39aa99','崔侍御以孩子三日示其所生詩見示因以二絕句和之 二','白居易','唐','唐诗','tang','','[]','愛惜肯將同寶玉，喜歡應勝得王侯。',32,'全唐诗/poet.tang.23000.json','["愛惜肯將同寶玉，喜歡應勝得王侯。", "弄璋詩句多才思，愁殺無兒老鄧攸。"]'),
('f91af54b-0586-42a0-a276-12dbd3acb52c','與皇甫庶子同遊城東','白居易','唐','唐诗','tang','','[]','閑遊何必多徒侶，相勸時時舉一桮。',64,'全唐诗/poet.tang.23000.json','["閑遊何必多徒侶，相勸時時舉一桮。", "博望苑中無職役，建春門外足池臺。", "綠油剪葉蒲新長，紅蠟黏枝杏欲開。", "白馬朱衣兩宮相，可憐天氣出城來。"]'),
('0151f171-df14-42d0-8ff5-25219c2adcd1','洛城東花下作','白居易','唐','唐诗','tang','','[]','記得舊詩章，花多數洛陽及逢枝似雪，已是鬢成霜。',71,'全唐诗/poet.tang.23000.json','["記得舊詩章，花多數洛陽及逢枝似雪，已是鬢成霜。", "向後光陰促，從前事意忙。", "無因重年少，何計駐時芳。", "欲送愁離面，須傾酒入腸。", "白頭無藉在，醉倒亦何妨。"]'),
('9195b7c8-9bb4-4325-aee1-c42ecfd1f4b3','晚春寄微之幷崔湖州','白居易','唐','唐诗','tang','','[]','洛陽陌上少交親，履道城邊欲暮春。',32,'全唐诗/poet.tang.23000.json','["洛陽陌上少交親，履道城邊欲暮春。", "崔在吳興元在越，出門騎馬覓何人。"]'),
('032c5192-8eae-48c1-bce6-b9537e183dd8','城東閑行因題尉遲司業水閣','白居易','唐','唐诗','tang','','[]','閑遶洛陽城，無人知姓名。',48,'全唐诗/poet.tang.23000.json','["閑遶洛陽城，無人知姓名。", "病乘籃轝出，老著茜衫行。", "處處花相引，時時酒一傾。", "借君溪閣上，醉詠兩三聲。"]'),
('d22d297a-bf8f-4b9c-963e-4e08631ac4cb','寄皇甫七','白居易','唐','唐诗','tang','','[]','孟夏愛吾廬，陶潛語不虛。',48,'全唐诗/poet.tang.23000.json','["孟夏愛吾廬，陶潛語不虛。", "花樽飄落酒，風案展開書。", "鄰女偷新果，家僮漉小魚。", "不知皇甫七，池上興何如。"]'),
('43330188-a882-4514-a8f3-7bd9bf00d8af','訪皇甫七','白居易','唐','唐诗','tang','','[]','上馬行數里，逢花傾一桮。',24,'全唐诗/poet.tang.23000.json','["上馬行數里，逢花傾一桮。", "更無停泊處，還是覓君來。"]'),
('b5fc3052-99dd-403c-8be2-2fa025683f7b','除蘇州刺史別洛城東花','白居易','唐','唐诗','tang','','[]','亂雪千花落，新絲兩鬢生。',48,'全唐诗/poet.tang.23000.json','["亂雪千花落，新絲兩鬢生。", "老除吳郡守，春別洛陽城。", "江上今重去，城東更一行。", "別花何用伴，勸酒有殘鶯。"]'),
('5ffa5719-32e9-4966-bf36-3e369ddb7437','奉和汴州令狐令公二十二韻','白居易','唐','唐诗','tang','','[]','客有東征者，夷門一落帆。',264,'全唐诗/poet.tang.23000.json','["客有東征者，夷門一落帆。", "二年方得到，五日未爲淹。", "在浚旌重葺，遊梁館更添。", "心因好善樂，貌爲禮賢謙。", "俗阜知敦勸，民安見察廉。", "仁風扇道路，陰雨膏閭閻。", "文律操將柄，兵機釣得鈐。", "碧幢油葉葉，紅斾火襜襜。", "景象春加麗，威容曉助嚴。", "槍森赤豹尾，纛吒黑龍髯。", "門靜塵初歛，城昏日半銜。", "選幽開後院，占勝坐前簷。", "平展絲頭毯，高褰錦額簾。", "雷搥柘枝鼓，雪擺胡騰衫。", "髮滑歌釵墜，妝光舞汗霑。", "回燈花簇簇，過酒玉纖纖。", "饌盛盤心殢，醅濃盞底黏。", "陸珍熊掌爛，海味蟹螯鹹。", "福履千夫祝，形儀四座瞻。", "羊公長在峴，傅說莫歸巖。", "眷愛人人遍，風情事事兼。", "猶嫌客不醉，同賦夜厭厭。"]'),
('284d7cd6-4607-4b81-9dda-746f2cd13c90','船夜援琴','白居易','唐','唐诗','tang','','["\u6292\u60c5"]','鳥棲魚不動，月照夜江深。',48,'全唐诗/poet.tang.23000.json','["鳥棲魚不動，月照夜江深。", "身外都無事，舟中只有琴。", "七弦爲益友，兩耳是知音。", "心靜即聲淡，其間無古今。"]'),
('50646d2c-4782-421f-9a71-cd8d9c0e38b6','荅劉和州禹錫','白居易','唐','唐诗','tang','','[]','換印雖頻命未通，歷陽湖上又秋風。',64,'全唐诗/poet.tang.23000.json','["換印雖頻命未通，歷陽湖上又秋風。", "不教才展休明代，爲罰詩爭造化功。", "我亦思歸田舍下，君應厭臥郡齋中。", "好相收拾爲閑伴，年齒官班約略同。"]'),
('d391dff9-a618-46b2-9e6c-84f942a87305','渡淮','白居易','唐','唐诗','tang','','[]','淮水東南闊，無風渡亦難。',48,'全唐诗/poet.tang.23000.json','["淮水東南闊，無風渡亦難。", "孤煙生乍直，遠樹望多圓。", "春浪櫂聲急，夕陽帆影殘。", "清流宜映月，今夜重吟看。"]'),
('729c0c57-ccff-4d7d-8a32-92188244f8de','赴蘇州至常州荅賈舍人','白居易','唐','唐诗','tang','','[]','杭城隔歲轉蘇臺，還擁前時五馬回。',64,'全唐诗/poet.tang.23000.json','["杭城隔歲轉蘇臺，還擁前時五馬回。", "厭見簿書先眼合，喜逢桮酒暫眉開。", "未酬恩寵年空去，欲立功名命不來。", "一別承明三領郡，甘從人道是粗才。"]'),
('95a119ed-dbc2-4fd8-8be8-344f7bfc99d9','去歲罷杭州今春領吳郡慙無善政聊寫鄙懷兼寄三相公','白居易','唐','唐诗','tang','','[]','爲問三丞相，如何秉國鈞。',96,'全唐诗/poet.tang.23000.json','["爲問三丞相，如何秉國鈞。", "那將最劇郡，付與苦慵人。", "豈有吟詩客，堪爲持節臣。", "不才空飽暖，無惠及飢貧。", "昨臥南城月，今行北境春。", "鉛刀磨欲盡，銀印換何頻。", "杭老遮車轍，吳童掃路塵。", "虛迎復虛送，慙見兩州民。"]'),
('70802095-82bb-44d5-812d-04ce5a10458b','宣武令狐相公以詩寄贈傳播吳中聊奉短草用申酬謝','白居易','唐','唐诗','tang','','[]','新詩傳詠忽紛紛，楚老吳娃耳徧聞。',64,'全唐诗/poet.tang.23000.json','["新詩傳詠忽紛紛，楚老吳娃耳徧聞。", "盡解呼爲好才子，不知官是上將軍。", "辭人命薄多無位，戰將功高少有文。", "謝朓篇章韓信鉞，一生雙得不如君。"]'),
('74054002-6168-408d-a90d-5ab76cd5e7eb','自詠','白居易','唐','唐诗','tang','','[]','形容瘦薄詩情苦，豈是人間有相人。',64,'全唐诗/poet.tang.23000.json','["形容瘦薄詩情苦，豈是人間有相人。", "只合一生眠白屋，何因三度擁朱輪。", "金章未佩雖非貴，銀榼常攜亦不貧。", "唯是無兒頭早白，被天磨折恰平均。"]'),
('d38579de-9748-4f5f-8459-9bc506ac35c1','吟前篇因寄微之','白居易','唐','唐诗','tang','','[]','君顏貴茂不清羸，君句雄華不苦悲。',32,'全唐诗/poet.tang.23000.json','["君顏貴茂不清羸，君句雄華不苦悲。", "何事遣君還似我，髭鬚早白亦無兒。"]'),
('52c81f8a-f36d-4d1d-bbf1-837cb43f8865','紫薇花','白居易','唐','唐诗','tang','','[]','紫薇花對紫微翁，名目雖同貌不同。',64,'全唐诗/poet.tang.23000.json','["紫薇花對紫微翁，名目雖同貌不同。", "獨占芳菲當夏景，不將顏色託春風。", "潯陽官舍雙高樹，興善僧庭一大叢。", "何似蘇州安置處，花堂欄下月明中。"]'),
('4d3e2fbc-94aa-44b7-9d01-84506da845ce','自到郡齋僅經旬日方專公務未及宴遊偷閑走筆題二十四韻兼寄常州賈舍人湖州崔郎中仍呈吳中諸客','白居易','唐','唐诗','tang','','[]','渭北離鄉客，江南守土臣。',290,'全唐诗/poet.tang.23000.json','["渭北離鄉客，江南守土臣。", "涉途初改月，入境已經旬。", "甲郡標天下，環封極海濱。", "版圖十萬戶，兵籍五千人。", "自顧才能少，何堪寵命頻。", "冒榮慙印綬，虛獎負絲綸。", "候病須通脈，防流要塞津。", "救煩無若靜，補拙莫如勤。", "削使科條簡，攤令賦役均。", "以茲爲報効，安敢不躬親。", "襦袴提於手，韋弦佩在紳。", "敢辭稱俗吏，且願活疲民。", "常未徵黃霸，湖猶借寇恂。", "媿無鐺脚政，徒忝犬牙鄰。", "制誥誇黃絹，詩篇占白蘋。", "銅符拋不得，瓊樹見無因。", "警寐鐘傳夜，催衙鼓報晨。", "唯知對胥吏，未暇接親賓。", "色變雲迎夏，聲殘鳥過春。", "麥風非逐扇，梅[雨]異隨輪。", "武寺山如故，王樓月自新。", "池塘閑長草，絲竹廢生塵。", "暑遣燒神酎，晴教曬舞茵。", "待還公事了，亦擬樂吾身。"]'),
('ffdf7da6-4507-4659-a2ed-8a00917b4bd3','題籠鶴','白居易','唐','唐诗','tang','','[]','經旬不飲酒，踰月未聞歌。',48,'全唐诗/poet.tang.23000.json','["經旬不飲酒，踰月未聞歌。", "豈是風情少，其如塵事多。", "虎丘慙客問，娃館妬人過。", "莫笑籠中鶴，相看去幾何。"]'),
('b27958b7-f862-4304-ac02-3b5eaabe6833','荅客問杭州','白居易','唐','唐诗','tang','','[]','爲我踟躕停酒盞，與君約略說杭州。',64,'全唐诗/poet.tang.23000.json','["爲我踟躕停酒盞，與君約略說杭州。", "山名天竺堆青黛，湖號錢唐瀉綠油。", "大屋簷多裝鴈齒，小航船亦畫龍頭。", "所嗟水路無三百，官繫何因得再遊。"]'),
('11775c2d-6759-4bc4-bb18-2aafe019206a','登閶門閑望','白居易','唐','唐诗','tang','','[]','閶門四望鬱蒼蒼，始覺州雄土俗強。',96,'全唐诗/poet.tang.23000.json','["閶門四望鬱蒼蒼，始覺州雄土俗強。", "十萬夫家供課稅，五千子弟守封疆。", "闔閭城碧鋪秋草，烏鵲橋紅帶夕陽。", "處處樓前飄管吹，家家門外泊舟航。", "雲埋虎寺山藏色，月耀娃宮水放光。", "曾賞錢唐嫌茂苑，今來未敢苦誇張。"]'),
('10a311dc-e167-4017-b8bb-0b3599f60a59','代諸妓贈送周判官','白居易','唐','唐诗','tang','','[]','妓筵今夜別姑蘇，客櫂明朝向鏡湖。',64,'全唐诗/poet.tang.23000.json','["妓筵今夜別姑蘇，客櫂明朝向鏡湖。", "莫汎扁舟尋范蠡，且隨五馬覓羅敷。", "蘭亭月破能迴否，娃館秋涼却到無。", "好與使君爲老伴，歸來休染白髭鬚。"]'),
('e1d02b56-b877-4295-a10c-6fc0cb49e2f1','秋寄微之十二韻','白居易','唐','唐诗','tang','','[]','娃館松江北，稽城浙水東。',144,'全唐诗/poet.tang.23000.json','["娃館松江北，稽城浙水東。", "屈君爲長吏，伴我作衰翁。", "旌斾知非遠，煙雲望不通。", "忙多對酒榼，興少閱詩筒。", "淡白秋來日，疎涼雨後風。", "餘霞數片綺，新月一張弓。", "影滿衰桐樹，香凋晚蕙叢。", "飢啼春穀鳥，寒怨絡絲蟲。", "覽鏡頭雖白，聽歌耳未聾。", "老愁從此遣，醉笑與誰同。", "清旦方堆案，黃昏始退公。", "可憐朝暮景，銷在兩衙中。"]'),
('67f9c69a-6585-4948-b9a9-310503ce835e','池上早秋','白居易','唐','唐诗','tang','','[]','荷芰綠參差，新秋水滿池。',48,'全唐诗/poet.tang.23000.json','["荷芰綠參差，新秋水滿池。", "早涼生北檻，殘照下東籬。", "露飽蟬聲嬾，風乾柳意衰。", "過潘二十歲，何必更愁悲。"]'),
('8c00ab70-1d79-4249-a760-15a7c97e7485','郡西亭偶詠','白居易','唐','唐诗','tang','','[]','常愛西亭面北林，公私塵事不能侵。',64,'全唐诗/poet.tang.23000.json','["常愛西亭面北林，公私塵事不能侵。", "共閑作伴無如鶴，與老相宜只有琴。", "莫遣是非分作界，須教吏隱合爲心。", "可憐此道人皆見，但要修行功用深。"]'),
('3248d69e-f5d2-4caf-ab2b-ee353ce68191','故衫','白居易','唐','唐诗','tang','','[]','闇淡緋衫稱老身，半披半曳出朱門。',64,'全唐诗/poet.tang.23000.json','["闇淡緋衫稱老身，半披半曳出朱門。", "袖中吳郡新詩本，襟上杭州舊酒痕。", "殘色過梅看向盡，故香因洗嗅猶存。", "曾經爛熳三年著，欲棄空箱似少恩。"]'),
('aed06eda-8098-4e73-9a80-0e6efd931429','郡中夜聽李山人彈三樂','白居易','唐','唐诗','tang','','[]','風琴秋拂匣，月戶夜開關。',48,'全唐诗/poet.tang.23000.json','["風琴秋拂匣，月戶夜開關。", "榮啓先生樂，姑蘇太守閑。", "傳聲千古後，得意一時間。", "却怪鍾期耳，唯聽水與山。"]'),
('090fe452-57a4-42dc-beb0-81174c375d84','東城桂三首 一','白居易','唐','唐诗','tang','','[]','子墮本從天竺寺，根盤今在闔閭城。',32,'全唐诗/poet.tang.23000.json','["子墮本從天竺寺，根盤今在闔閭城。", "當時應逐南風落，落向人間取次生。"]'),
('5cc52761-d00f-4944-b66b-c3c8cee78d43','東城桂三首 二','白居易','唐','唐诗','tang','','[]','霜雪壓多雖不死，荆榛長疾欲相埋。',32,'全唐诗/poet.tang.23000.json','["霜雪壓多雖不死，荆榛長疾欲相埋。", "長憂落在樵人手，賣作蘇州一束柴。"]'),
('df1a7e39-a2a2-4990-9945-03e188054f51','東城桂三首 三','白居易','唐','唐诗','tang','','[]','遙知天上桂花孤，試問嫦娥更要無。',16,'全唐诗/poet.tang.23000.json','["遙知天上桂花孤，試問嫦娥更要無。"]'),
('7cea7180-20db-4b66-a509-95e6b77c01ac','聞行簡恩賜章服喜成長句寄之','白居易','唐','唐诗','tang','','[]','吾年五十加朝散，爾亦今年賜服章。',64,'全唐诗/poet.tang.23000.json','["吾年五十加朝散，爾亦今年賜服章。", "齒髮恰同知命歲，官銜俱是客曹郎。", "榮傳錦帳花聯萼，彩動綾袍鴈趂行。", "大抵著緋宜老大，莫嫌秋鬢數莖霜。"]'),
('8952d8d5-41ea-4907-9c7e-7d52a1df2fc4','喚笙歌','白居易','唐','唐诗','tang','','[]','露墜萎花槿，風吹敗葉荷。',48,'全唐诗/poet.tang.23000.json','["露墜萎花槿，風吹敗葉荷。", "老心歡樂少，秋眼感傷多。", "芳歲今如此，衰翁可奈何。", "猶應不如醉，試遣喚笙歌。"]'),
('20c1c027-c94e-4373-a9f5-29c19eaae096','對酒吟','白居易','唐','唐诗','tang','','[]','一拋學士筆，三佩使君符。',96,'全唐诗/poet.tang.23000.json','["一拋學士筆，三佩使君符。", "未換銀青綬，唯添雪白鬚。", "公門衙退掩，妓席客來鋪。", "履舃從相近，謳吟任所須。", "金銜嘶五馬，鈿帶舞雙姝。", "不得當年有，猶勝到老無。", "合聲歌漢月，齊手拍吳歈。", "今夜還先醉，應煩紅袖扶。"]'),
('a919f43f-d7b1-40b9-8c7d-603c8d7a1abc','偶飲','白居易','唐','唐诗','tang','','[]','三盞醺醺四體融，妓亭簷下夕陽中。',66,'全唐诗/poet.tang.23000.json','["三盞醺醺四體融，妓亭簷下夕陽中。", "千聲方響敲相續，一曲[雲]和戛未終。", "今日心情如往日，秋風氣味似春風。", "唯憎小吏樽前報，道去衙時水五筒。"]'),
('0d4987f0-f02c-47aa-a37f-2ffb738367bf','早發赴洞庭舟中作','白居易','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','閶門曙色欲蒼蒼，星月高低宿水光。',64,'全唐诗/poet.tang.23000.json','["閶門曙色欲蒼蒼，星月高低宿水光。", "櫂舉影搖燈燭動，舟移聲拽管弦長。", "漸看海樹紅生日，遙見包山白帶霜。", "出郭已行十五里，唯消一曲慢霓裳。"]'),
('07ac80e7-24c3-490c-9321-f8957d2d62ff','宿湖中','白居易','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','水天向晚碧沉沉，樹影霞光重疊深。',64,'全唐诗/poet.tang.23000.json','["水天向晚碧沉沉，樹影霞光重疊深。", "浸月冷波千頃練，苞霜新橘萬株金。", "幸無案牘何妨醉，縱有笙歌不廢吟。", "十隻畫船何處宿，洞庭山腳太湖心。"]'),
('b0a52e1c-6a5b-4386-ace5-6bab56e0974f','揀貢橘書情','白居易','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭貢橘揀宜精，太守勤王請自行。',64,'全唐诗/poet.tang.23000.json','["洞庭貢橘揀宜精，太守勤王請自行。", "珠顆形容隨日長，瓊漿氣味得霜成。", "登山敢惜駑駘力，望闕難伸螻蟻情。", "疎賤無由親跪獻，願憑朱實表丹誠。"]'),
('42bdfb3b-d1cf-477e-b3fe-24b4dbc4bb00','夜泛陽塢入明月灣即事寄崔湖州','白居易','唐','唐诗','tang','','[]','湖山處處好淹留，最愛東灣北塢頭。',64,'全唐诗/poet.tang.23000.json','["湖山處處好淹留，最愛東灣北塢頭。", "掩映橘林千點火，泓澄潭水一盆油。", "龍頭畫舸銜明月，鵲脚紅旗蘸碧流。", "爲報茶山崔太守，與君各是一家遊。"]'),
('bcda8158-e93f-4818-8bb9-decef0430517','泛太湖書事寄微之','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','煙渚雲帆處處通，飄然舟似入虛空。',128,'全唐诗/poet.tang.23000.json','["煙渚雲帆處處通，飄然舟似入虛空。", "玉桮淺酌巡初匝，金管徐吹曲未終。", "黃夾纈林寒有葉，碧琉璃水淨無風。", "避旗飛鷺翩翻白，驚鼓跳魚撥剌紅。", "澗雪壓多松偃蹇，巖泉滴久石玲瓏。", "書爲故事留湖上，吟作新詩寄浙東。", "軍府威容從道盛，江山氣色定知同。", "報君一事君應羨，五宿澄波皓月中。"]'),
('88d06421-854b-4335-a708-249bc7795b29','題新館','白居易','唐','唐诗','tang','','[]','曾爲白社羈遊子，今作朱門醉飽身。',64,'全唐诗/poet.tang.23000.json','["曾爲白社羈遊子，今作朱門醉飽身。", "十萬戶州尤覺貴，二千石祿敢言貧。", "重裘每念單衣士，兼味嘗思旅食人。", "新館寒來多少客，欲回歌酒暖風塵。"]'),
('a9270b2e-c8cf-4ae9-8b79-58bf7fac4fbb','西樓喜雪命宴','白居易','唐','唐诗','tang','','[]','宿雲黃慘澹，曉雪白飄颻。',72,'全唐诗/poet.tang.23000.json','["宿雲黃慘澹，曉雪白飄颻。", "散麪遮槐市，堆花壓柳橋。", "四郊鋪縞素，萬室甃瓊瑤。", "銀榼攜桑落，金爐上麗譙。", "光迎舞妓動，寒近醉人銷。", "歌樂雖盈耳，慙無五袴謠。"]'),
('48f5b2c1-37be-4114-9f50-6001f4abd841','新栽梅','白居易','唐','唐诗','tang','','[]','池邊新種七株梅，欲到花時點檢來。',32,'全唐诗/poet.tang.23000.json','["池邊新種七株梅，欲到花時點檢來。", "莫怕長洲桃李妬，今年好爲使君開。"]'),
('ad771777-63dd-41fc-b1c2-da11e8cf64cf','酬劉和州戲贈','白居易','唐','唐诗','tang','','[]','錢唐山水接蘇臺，兩地褰帷媿不才。',64,'全唐诗/poet.tang.23000.json','["錢唐山水接蘇臺，兩地褰帷媿不才。", "政事素無爭學得，風情舊有且將來。", "雙蛾解珮啼相送，五馬鳴珂笑却回。", "不似劉郎無景行，長拋春恨在天台。"]'),
('d627be42-d1d7-4c7e-b46b-dbf5fccd8cb2','戲和賈常州醉中二絕句 一','白居易','唐','唐诗','tang','','[]','聞道毗陵詩酒興，近來積漸學姑蘇。',32,'全唐诗/poet.tang.23000.json','["聞道毗陵詩酒興，近來積漸學姑蘇。", "罨頭新令從偷去，刮骨清吟得似無。"]'),
('5d43b327-3341-43ac-808b-bd45596562c6','戲和賈常州醉中二絕句 二','白居易','唐','唐诗','tang','','[]','越調管吹留客曲，吳吟詩送暖寒杯。',32,'全唐诗/poet.tang.23000.json','["越調管吹留客曲，吳吟詩送暖寒杯。", "娃宮無限風流事，好遣孫心暫學來。"]'),
('4a6cfb43-177f-41eb-bd43-555f89544243','歲暮寄微之三首 一','白居易','唐','唐诗','tang','','[]','微之別久能無歎，知退書稀豈免愁。',64,'全唐诗/poet.tang.23000.json','["微之別久能無歎，知退書稀豈免愁。", "甲子百年過半後，光陰一歲欲終頭。", "池水曉合膠船底，樓雪晴銷露瓦溝。", "自覺歡情隨日減，蘇州心不及杭州。"]'),
('64ac8751-6649-472d-ae40-374d236ed20a','歲暮寄微之三首 二','白居易','唐','唐诗','tang','','[]','榮進雖頻退亦頻，與君才命不調勻。',64,'全唐诗/poet.tang.23000.json','["榮進雖頻退亦頻，與君才命不調勻。", "若不九重中掌事，即須千里外拋身。", "紫垣南北廳曾對，滄海東西郡又鄰。", "唯欠結廬嵩洛下，一時歸去作閑人。"]'),
('220fa681-7e0f-44ed-a333-246ba98d1e48','歲暮寄微之三首 三','白居易','唐','唐诗','tang','','[]','白頭歲暮苦相思，除却悲吟無可爲。',64,'全唐诗/poet.tang.23000.json','["白頭歲暮苦相思，除却悲吟無可爲。", "枕上從妨一夜睡，燈前讀盡十年詩。", "龍鍾校正騎驢日，顦顇通江司馬時。", "若並如今是全活，紆朱拖紫且開眉。"]'),
('9bcf668e-711b-4008-b658-bae89c1920db','歲日家宴戲示弟姪等兼呈張侍御二十八丈殷判官二十三兄','白居易','唐','唐诗','tang','','[]','弟妹妻孥小姪甥，嬌癡弄我助歡情。',64,'全唐诗/poet.tang.23000.json','["弟妹妻孥小姪甥，嬌癡弄我助歡情。", "歲盞後推藍尾酒，春盤先勸膠牙餳。", "形骸潦到雖堪歎，骨肉團圓亦可榮。", "猶有誇張少年處，笑呼張丈喚殷兄。"]'),
('3705c324-e7be-4cb2-83e0-142d2cb0f321','正月三日閑行','白居易','唐','唐诗','tang','','[]','黃鸝巷口鶯欲語，烏鵲河頭冰欲銷。',64,'全唐诗/poet.tang.23000.json','["黃鸝巷口鶯欲語，烏鵲河頭冰欲銷。", "綠浪東西南北水，紅欄三百九十橋。", "鴛鴦蕩漾雙雙翅，楊柳交加萬萬條。", "借問春風來早晚，只從前日到今朝。"]'),
('a6a56c52-ba9c-4b24-a351-2cf288e865fb','夜歸','白居易','唐','唐诗','tang','','[]','逐勝移朝宴，留歡放晚衙。',72,'全唐诗/poet.tang.23000.json','["逐勝移朝宴，留歡放晚衙。", "賓寮多謝客，騎從半吳娃。", "到處銷春景，歸時及月華。", "城陰一道直，燭焰兩行斜。", "東吹先催柳，南霜不殺花。", "臯橋夜沽酒，燈火是誰家。"]'),
('f9b848c2-09cd-47dd-87b1-1514dde93ce7','自歎','白居易','唐','唐诗','tang','','[]','豈獨年相迫，兼爲病所侵。',48,'全唐诗/poet.tang.23000.json','["豈獨年相迫，兼爲病所侵。", "春來痰氣動，老去嗽聲深。", "眼暗猶操筆，頭斑未挂簪。", "因循過日月，真是俗人心。"]'),
('72ee1249-ecce-4760-8ac9-d803c9838535','郡中閑獨寄微之及崔湖州','白居易','唐','唐诗','tang','','[]','少年賓旅非吾輩，晚歲簪纓束我身。',64,'全唐诗/poet.tang.23000.json','["少年賓旅非吾輩，晚歲簪纓束我身。", "酒散更無同宿客，詩成長作獨吟人。", "蘋洲會面知何日，鏡水離心又一春。", "兩處也應相憶在，官高年長少情親。"]'),
('1de53824-9293-43d0-b5d1-95fdf5d0428d','小舫','白居易','唐','唐诗','tang','','[]','小舫一艘新造了，輕裝梁柱庳安篷。',64,'全唐诗/poet.tang.23000.json','["小舫一艘新造了，輕裝梁柱庳安篷。", "深坊靜岸遊應徧，淺水低橋去盡通。", "黃柳影籠隨櫂月，白蘋香起打頭風。", "慢牽欲傍櫻桃泊，借問誰家花最紅。"]'),
('70a3a211-7842-404c-82d8-3f9a8d395a3c','馬墜強出贈同座','白居易','唐','唐诗','tang','','[]','足傷遭馬墜，腰重倩人擡。',48,'全唐诗/poet.tang.23000.json','["足傷遭馬墜，腰重倩人擡。", "秪合窗間臥，何由花下來。", "坐依桃葉枝，行呷地黃桮。", "強出非他意，東風落盡梅。"]'),
('cb67b893-284e-4db0-9179-d1b930a1e316','夜聞賈常州崔湖州茶山境會想羨歡宴因寄此詩','白居易','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u95f2\u9002", "\u5199\u8336"]','遙聞境會茶山夜，珠翠歌鐘俱遶身。',64,'全唐诗/poet.tang.23000.json','["遙聞境會茶山夜，珠翠歌鐘俱遶身。", "盤下中分兩州界，燈前合作一家春。", "青娥遰舞應爭妙，紫笋齊嘗各鬬新。", "自歎花時北窗下，蒲黃酒對病眠人。"]'),
('0730fb32-2440-4438-9fc5-95fa7c02059b','酬微之開拆新樓初畢相報末聯見戲之作','白居易','唐','唐诗','tang','','[]','海山鬱鬱石稜稜，新豁高居正好登。',64,'全唐诗/poet.tang.23000.json','["海山鬱鬱石稜稜，新豁高居正好登。", "南臨贍部三千界，東對蓬宮十二層。", "報我樓成秋望月，把君詩讀夜回燈。", "無妨却有他心眼，妝點亭臺即不能。"]'),
('da4834a4-014e-4281-b6d2-d626d4cae4ea','病中多雨逢寒食','白居易','唐','唐诗','tang','','[]','水國多陰常嬾出，老夫饒病愛閑眠。',64,'全唐诗/poet.tang.23000.json','["水國多陰常嬾出，老夫饒病愛閑眠。", "三旬臥度鶯花月，一半春銷風雨天。", "薄暮何人吹觱篥，新晴幾處縛鞦韆。", "綵繩芳樹長如舊，唯是年年換少年。"]'),
('b4962e15-55b5-4797-8972-2d7aecca7f10','清明夜','白居易','唐','唐诗','tang','','["\u6e05\u660e\u8282", "\u6e05\u660e", "\u8e0f\u9752"]','好風朧月清明夜，碧砌紅軒刺史家。',32,'全唐诗/poet.tang.23000.json','["好風朧月清明夜，碧砌紅軒刺史家。", "獨繞迴廊行復歇，遙聽弦管暗看花。"]'),
('69a2e7f7-84d5-4cbe-9161-888e1fc0fe69','蘇州柳','白居易','唐','唐诗','tang','','[]','金谷園中黃嫋娜，曲江亭畔碧婆娑。',48,'全唐诗/poet.tang.23000.json','["金谷園中黃嫋娜，曲江亭畔碧婆娑。", "老來處處遊行徧，不似蘇州柳最多。", "絮撲白頭條拂面，使君無計奈春何。"]'),
('2c4a9ce7-50bc-4a25-9d38-645f4bc456c2','三月二十八日贈周判官','白居易','唐','唐诗','tang','','[]','一春惆悵殘三日，醉問周郎憶得無。',32,'全唐诗/poet.tang.23000.json','["一春惆悵殘三日，醉問周郎憶得無。", "柳絮送人鶯勸酒，去年今日別東都。"]'),
('cb5b068a-4016-4069-88a0-5eb16380e156','偶作','白居易','唐','唐诗','tang','','[]','紅杏初生葉，青梅已綴枝。',48,'全唐诗/poet.tang.23000.json','["紅杏初生葉，青梅已綴枝。", "闌珊花落後，寂寞酒醒時。", "坐悶低眉久，行慵舉足遲。", "少年君莫怪，頭白自應知。"]'),
('8c9486c8-14af-4be8-b73e-20e06fcaa100','重荅劉和州','白居易','唐','唐诗','tang','','[]','分無佳麗敵西施，敢有文章替左司。',64,'全唐诗/poet.tang.23000.json','["分無佳麗敵西施，敢有文章替左司。", "隨分笙歌聊自樂，等閑篇詠被人知。", "花邊妓引尋香徑，月下僧留宿劒池。", "可惜當時好風景，吳王應不解吟詩。"]'),
('d846c0ad-cf6e-4605-970f-19737f3f02c5','奉送三兄','白居易','唐','唐诗','tang','','[]','少年曾管二千兵，晝聽笙歌夜斫營。',64,'全唐诗/poet.tang.23000.json','["少年曾管二千兵，晝聽笙歌夜斫營。", "自反丘園頭盡白，每逢旗鼓眼猶明。", "杭州暮醉連牀臥，吳郡春遊並馬行。", "自媿阿連官職慢，只教兄作使君兄。"]'),
('735ba85e-5a21-4fe1-837d-dc9c4c197d98','城上夜宴','白居易','唐','唐诗','tang','','[]','留春不住登城望，惜夜相將秉燭遊。',64,'全唐诗/poet.tang.23000.json','["留春不住登城望，惜夜相將秉燭遊。", "風月萬家河兩岸，笙歌一曲郡西樓。", "詩聽越客吟何苦，酒被吳娃勸不休。", "從道人生都是夢，夢中歡笑亦勝愁。"]'),
('0b45d8a0-3773-4495-afa8-ff48934fea92','重題小舫贈周從事兼戲微之','白居易','唐','唐诗','tang','','[]','細[篷]青篾織魚鱗，小眼紅窗襯麴塵。',66,'全唐诗/poet.tang.23000.json','["細[篷]青篾織魚鱗，小眼紅窗襯麴塵。", "闊狹纔容從事座，高低恰稱使君身。", "舞筵須揀腰輕女，仙櫂難勝骨重人。", "不似鏡湖廉使出，高檣大艑鬧驚春。"]'),
('e9972acf-14e7-4ce0-9c3d-9a70144ea2f8','吳櫻桃','白居易','唐','唐诗','tang','','[]','含桃最說出東吳，香色鮮穠氣味殊。',64,'全唐诗/poet.tang.23000.json','["含桃最說出東吳，香色鮮穠氣味殊。", "洽恰舉頭千萬顆，婆娑拂面兩三株。", "鳥偷飛處銜將火，人摘爭時蹋破珠。", "可惜風吹兼雨打，明朝後日即應無。"]'),
('5afc84e2-35d2-4add-bdaa-1f425408de87','春盡勸客酒','白居易','唐','唐诗','tang','','[]','林下春將盡，池邊日半斜。',48,'全唐诗/poet.tang.23000.json','["林下春將盡，池邊日半斜。", "櫻桃落砌顆，夜合隔簾花。", "嘗酒留閑客，行茶使小娃。", "殘杯勸不飲，留醉向誰家。"]'),
('397c4d28-1cff-48ce-b9ce-5fefcca6e077','仲夏齋居偶題八韻寄微之及崔湖州','白居易','唐','唐诗','tang','','[]','腥血與葷蔬，停來一月餘。',96,'全唐诗/poet.tang.23000.json','["腥血與葷蔬，停來一月餘。", "肌膚雖瘦損，方寸任清虛。", "體適通宵坐，頭慵隔日梳。", "眼前無俗物，身外即僧居。", "水榭風來遠，松廊雨過初。", "褰簾放巢燕，投食施池魚。", "久別閑遊伴，頻勞問疾書。", "不知湖與越，吏隱興何如。"]'),
('a2ea81d7-5a35-47c8-af31-910085d8db11','官宅','白居易','唐','唐诗','tang','','[]','紅紫共紛紛，祗承老使君。',48,'全唐诗/poet.tang.23000.json','["紅紫共紛紛，祗承老使君。", "移舟木蘭櫂，行酒石榴帬。", "水色窗窗見，花香院院聞。", "戀他官舍住，雙鬢白如雲。"]'),
('d4871bed-61c5-478c-8451-0b3023aa5ed0','六月三日夜聞蟬','白居易','唐','唐诗','tang','','[]','荷香清露墜，柳動好風生。',60,'全唐诗/poet.tang.23000.json','["荷香清露墜，柳動好風生。", "微月初三夜，新蟬第一聲。", "乍聞愁北客，靜聽憶東京。", "我有竹林宅，別來蟬再鳴。", "不知池上月，誰撥小船行。"]'),
('4adc0a51-920f-4c4c-80ec-b8d0600d2c53','蓮石','白居易','唐','唐诗','tang','','[]','青石一兩片，白蓮三四枝。',72,'全唐诗/poet.tang.23000.json','["青石一兩片，白蓮三四枝。", "寄將東洛去，心與物相隨。", "石倚風前樹，蓮栽月下池。", "遙知安置處，預想發榮時。", "領郡來何遠，還鄉去已遲。", "莫言千里別，歲晚有心期。"]'),
('99bbf157-b2fe-4428-84ce-05389ff936a8','眼病二首 一','白居易','唐','唐诗','tang','','[]','散亂空中千片雪，蒙籠物上一重紗。',64,'全唐诗/poet.tang.23000.json','["散亂空中千片雪，蒙籠物上一重紗。", "縱逢晴景如看霧，不是春天亦看花。", "僧說客塵來眼界，醫言風眩在肝家。", "兩頭治療何曾瘥，藥力微茫佛力賒。"]'),
('32a240b5-73b1-4b1d-8a58-e93c2884bfb5','眼病二首 二','白居易','唐','唐诗','tang','','[]','眼藏損傷來已久，病根牢固去應難。',64,'全唐诗/poet.tang.23000.json','["眼藏損傷來已久，病根牢固去應難。", "醫師盡勸先停酒，道侶多教早罷官。", "案上謾鋪龍樹論，盒中虛撚決明丸。", "人間方藥應無益，爭得金箆試刮看。"]'),
('3f57ba9e-88e9-423e-b2ba-27a83e2d91a1','題東武丘寺六韻','白居易','唐','唐诗','tang','','[]','香剎看非遠，祇園入始深。',72,'全唐诗/poet.tang.23000.json','["香剎看非遠，祇園入始深。", "龍蟠松矯矯，玉立竹森森。", "怪石千僧坐，靈池一劒沈。", "海當亭兩面，山在寺中心。", "酒熟憑花勸，詩成倩鳥吟。", "寄言軒冕客，此地好抽簪。"]'),
('2b6ad2e4-49f2-410a-88f0-99b678ed315a','夜遊西武丘寺八韻','白居易','唐','唐诗','tang','','[]','不厭西丘寺，閑來即一過。',96,'全唐诗/poet.tang.23000.json','["不厭西丘寺，閑來即一過。", "舟船轉雲島，樓閣出煙蘿。", "路入青松影，門臨白月波。", "魚跳驚秉燭，猨覰怪鳴珂。", "搖曳雙紅斾，娉婷十翠娥。", "香花助羅綺，鐘梵避笙歌。", "領郡時將久，遊山數幾何。", "一年十二度，非少亦非多。"]'),
('ca4e1a13-ec72-4d1b-82d1-9370cbb9d835','詠懷','白居易','唐','唐诗','tang','','[]','蘇杭自昔稱名郡，牧守當今當好官。',64,'全唐诗/poet.tang.23000.json','["蘇杭自昔稱名郡，牧守當今當好官。", "兩地江山蹋得徧，五年風月詠將殘。", "幾時酒醆曾拋却，何處花枝不把看？", "白髮滿頭歸得也，詩情酒興漸闌珊。"]'),
('81ff5a96-25fd-4e27-941c-25eee0552cb5','重詠','白居易','唐','唐诗','tang','','[]','日覺雙眸暗，年驚兩鬢蒼。',48,'全唐诗/poet.tang.23000.json','["日覺雙眸暗，年驚兩鬢蒼。", "病應無處避，老更不宜忙。", "徇俗心情少，休官道理長。", "今秋歸去定，何必重思量。"]'),
('407b7038-fd7c-402d-bb36-20a3fe23d995','百日假滿','白居易','唐','唐诗','tang','','[]','心中久有歸田計，身上都無濟世才。',64,'全唐诗/poet.tang.23000.json','["心中久有歸田計，身上都無濟世才。", "長告初從百日滿，故鄉元約一年回。", "馬辭轅下頭高舉，鶴出籠中翅大開。", "但拂衣行莫回顧，的無官職趁人來。"]'),
('3b4ab5ef-a6d2-4d81-a538-9e2bfc0129dd','九日寄微之','白居易','唐','唐诗','tang','','[]','眼闇頭風事事妨，遶籬新菊爲誰黃。',96,'全唐诗/poet.tang.23000.json','["眼闇頭風事事妨，遶籬新菊爲誰黃。", "閑遊日久心慵倦，痛飲年深肺損傷。", "吳郡兩回逢九月，越州四度見重陽。", "怕飛杯酒多分數，厭聽笙歌舊曲章。", "蟋蟀聲寒初過雨，茱萸色淺未經霜。", "去秋共數登高會，又被今年減一場。"]'),
('ed6c13dd-73fd-4528-b089-b71cbb2e2bb9','題報恩寺','白居易','唐','唐诗','tang','','[]','好是清涼地，都無繫絆身。',48,'全唐诗/poet.tang.23000.json','["好是清涼地，都無繫絆身。", "晚晴宜野寺，秋景屬閑人。", "淨石堪敷坐，寒泉可濯巾。", "自慙容鬢上，猶帶郡庭塵。"]'),
('c6b1e472-ea33-45a1-abe7-3480de6a7250','晚起','白居易','唐','唐诗','tang','','[]','臥聽鼕鼕衙鼓聲，起遲睡足長心情。',64,'全唐诗/poet.tang.23000.json','["臥聽鼕鼕衙鼓聲，起遲睡足長心情。", "華簪脫後頭雖白，堆案拋來眼校明。", "閑上籃轝乘興出，醉回花舫信風行。", "明朝更濯塵纓去，聞道松江水最清。"]'),
('410ddbf7-7616-4230-a411-a8e6d5a995a4','自思益寺次楞伽寺作','白居易','唐','唐诗','tang','','[]','朝從思益峰遊後，晚到楞伽寺歇時。',64,'全唐诗/poet.tang.23000.json','["朝從思益峰遊後，晚到楞伽寺歇時。", "照水姿容雖已老，上山筋力未全衰。", "行逢禪客多相問，坐倚漁舟一自思。", "猶去懸車十五載，休官非早亦非遲。"]'),
('c63c7e0a-d361-4626-a4d2-49db01b48fbc','松江亭攜樂觀漁宴宿','白居易','唐','唐诗','tang','','[]','震澤平蕪岸，松江落葉波。',72,'全唐诗/poet.tang.23000.json','["震澤平蕪岸，松江落葉波。", "在官常夢想，爲客始經過。", "水面排罾網，船頭簇綺羅。", "朝盤鱠紅鯉，夜燭舞青娥。", "雁斷知風急，潮平見月多。", "繁絲與促管，不解和漁歌。"]'),
('f3c57737-1c2c-4d34-b9c9-5dc6e24394a9','宿靈巖寺上院','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','高高白月上青林，客去僧歸獨夜深。',64,'全唐诗/poet.tang.23000.json','["高高白月上青林，客去僧歸獨夜深。", "葷血屏除唯對酒，歌鐘放散只留琴。", "更無俗物當人眼，但有泉聲洗我心。", "最愛曉亭東望好，太湖煙水綠沈沈。"]'),
('a0b3902c-6f2a-4b1d-b19a-845c9dfef2c9','酬別周從事二首 一','白居易','唐','唐诗','tang','','[]','腰痛拜迎人客倦，眼昏勾押簿書難。',32,'全唐诗/poet.tang.23000.json','["腰痛拜迎人客倦，眼昏勾押簿書難。", "辭官歸去緣衰病，莫作陶潛范蠡看。"]'),
('2a622866-547e-4b15-82db-7d664b7133e3','酬別周從事二首 二','白居易','唐','唐诗','tang','','[]','洛下田園久拋擲，吳中歌酒莫留連。',32,'全唐诗/poet.tang.23000.json','["洛下田園久拋擲，吳中歌酒莫留連。", "嵩陽雲樹伊川月，已校歸遲四五年。"]'),
('159c2a24-3be3-4a3d-b975-17c337b915b5','武丘寺路','白居易','唐','唐诗','tang','','[]','自開山寺路，水陸往來頻。',48,'全唐诗/poet.tang.23000.json','["自開山寺路，水陸往來頻。", "銀勒牽驕馬，花船載麗人。", "芰荷生欲徧，桃李種仍新。", "好住湖堤上，長留一道春。"]'),
('0b8b4672-b563-42ef-b2dd-811f1df5fadc','齊雲樓晚望偶題十韻兼呈馮侍御周殷二協律','白居易','唐','唐诗','tang','','[]','潦倒宦情盡，蕭條芳歲闌。',120,'全唐诗/poet.tang.23000.json','["潦倒宦情盡，蕭條芳歲闌。", "欲辭南國去，重上北城看。", "複疊江山壯，平鋪井邑寬。", "人稠過楊府，坊鬧半長安。", "插霧峰頭沒，穿霞日脚殘。", "水光紅漾漾，樹色綠漫漫。", "約略留遺愛，殷勤念舊歡。", "病拋官職易，老別友朋難。", "九月全無熱，西風亦未寒。", "齊雲樓北面，半日凭欄干。"]'),
('ac5183a6-4d6f-4ae7-83bd-7f925d2e71af','河亭晴望','白居易','唐','唐诗','tang','','[]','風轉雲頭歛，煙銷水面開。',48,'全唐诗/poet.tang.23000.json','["風轉雲頭歛，煙銷水面開。", "晴虹橋影出，秋雁櫓聲來。", "郡靜官初罷，鄉遙信未迴。", "明朝是重九，誰勸菊花桮。"]'),
('1dc8f53a-980e-40fa-b2c1-4c00638899d4','留別微之','白居易','唐','唐诗','tang','','[]','干時久與本心違，悟道深知前事非。',64,'全唐诗/poet.tang.23000.json','["干時久與本心違，悟道深知前事非。", "猶厭勞形辭郡印，那將趂伴著朝衣。", "五千言裏教知足，三百篇中勸式微。", "少室雲邊伊水畔，比君校老合先歸。"]'),
('2cae3a49-73b0-45a3-a68f-4db8695761ea','自喜','白居易','唐','唐诗','tang','','[]','自喜天教我少緣，家徒行計兩翩翩。',64,'全唐诗/poet.tang.23000.json','["自喜天教我少緣，家徒行計兩翩翩。", "身兼妻子都三口，鶴與琴書共一船。", "僮僕減來無冗食，資糧算外有餘錢。", "攜將貯作丘中費，猶免飢寒得數年。"]'),
('fd2f8c79-b10b-43fa-b4d7-b2cfc7171976','武丘寺路宴留別諸妓','白居易','唐','唐诗','tang','','[]','銀泥帬映錦障泥，畫舸停橈馬簇蹄。',64,'全唐诗/poet.tang.23000.json','["銀泥帬映錦障泥，畫舸停橈馬簇蹄。", "清管曲終鸚鵡語，紅旗影動䮂䮧嘶。", "漸消醉色朱顏淺，欲語離情翠黛低。", "莫忘使君吟詠處，女墳湖北武丘西。"]'),
('b7cf5cd4-a4f2-49c6-9bc8-49658ddfc2d7','江上對酒二首 一','白居易','唐','唐诗','tang','','[]','酒助疎頑性，琴資緩慢情。',48,'全唐诗/poet.tang.23000.json','["酒助疎頑性，琴資緩慢情。", "有慵將送老，無智可勞生。", "忽忽忘機坐，倀倀任運行。", "家鄉安處是，那獨在神京。"]'),
('48159445-7697-4040-9746-a11162b31f96','江上對酒二首 二','白居易','唐','唐诗','tang','','[]','久貯滄浪意，初辭桎梏身。',48,'全唐诗/poet.tang.23000.json','["久貯滄浪意，初辭桎梏身。", "昏昏常帶酒，默默不應人。", "坐穩便箕踞，眠多愛欠伸。", "客來存禮數，始著白綸巾。"]'),
('2645ac88-2914-4384-8228-87b44434580c','望亭驛酬別周判官','白居易','唐','唐诗','tang','','[]','何事出長洲，連宵飲不休。',48,'全唐诗/poet.tang.23000.json','["何事出長洲，連宵飲不休。", "醒應難作別，歡漸少於愁。", "燈火穿村市，笙歌上驛樓。", "何言五十里，已不屬蘇州。"]'),
('cbd1ac2f-cf20-40a5-817b-14924b06a285','見小姪龜兒詠燈詩幷臘娘製衣因寄行簡','白居易','唐','唐诗','tang','','[]','已知臘子能裁服，復報龜兒解詠燈。',32,'全唐诗/poet.tang.23000.json','["已知臘子能裁服，復報龜兒解詠燈。", "巧婦才人常薄命，莫教男女苦多能。"]'),
('81823c73-63ae-460d-a801-19ae7f4d1fdb','酒筵上荅張居士','白居易','唐','唐诗','tang','','[]','但要前塵減，無妨外相同。',48,'全唐诗/poet.tang.23000.json','["但要前塵減，無妨外相同。", "雖過酒肆上，不離道場中。", "弦管聲非實，花鈿色是空。", "何人知此義，唯有淨名翁。"]'),
('d70667b9-669e-462b-a815-96303acde962','鸚鵡','白居易','唐','唐诗','tang','','[]','隴西鸚鵡到江東，養得經年觜漸紅。',64,'全唐诗/poet.tang.23000.json','["隴西鸚鵡到江東，養得經年觜漸紅。", "常恐思歸先剪翅，每因餧食暫開籠。", "人憐巧語情雖重，鳥憶高飛意不同。", "應似朱門歌舞妓，深藏牢閉後房中。"]'),
('a80a6513-bbe1-4f76-be73-2fb46f6e8b41','聽琵琶妓彈略略','白居易','唐','唐诗','tang','','[]','腕軟撥頭輕，新教略略成。',48,'全唐诗/poet.tang.23000.json','["腕軟撥頭輕，新教略略成。", "四弦千遍語，一曲萬重情。", "法向師邊得，能從意上生。", "莫欺江外手，別是一家聲。"]'),
('9aeb8a60-5162-4390-992c-46f379a53706','寫新詩寄微之偶題卷後','白居易','唐','唐诗','tang','','[]','寫了吟看滿卷愁，淺紅牋紙小銀鉤。',32,'全唐诗/poet.tang.23000.json','["寫了吟看滿卷愁，淺紅牋紙小銀鉤。", "未容寄與微之去，已被人傳到越州。"]'),
('24d89bdc-6938-4848-8a1f-8c871fc00aa5','寶曆二年八月三十日夜夢後作','白居易','唐','唐诗','tang','','[]','塵纓忽解誠堪喜，世網重來未可知。',32,'全唐诗/poet.tang.23000.json','["塵纓忽解誠堪喜，世網重來未可知。", "莫忘全吳館中夢，嶺南泥雨步行時。"]'),
('9ae5d6fb-2f7b-4ecc-a439-b22bd39e8f23','與夢得同登棲靈塔','白居易','唐','唐诗','tang','','[]','半月悠悠在廣陵，何樓何塔不同登。',32,'全唐诗/poet.tang.23000.json','["半月悠悠在廣陵，何樓何塔不同登。", "共憐筋力猶堪在，上到棲靈第九層。"]'),
('a1fa4545-fc30-4c04-878c-dd3d0b3c934e','夢蘇州水閣寄馮侍御','白居易','唐','唐诗','tang','','[]','揚州驛裏夢蘇州，夢到花橋水閣頭。',32,'全唐诗/poet.tang.23000.json','["揚州驛裏夢蘇州，夢到花橋水閣頭。", "覺後不知馮侍御，此中昨夜共誰遊。"]'),
('1a3b0891-a7f3-42b0-a2da-582cb19658f7','喜罷郡','白居易','唐','唐诗','tang','','[]','五年兩郡亦堪嗟，偷出遊山走看花。',64,'全唐诗/poet.tang.23000.json','["五年兩郡亦堪嗟，偷出遊山走看花。", "自此光陰爲己有，從前日月屬官家。", "樽前免被催迎使，枕上休聞報坐衙。", "睡到午時歡到夜，回看官職是泥沙。"]'),
('213e51fd-6871-4d7f-a5a1-9bbf57fa272c','荅次休上人','白居易','唐','唐诗','tang','','[]','姓白使君無麗句，名休座主有新文。',32,'全唐诗/poet.tang.23000.json','["姓白使君無麗句，名休座主有新文。", "禪心不合生分別，莫愛餘霞嫌碧雲。"]'),
('82d15471-a8d9-441b-9df0-fd44c38f1c26','感悟妄緣題如上人壁','白居易','唐','唐诗','tang','','[]','自從爲騃童，直至作衰翁。',72,'全唐诗/poet.tang.23000.json','["自從爲騃童，直至作衰翁。", "所好隨年異，爲忙終日同。", "弄沙成佛塔，鏘玉謁王宮。", "彼此皆兒戲，須臾即色空。", "有營非了義，無著是真宗。", "兼恐勤修道，猶應在妄中。"]'),
('3a75fb8c-f4f3-4b74-a9bc-0e04dd914c02','思子臺有感二首 一','白居易','唐','唐诗','tang','','[]','曾家機上聞投杼，尹氏園中見掇蜂。',32,'全唐诗/poet.tang.23000.json','["曾家機上聞投杼，尹氏園中見掇蜂。", "但以恩情生隙罅，何人不解作江充。"]'),
('6017dfa6-a221-4bef-8838-55e7cbaa4a33','思子臺有感二首 二','白居易','唐','唐诗','tang','','[]','闇生魑魅蠹生蟲，何異讒生疑阻中。',32,'全唐诗/poet.tang.23000.json','["闇生魑魅蠹生蟲，何異讒生疑阻中。", "但使武皇心似燭，江充不敢作江充。"]'),
('b49097d6-8b02-479c-8aa6-8b871dc827b4','賦得邊城角','白居易','唐','唐诗','tang','','[]','邊角兩三枝，霜天隴上兒。',48,'全唐诗/poet.tang.23000.json','["邊角兩三枝，霜天隴上兒。", "望鄉相並立，向月一時吹。", "戰馬頭皆舉，征人手盡垂。", "嗚嗚三奏罷，城上展旌旗。"]'),
('c56ff271-9f32-4f56-a08a-fbd69dde4736','憶洛中所居','白居易','唐','唐诗','tang','','[]','忽憶東都宅，春來事宛然。',84,'全唐诗/poet.tang.23000.json','["忽憶東都宅，春來事宛然。", "雪銷行徑裏，水上臥房前。", "厭綠栽黃竹，嫌紅種白蓮。", "醉教鸎送酒，閑遣鶴看船。", "幸是林園主，慙爲食祿牽。", "宦情薄似紙，鄉思急於弦。", "豈合姑蘇守，歸休更待年。"]'),
('e50b3fa5-cbed-40a3-a54b-86c25a2c9d43','想歸田園','白居易','唐','唐诗','tang','','[]','戀他朝市求何事，想取丘園樂此身。',64,'全唐诗/poet.tang.23000.json','["戀他朝市求何事，想取丘園樂此身。", "千首惡詩吟過日，一壺好酒醉消春。", "歸鄉年亦非全老，罷郡家仍未苦貧。", "快活不知如我者，人間能有幾多人。"]'),
('785ddb64-8fd9-402b-b4fc-8cb50e1469ed','琴茶','白居易','唐','唐诗','tang','','["\u7231\u56fd", "\u751f\u6d3b"]','兀兀寄形羣動內，陶陶任性一生間。',64,'全唐诗/poet.tang.23000.json','["兀兀寄形羣動內，陶陶任性一生間。", "自拋官後春多醉，不讀書來老更閑。", "琴裏知聞唯淥水，茶中故舊是蒙山。", "窮通行止長相伴，誰道吾今無往還。"]'),
('e72edc33-55dd-4ec2-8e17-432c3b8e70ea','贈楚州郭使君','白居易','唐','唐诗','tang','','[]','淮水東南第一州，山圍雉堞月當樓。',64,'全唐诗/poet.tang.23000.json','["淮水東南第一州，山圍雉堞月當樓。", "黃金印綬懸腰底，白雪歌詩落筆頭。", "笑看兒童騎竹馬，醉攜賓客上仙舟。", "當家美事堆身上，何啻林宗與細侯。"]'),
('15e79aa0-f66b-4029-8040-cf0d273a2346','和郭使君題枸杞','白居易','唐','唐诗','tang','','[]','山陽太守政嚴明，吏靜人安無犬驚。',32,'全唐诗/poet.tang.23000.json','["山陽太守政嚴明，吏靜人安無犬驚。", "不知靈藥根成狗，怪得時聞吠夜聲。"]'),
('c4e0cbe7-12cb-460f-89fc-74e68c8f220e','初到洛下閑遊','白居易','唐','唐诗','tang','','[]','漢庭重少身宜退，洛下閑居迹可逃。',64,'全唐诗/poet.tang.23000.json','["漢庭重少身宜退，洛下閑居迹可逃。", "趂伴入朝應老醜，尋春放醉尚粗豪。", "詩攜綵紙新裝卷，酒典緋花舊賜袍。", "曾在東方千騎上，至今躞蹀馬頭高。"]'),
('7faa59ad-1cd2-45af-8b4a-90d7fb3d6b5e','醉贈劉二十八使君','白居易','唐','唐诗','tang','','["\u529d\u6170", "\u53cb\u60c5"]','爲我引桮添酒飲，與君把箸擊盤歌。',64,'全唐诗/poet.tang.23000.json','["爲我引桮添酒飲，與君把箸擊盤歌。", "詩稱國手徒爲爾，命壓人頭不奈何。", "舉眼風光長寂寞，滿朝官職獨蹉跎。", "亦知合被才名折，二十三年折太多。"]'),
('0fc8638d-63e2-40c6-85b6-47187c4f3920','太湖石','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','煙翠三秋色，波濤萬古痕。',48,'全唐诗/poet.tang.23000.json','["煙翠三秋色，波濤萬古痕。", "削成青玉片，截斷碧雲根。", "風氣通巖穴，苔文護洞門。", "三峰具體小，應是華山孫。"]'),
('84dbbb20-092f-4c3e-b2a6-02bf679895bb','過敷水','白居易','唐','唐诗','tang','','[]','垂鞭欲渡羅敷水，處分鳴騶且緩驅。',48,'全唐诗/poet.tang.23000.json','["垂鞭欲渡羅敷水，處分鳴騶且緩驅。", "秦氏雙蛾久冥漠，蘇臺五馬尚踟躕。", "村童店女仰頭笑，今日使君真是愚。"]'),
('a5c44a5f-e66a-46a7-9085-e82845005c3a','南院','白居易','唐','唐诗','tang','','[]','林院無情緒，經春不一開。',48,'全唐诗/poet.tang.23000.json','["林院無情緒，經春不一開。", "楊花飛作穗，榆莢落成堆。", "壯氣從中減，流年逐後催。", "只應如過客，病去老迎來。"]'),
('803526d9-c6e4-4554-a31f-f5dd186c0fdc','閑詠','白居易','唐','唐诗','tang','','[]','步月憐清景，眠松愛綠陰。',48,'全唐诗/poet.tang.23000.json','["步月憐清景，眠松愛綠陰。", "早年詩思苦，晚歲道情深。", "夜學禪多坐，秋牽興暫吟。", "悠然兩事外，無處更留心。"]'),
('3d467148-f86d-4284-b6d8-1e9179276490','初授祕監拜賜金紫閑吟小酌偶寫所懷','白居易','唐','唐诗','tang','','[]','紫袍新祕監，白首舊書生。',72,'全唐诗/poet.tang.23000.json','["紫袍新祕監，白首舊書生。", "鬢雪人間壽，腰金世上榮。", "子孫無可念，產業不能營。", "酒引眼前興，詩留身後名。", "閑傾三數酌，醉詠十餘聲。", "便是羲皇代，先從心太平。"]'),
('8d056283-9fea-4573-83ae-e70205d683b0','新昌閑居招楊郎中兄弟','白居易','唐','唐诗','tang','','[]','紗巾角枕病眠翁，忙少閑多誰與同。',64,'全唐诗/poet.tang.23000.json','["紗巾角枕病眠翁，忙少閑多誰與同。", "但有雙松當砌下，更無一事到心中。", "金章紫綬堪如夢，皂蓋朱輪別似空。", "暑月貧家何所有，客來唯贈北窗風。"]'),
('7c30a404-2221-46e5-9c57-2d0943d205be','祕省後廳','白居易','唐','唐诗','tang','','[]','槐花雨潤新秋地，桐葉風翻欲夜天。',32,'全唐诗/poet.tang.23000.json','["槐花雨潤新秋地，桐葉風翻欲夜天。", "盡日後廳無一事，白頭老監枕書眠。"]'),
('c7359627-a02c-4f97-a53a-65ff5b203f7f','松齋偶興','白居易','唐','唐诗','tang','','[]','置心思慮外，滅跡是非間。',48,'全唐诗/poet.tang.23000.json','["置心思慮外，滅跡是非間。", "約俸爲生計，隨官換往還。", "耳煩聞曉角，眼醒見秋山。", "賴此松簷下，朝回半日閑。"]'),
('9973b5a9-2259-428d-8d11-9bf2368a32e9','和楊郎中賀楊僕射致仕後楊侍郎門生合宴席上作','白居易','唐','唐诗','tang','','[]','業重關西繼大名，恩深闕下遂高情。',64,'全唐诗/poet.tang.23000.json','["業重關西繼大名，恩深闕下遂高情。", "祥鱣降伴趨庭鯉，賀燕飛和出谷鶯。", "范蠡舟中無子弟，疏家席上欠門生。", "可憐玉樹連桃李，從古無如此會榮。"]'),
('ef85d9e5-cbed-49aa-985e-9480b353bd50','松下琴贈客','白居易','唐','唐诗','tang','','[]','松寂風初定，琴清夜欲闌。',48,'全唐诗/poet.tang.23000.json','["松寂風初定，琴清夜欲闌。", "偶因羣動息，試撥一聲看。", "寡鶴當徽怨，秋泉應指寒。", "慙君此傾聽，本不爲君彈。"]'),
('5efa7d4e-3180-4887-8aa1-8da52f29a26a','秋齋','白居易','唐','唐诗','tang','','[]','晨起秋齋冷，蕭條稱病容。',48,'全唐诗/poet.tang.23000.json','["晨起秋齋冷，蕭條稱病容。", "清風兩窗竹，白露一庭松。", "阮籍謀身拙，嵇康向事慵。", "生涯別有處，浩氣在心胸。"]'),
('56a74c85-c6ad-4130-9f96-89636456321b','塗山寺獨遊','白居易','唐','唐诗','tang','','[]','野徑行無伴，僧房宿有期。',24,'全唐诗/poet.tang.23000.json','["野徑行無伴，僧房宿有期。", "塗山來去熟，唯是馬蹄知。"]'),
('ca944a08-1785-4bfb-b2da-fde0d7409057','登觀音臺望城','白居易','唐','唐诗','tang','','[]','百千家似圍棊局，十二街如種菜畦。',32,'全唐诗/poet.tang.23000.json','["百千家似圍棊局，十二街如種菜畦。", "遙認微微入朝火，一條星宿五門西。"]'),
('fcf9d915-4c5e-4abc-8999-82681aa05704','登靈應臺北望','白居易','唐','唐诗','tang','','[]','臨高始見人寰小，對遠方知色界空。',32,'全唐诗/poet.tang.23000.json','["臨高始見人寰小，對遠方知色界空。", "回首却歸朝市去，一稊米落太倉中。"]'),
('586543b7-3cd8-4f80-a0a6-a73f9f5e600d','酬裴相公題興化小池見招長句','白居易','唐','唐诗','tang','','[]','爲愛小塘招散客，不嫌老監與新詩。',64,'全唐诗/poet.tang.23000.json','["爲愛小塘招散客，不嫌老監與新詩。", "山公倒載無妨學，范蠡扁舟未要追。", "蓬斷偶飄桃李徑，鷗驚誤拂鳳皇池。", "敢辭課拙詶高韻，一勺爭禁萬頃陂。"]'),
('56a12f40-2367-4944-8517-cdb25e866824','閑行','白居易','唐','唐诗','tang','','[]','五十年來思慮熟，忙人應未勝閑人。',64,'全唐诗/poet.tang.23000.json','["五十年來思慮熟，忙人應未勝閑人。", "林園傲逸真成貴，衣食單疎不是貧。", "專掌圖書無過地，遍尋山水自由身。", "儻年七十猶強健，尚得閑行十五春。"]'),
('9ad301dc-138a-4f6f-94b8-cc8a72153869','閑出','白居易','唐','唐诗','tang','','[]','兀兀出門何處去，新昌街晚樹陰斜。',32,'全唐诗/poet.tang.23000.json','["兀兀出門何處去，新昌街晚樹陰斜。", "馬蹄知意緣行熟，不向楊家即庾家。"]'),
('eb1b2bc7-a921-4bc8-a82a-db73e4ebba43','與僧智如夜話','白居易','唐','唐诗','tang','','[]','嬾鈍尤知命，幽棲漸得朋。',48,'全唐诗/poet.tang.23000.json','["嬾鈍尤知命，幽棲漸得朋。", "門閑無謁客，室靜有禪僧。", "爐向初冬火，籠停半夜燈。", "憂勞緣智巧，自喜百無能。"]'),
('218851e4-3dfa-4718-ab14-441c5ea4bab5','憶廬山舊隱及洛下新居','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','形骸僶俛班行內，骨肉句留俸祿中。',64,'全唐诗/poet.tang.23000.json','["形骸僶俛班行內，骨肉句留俸祿中。", "無奈攀緣隨手長，亦知恩愛到頭空。", "草堂久閉廬山下，竹院新拋洛水東。", "自是未能歸去得，世間誰要白鬚翁。"]'),
('a9334bcd-0f9d-4a87-b260-3383a5590d16','晚寒','白居易','唐','唐诗','tang','','[]','急景流如箭，淒風利似刀。',48,'全唐诗/poet.tang.23000.json','["急景流如箭，淒風利似刀。", "暝催雞翅歛，寒束樹枝高。", "縮水濃和酒，加緜厚絮袍。", "可憐冬計畢，煖臥醉陶陶。"]'),
('fcabf7d5-1aa0-4058-90d2-b8afc60c3aaf','偶眠','白居易','唐','唐诗','tang','','[]','放桮書案上，枕臂火爐前。',48,'全唐诗/poet.tang.23000.json','["放桮書案上，枕臂火爐前。", "老愛尋思事，慵多取次眠。", "妻教卸烏帽，婢與展青氊。", "便是屏風樣，何勞畫古賢。"]'),
('9c2eb7a4-bb2d-464b-9cc2-1c0fde1276d9','華城西北雉堞最高崔相公首創樓臺錢左丞繼種花果合爲勝境題在雅篇歲暮獨遊悵然成詠','白居易','唐','唐诗','tang','','[]','高居稱君子，瀟灑四無鄰。',48,'全唐诗/poet.tang.23000.json','["高居稱君子，瀟灑四無鄰。", "丞相棟梁久，使君桃李新。", "凝情看麗句，駐步想清塵。", "況是寒天客，樓空無主人。"]'),
('95073e67-d7f7-4f11-ae5c-fca43d84ddcd','奉使途中戲贈張常侍','白居易','唐','唐诗','tang','','[]','早風吹土滿長衢，驛騎星軺盡疾驅。',32,'全唐诗/poet.tang.23000.json','["早風吹土滿長衢，驛騎星軺盡疾驅。", "共笑籃舁亦稱使，日馳一驛向東都。"]'),
('77360386-2190-4ca0-93be-60bc18e5f57d','有小白馬乘馭多時奉使東行至稠桑驛溘然而斃足可驚傷不能忘情題二十韻','白居易','唐','唐诗','tang','','[]','能驟復能馳，翩翩白馬兒。',240,'全唐诗/poet.tang.23000.json','["能驟復能馳，翩翩白馬兒。", "毛寒一團雪，鬃薄萬條絲。", "皁蓋春行日，驪駒曉從時。", "雙旌前獨步，五馬內偏騎。", "芳草承蹄葉，垂楊拂頂枝。", "跨將迎好客，惜不換妖姬。", "慢鞚遊蕭寺，閑驅醉習池。", "睡來乘作夢，興發倚成詩。", "鞭爲馴難下，鞍緣穩不離。", "北歸還共到，東使亦相隨。", "赭白何曾變，玄黃豈得知。", "嘶風覺聲急，蹋雪怪行遲。", "昨夜猶芻秣，今朝尚縶維。", "臥槽應不起，顧主遂長辭。", "塵滅駸駸迹，霜留皎皎姿。", "度關形未改，過隙影難追。", "念倍燕求駿，情深項別騅。", "銀收鉤臆帶，金卸絡頭羈。", "何處埋奇骨，誰家覓弊帷。", "稠桑驛門外，吟罷涕雙垂。"]'),
('795565b9-d424-4054-a14c-50db84ea637f','題噴玉泉','白居易','唐','唐诗','tang','','[]','泉噴聲如玉，潭澄色似空。',48,'全唐诗/poet.tang.23000.json','["泉噴聲如玉，潭澄色似空。", "練垂青嶂上，珠瀉綠盆中。", "溜滴三秋雨，寒生六月風。", "何時此岩下，來作濯纓翁。"]'),
('f66e17bf-07e1-4049-9e77-b44bb8c693ad','酬皇甫賓客','白居易','唐','唐诗','tang','','[]','閑官兼慢使，著處易停輪。',48,'全唐诗/poet.tang.23000.json','["閑官兼慢使，著處易停輪。", "況欲逢新歲，仍初見故人。", "冒寒尋到洛，待煖始歸秦。", "亦擬同攜手，城東畧看春。"]'),
('3800c4bf-825d-4a24-b998-939c301a89af','種白蓮','白居易','唐','唐诗','tang','','[]','吳中白藕洛中栽，莫戀江南花嬾開。',32,'全唐诗/poet.tang.23000.json','["吳中白藕洛中栽，莫戀江南花嬾開。", "萬里攜歸爾知否，紅蕉朱槿不將來。"]'),
('506a9d4f-b70e-4de1-b7d7-d8d7b21851ea','答蘇庶子','白居易','唐','唐诗','tang','','[]','偶作關東使，重陪洛下遊。',48,'全唐诗/poet.tang.23000.json','["偶作關東使，重陪洛下遊。", "病來從斷酒，老去可禁愁。", "款曲偏青眼，蹉跎各白頭。", "蓬山閑氣味，依約似龍樓。"]'),
('a2dc9881-1139-4d03-a140-ca96daf47fa0','答尉遲少監水閣重宴','白居易','唐','唐诗','tang','','[]','人情依舊歲華新，今日重招往日賓。',64,'全唐诗/poet.tang.23000.json','["人情依舊歲華新，今日重招往日賓。", "雞黍重回千里駕，林園闇換四年春。", "水軒平寫琉璃鏡，草岸斜鋪翡翠茵。", "聞道經營費心力，忍教成後屬他人。"]'),
('9b0231df-73c6-432d-bf03-444aaa8e6df7','和劉郎中傷鄂姬','白居易','唐','唐诗','tang','','[]','不獨君嗟我亦嗟，西風北雪殺南花。',32,'全唐诗/poet.tang.23000.json','["不獨君嗟我亦嗟，西風北雪殺南花。", "不知月夜魂歸處，鸚鵡洲頭第幾家。"]'),
('5a20ea2d-6ce9-42aa-a559-f171f53d4779','贈東鄰王十三','白居易','唐','唐诗','tang','','[]','攜手池邊月，開襟竹下風。',48,'全唐诗/poet.tang.23000.json','["攜手池邊月，開襟竹下風。", "驅愁知酒力，破睡見茶功。", "居處東西接，年顏老少同。", "能來爲伴否，伊上作漁翁。"]'),
('7c3bbdb6-8f97-4a83-9a24-db9b4e9535b6','早春同劉郎中寄宣武令狐相公','白居易','唐','唐诗','tang','','[]','梁園不到一年強，遙想清吟對綠觴。',64,'全唐诗/poet.tang.23000.json','["梁園不到一年強，遙想清吟對綠觴。", "更有何人能飲酌，新添幾卷好篇章。", "馬頭拂柳時回轡，豹尾穿花暫亞槍。", "誰引相公開口笑，不逢白監與劉郎。"]'),
('4fded530-0634-4d30-9ee0-6a126d3473d8','寄太原李相公','白居易','唐','唐诗','tang','','[]','聞道北都今一變，政和軍樂萬人安。',64,'全唐诗/poet.tang.23000.json','["聞道北都今一變，政和軍樂萬人安。", "綺羅二八圍賓榻，組練三千夾將壇。", "蟬鬢應誇丞相少，貂裘不覺太原寒。", "世間大有虛榮貴，百歲無君一日歡。"]'),
('5e5af8b2-142c-4c56-8729-413b9cbd438f','雪中寄令狐相公兼呈夢得','白居易','唐','唐诗','tang','','[]','兔園春雪梁王會，想對金罍詠玉塵。',32,'全唐诗/poet.tang.23000.json','["兔園春雪梁王會，想對金罍詠玉塵。", "今日相如身在此，不知客右坐何人。"]'),
('1192b8fe-60b3-4781-a068-0180e48f78b7','出使在途所騎馬死改乘肩轝將歸長安偶詠旅懷寄太原李相公','白居易','唐','唐诗','tang','','[]','驛路崎嶇泥雪寒，欲登籃轝一長嘆。',64,'全唐诗/poet.tang.23000.json','["驛路崎嶇泥雪寒，欲登籃轝一長嘆。", "風光不見桃花騎，塵土空留杏葉鞍。", "喪乘獨歸殊不易，脫驂相贈豈爲難。", "幷州好馬應無數，不怕旌旄試覓看。"]'),
('7ccfdb12-ebda-4aab-aa04-d7d4596b6daa','有雙鶴留在洛中忽見劉郎中依然鳴顧劉因爲鶴嘆二篇寄予予以二絕句答之 一','白居易','唐','唐诗','tang','','[]','辭鄉遠隔華亭水，逐我來棲緱嶺雲。',32,'全唐诗/poet.tang.23000.json','["辭鄉遠隔華亭水，逐我來棲緱嶺雲。", "慚媿稻粱長不飽，未曾回眼向雞羣。"]'),
('37d19277-9ac9-49eb-82da-b0cbb36008f8','有雙鶴留在洛中忽見劉郎中依然鳴顧劉因爲鶴嘆二篇寄予予以二絕句答之 二','白居易','唐','唐诗','tang','','[]','荒草院中池水畔，銜恩不去又經春。',32,'全唐诗/poet.tang.23000.json','["荒草院中池水畔，銜恩不去又經春。", "見君驚喜雙回顧，應爲吟聲似主人。"]'),
('11bafd22-27c4-463f-81f4-a6215439b2cf','宿竇使君莊水亭','白居易','唐','唐诗','tang','','[]','使君何在在江東，池柳初黃杏欲紅。',32,'全唐诗/poet.tang.23000.json','["使君何在在江東，池柳初黃杏欲紅。", "有興即來閑便宿，不知誰是主人翁。"]'),
('0a14046d-0356-4329-a8b6-ea3118c62f3e','龍門下作','白居易','唐','唐诗','tang','','[]','龍門澗下濯塵纓，擬作閑人過此生。',32,'全唐诗/poet.tang.23000.json','["龍門澗下濯塵纓，擬作閑人過此生。", "筋力不將諸處用，登山臨水詠詩行。"]'),
('03af1258-83a1-4fcf-9ef0-824b1daa7f8c','姚侍御見過戲贈','白居易','唐','唐诗','tang','','[]','晚起春寒慵裹頭，客來池上偶同遊。',32,'全唐诗/poet.tang.23000.json','["晚起春寒慵裹頭，客來池上偶同遊。", "東臺御史多提舉，莫按金章繫布裘。"]'),
('26dc88d1-5f07-423c-8bae-bbc4c85da786','履道春居','白居易','唐','唐诗','tang','','[]','微雨灑園林，新晴好一尋。',48,'全唐诗/poet.tang.23000.json','["微雨灑園林，新晴好一尋。", "低風洗池面，斜日拆花心。", "暝助嵐陰重，春添水色深。", "不如陶省事，猶抱有弦琴。"]'),
('a50dd611-acce-4f90-ba58-7e298b93771f','題洛中第宅','白居易','唐','唐诗','tang','','[]','水木誰家宅，門高占地寬。',72,'全唐诗/poet.tang.23000.json','["水木誰家宅，門高占地寬。", "懸魚挂青甃，行馬護朱欄。", "春榭籠煙煖，秋庭鎖月寒。", "松膠黏琥珀，筠粉撲琅玕。", "試問池臺主，多爲將相官。", "終身不曾到，唯展宅圖看。"]'),
('87c80000-9ca1-450e-b23f-2a4b5d8e0129','寄殷協律','白居易','唐','唐诗','tang','','["\u6000\u4eba", "\u53cb\u4eba", "\u6292\u60c5"]','五歲優游同過日，一朝消散[似]浮雲。',66,'全唐诗/poet.tang.23000.json','["五歲優游同過日，一朝消散[似]浮雲。", "琴詩酒伴皆拋我，雪月花時最憶君。", "幾度聽雞歌白日，亦曾騎馬詠紅裙。", "吳娘暮雨蕭蕭曲，自別江南更不聞。"]'),
('cc250d91-d362-4621-baf4-63304f5e0f44','洛下諸客就宅相送偶題西亭','白居易','唐','唐诗','tang','','[]','几榻臨池坐，軒車冒雪過。',48,'全唐诗/poet.tang.23000.json','["几榻臨池坐，軒車冒雪過。", "交親致桮酒，僮僕解笙歌。", "流歲行將晚，浮榮得幾多。", "林泉應問我，不住意如何。"]'),
('b2d57649-22a8-4dd5-9633-d2d2df843ca4','答林泉','白居易','唐','唐诗','tang','','[]','好住舊林泉，回頭一悵然。',48,'全唐诗/poet.tang.23000.json','["好住舊林泉，回頭一悵然。", "漸知吾潦倒，深愧爾留連。", "欲作棲雲計，須營種黍錢。", "更容求一郡，不得亦歸田。"]'),
('812f82fd-b61b-4190-969b-30413308faa7','將發洛中枉令狐相公手札兼辱二篇寵行以長句答之','白居易','唐','唐诗','tang','','[]','尺素忽驚來梓澤，雙金不惜送蓬山。',64,'全唐诗/poet.tang.23000.json','["尺素忽驚來梓澤，雙金不惜送蓬山。", "八行落泊飛雲雨，五字鎗鏦動珮環。", "玉韻乍聽堪醒酒，銀鉤細讀當披顏。", "收藏便作終身寶，何啻三年懷袖間。"]'),
('5585e4e6-6526-45c0-bd38-e79693ee4c95','臨都驛答夢得六言二首 一','白居易','唐','唐诗','tang','','[]','揚子津頭月下，臨都驛裏燈前。',28,'全唐诗/poet.tang.23000.json','["揚子津頭月下，臨都驛裏燈前。", "昨日老於前日，去年春似今年。"]'),
('6f3391c1-8a9f-432f-9edf-1e70ffb08683','臨都驛答夢得六言二首 二','白居易','唐','唐诗','tang','','[]','謝守歸爲秘監，馮公老作郎官。',28,'全唐诗/poet.tang.23000.json','["謝守歸爲秘監，馮公老作郎官。", "前事不須問著，新詩且更吟看。"]'),
('5aa3def9-8feb-467b-9f28-84df62f0c714','喜錢左丞再除華州以詩伸賀','白居易','唐','唐诗','tang','','[]','左轄輟中臺，門東委上才。',48,'全唐诗/poet.tang.23000.json','["左轄輟中臺，門東委上才。", "彤襜經宿到，絳帳及春開。", "民望懇難奪，天心慈易回。", "那知不隔歲，重借寇恂來。"]'),
('f58d8266-4dbc-4e59-80a9-db04811a2de9','和錢華州題少華清光絕句','白居易','唐','唐诗','tang','','[]','高情雅韻三峯守，主領清光管白雲。',32,'全唐诗/poet.tang.23000.json','["高情雅韻三峯守，主領清光管白雲。", "自笑亦曾爲刺史，蘇州肥膩不如君。"]'),
('53dd60a6-c37e-4b00-9f98-19662889c8fc','送陝府王大夫','白居易','唐','唐诗','tang','','[]','金馬門前回劒珮，鐵牛城下擁旌旗。',32,'全唐诗/poet.tang.23000.json','["金馬門前回劒珮，鐵牛城下擁旌旗。", "他時萬一爲交代，留取甘棠三兩枝。"]'),
('54abc77f-ac71-4825-93c7-c155b27dff0f','代迎春花招劉郎中','白居易','唐','唐诗','tang','','["\u548f\u7269", "\u55bb\u4eba", "\u548f\u7269\u8bd7", "\u82b1", "\u5199\u82b1"]','幸與松筠相近栽，不隨桃李一時開。',32,'全唐诗/poet.tang.23000.json','["幸與松筠相近栽，不隨桃李一時開。", "杏園豈敢妨君去，未有花時且看來。"]'),
('b62f2238-14f3-41a1-910a-a52266d15ea6','翫迎春花贈楊郎中','白居易','唐','唐诗','tang','','[]','金英翠萼帶春寒，黃色花中有幾般。',32,'全唐诗/poet.tang.23000.json','["金英翠萼帶春寒，黃色花中有幾般。", "憑君與向遊人道，莫作蔓菁花眼看。"]'),
('e573bdad-7b86-47f5-aeed-2edaf512967b','閑出','白居易','唐','唐诗','tang','','[]','身外無羈束，心中少是非。',48,'全唐诗/poet.tang.23000.json','["身外無羈束，心中少是非。", "被花留便住，逢酒醉方歸。", "人事行時少，官曹入日稀。", "春寒遊正好，穩馬薄綿衣。"]'),
('3e15c462-6977-474d-b4c9-d81e7225d8a3','座上贈盧判官','白居易','唐','唐诗','tang','','[]','把酒承花花落頻，花香酒味相和春。',32,'全唐诗/poet.tang.23000.json','["把酒承花花落頻，花香酒味相和春。", "莫言不是江南會，虛白亭中舊主人。"]'),
('e698becc-27d1-481c-ba5c-8ec131c898cc','曲江有感','白居易','唐','唐诗','tang','','[]','曲江西岸又春風，萬樹花前一老翁。',32,'全唐诗/poet.tang.23000.json','["曲江西岸又春風，萬樹花前一老翁。", "遇酒逢花還且醉，若論惆悵事何窮。"]'),
('bf9ad6f4-368b-40e2-bbbc-87d48674cc2c','杏園花下贈劉郎中','白居易','唐','唐诗','tang','','[]','怪君把酒偏惆悵，曾是貞元花下人。',32,'全唐诗/poet.tang.23000.json','["怪君把酒偏惆悵，曾是貞元花下人。", "自別花來多少事，東風二十四回春。"]'),
('9fe915c6-5d52-4177-b90e-2b6875275b61','花前有感兼呈崔相公劉郎中','白居易','唐','唐诗','tang','','[]','落花如雪鬢如霜，醉把花看益自傷。',64,'全唐诗/poet.tang.23000.json','["落花如雪鬢如霜，醉把花看益自傷。", "少日爲名多檢束，長年無興可顛狂。", "四時輪轉春常少，百刻支分夜苦長。", "何事同生壬子歲，老於崔相及劉郎。"]'),
('c92f757e-b30f-45cc-856f-30e3c4600f9a','微之就拜尚書居易續除刑部因書賀意兼詠離懷','白居易','唐','唐诗','tang','','[]','我爲憲部入南宮，君作尚書鎮浙東。',64,'全唐诗/poet.tang.23000.json','["我爲憲部入南宮，君作尚書鎮浙東。", "老去一時成白首，別來七度換春風。", "簪纓假合虛名在，筋力銷磨實事空。", "遠地官高親故少，些些談笑與誰同。"]'),
('da239ce5-f95e-4ad5-a95a-5d33163d4cf1','喜與韋左丞同入南省因敘舊以贈之','白居易','唐','唐诗','tang','','[]','早年同遇陶鈞主，利鈍精粗共在鎔。',64,'全唐诗/poet.tang.23000.json','["早年同遇陶鈞主，利鈍精粗共在鎔。", "金劒淬來長透匣，鉛刀磨盡不成鋒。", "差肩北省慙非據，接武南宮幸再容。", "跛鼈雖遲騏驥疾，何妨中路亦相逢。"]'),
('5e2240af-d21e-4adc-bbb0-8c020cc5ee4c','伊州','白居易','唐','唐诗','tang','','[]','老去將何散老愁，新教小玉唱伊州。',32,'全唐诗/poet.tang.23000.json','["老去將何散老愁，新教小玉唱伊州。", "亦應不得多年聽，未教成時已白頭。"]'),
('68170055-ffba-441c-b198-c9de18ca237c','早朝','白居易','唐','唐诗','tang','','[]','鼓動出新昌，雞鳴赴建章。',72,'全唐诗/poet.tang.23000.json','["鼓動出新昌，雞鳴赴建章。", "翩翩穩鞍馬，楚楚健衣裳。", "宮漏傳殘夜，城陰送早涼。", "月堤槐露氣，風燭樺煙香。", "雙闕龍相對，千官雁一行。", "漢庭方尚少，慙嘆鬢如霜。"]'),
('0e1cb68b-0d05-44e8-a92d-90e8d6ace1f3','答裴相公乞鶴','白居易','唐','唐诗','tang','','[]','警露聲音好，沖天相貌殊。',48,'全唐诗/poet.tang.23000.json','["警露聲音好，沖天相貌殊。", "終宜向遼廓，不稱在泥塗。", "白首勞爲伴，朱門幸見呼。", "不知疎野性，解愛鳳池無。"]'),
('ad0697af-2d57-4cb0-9ea7-420fb785d806','晚從省歸','白居易','唐','唐诗','tang','','[]','朝回北闕值清晨，晚出南宮送暮春。',64,'全唐诗/poet.tang.23000.json','["朝回北闕值清晨，晚出南宮送暮春。", "入去丞郎非散秩，歸來詩酒是閑人。", "猶思泉石多成夢，尚嘆簪裾未離身。", "終是不如山下去，心頭眼底兩無塵。"]'),
('e961dc36-ff3f-4c04-89e7-ade8ec9c01f8','北窗閑坐','白居易','唐','唐诗','tang','','[]','虛窗兩叢竹，靜室一爐香。',48,'全唐诗/poet.tang.23000.json','["虛窗兩叢竹，靜室一爐香。", "門外紅塵合，城中白日忙。", "無煩尋道士，不要學仙方。", "自有延年術，心閑歲月長。"]'),
('c49022b6-74af-46c2-8863-890e95922651','酬嚴給事','白居易','唐','唐诗','tang','','[]','嬴女偷乘鳳去時，洞中潛歇弄瓊枝。',32,'全唐诗/poet.tang.23000.json','["嬴女偷乘鳳去時，洞中潛歇弄瓊枝。", "不緣啼鳥春饒舌，青瑣仙郎可得知。"]'),
('d3d685c7-9217-4776-b9d3-412ae6b2a05a','京路','白居易','唐','唐诗','tang','','[]','西來爲看秦山雪，東去緣尋洛苑春。',32,'全唐诗/poet.tang.23000.json','["西來爲看秦山雪，東去緣尋洛苑春。", "來去騰騰兩京路，閑行除我更無人。"]'),
('9680c3f4-d5b3-430d-ae79-2bb35e5ac83a','華州西','白居易','唐','唐诗','tang','','[]','每逢人靜慵多歇，不計程行困即眠。',32,'全唐诗/poet.tang.23000.json','["每逢人靜慵多歇，不計程行困即眠。", "上得籃轝未能去，春風敷水店門前。"]'),
('9e568379-777b-4eea-8aa5-44f65a4ec62d','從陝至東京','白居易','唐','唐诗','tang','','[]','從陝至東京，山低路漸平。',48,'全唐诗/poet.tang.23000.json','["從陝至東京，山低路漸平。", "風光四百里，車馬十三程。", "花共垂鞭看，桮多並轡傾。", "笙歌與談笑，隨分自將行。"]'),
('8dcf2049-139c-4649-91dd-1b1d25c04e5d','送春','白居易','唐','唐诗','tang','','[]','銀花鑿落從君勸，金屑琵琶爲我彈。',32,'全唐诗/poet.tang.23000.json','["銀花鑿落從君勸，金屑琵琶爲我彈。", "不獨送春兼送老，更嘗一着更聽看。"]'),
('6d47da9b-8ad5-4ac3-bd5f-c0abfe9d4aeb','宿杜曲花下','白居易','唐','唐诗','tang','','[]','覓得花千樹，攜來酒一壺。',96,'全唐诗/poet.tang.23000.json','["覓得花千樹，攜來酒一壺。", "嬾歸兼擬宿，未醉豈勞扶。", "但惜春將晚，寧愁日漸晡。", "籃轝爲臥舍，漆盝是行廚。", "斑竹盛茶櫃，紅泥罨飯爐。", "眼前無所闕，身外更何須。", "小面琵琶婢，蒼頭觱篥奴。", "從君飽富貴，曾作此遊無。"]'),
('a2730deb-c3c3-469b-9b04-72a245f92362','逢舊','白居易','唐','唐诗','tang','','[]','久別偶相逢，俱疑是夢中。',24,'全唐诗/poet.tang.23000.json','["久別偶相逢，俱疑是夢中。", "即今歡樂事，放醆又成空。"]'),
('f5608e17-7480-4b59-abde-75943af4bc64','繡婦嘆','白居易','唐','唐诗','tang','','[]','連枝花樣繡羅襦，本擬新年餉小姑。',64,'全唐诗/poet.tang.23000.json','["連枝花樣繡羅襦，本擬新年餉小姑。", "自覺逢春饒悵望，誰能每日趂功夫。", "針頭不解愁眉結，線縷難穿淚臉珠。", "雖凭繡牀都不繡，同牀繡伴得知無。"]'),
('f30a611c-ee72-4317-a752-b241955ff493','春詞','白居易','唐','唐诗','tang','','["\u6625\u5929", "\u95fa\u6028", "\u5973\u5b50"]','低花樹暎小妝樓，春入眉心兩點愁。',32,'全唐诗/poet.tang.23000.json','["低花樹暎小妝樓，春入眉心兩點愁。", "斜倚欄干背鸚鵡，思量何事不回頭。"]'),
('91d95c1f-1c5a-45a3-945b-04bda88e28ac','恨詞','白居易','唐','唐诗','tang','','[]','翠黛眉低歛，紅珠淚暗銷。',24,'全唐诗/poet.tang.23000.json','["翠黛眉低歛，紅珠淚暗銷。", "從來恨人意，不省似今朝。"]'),
('aa97f05f-e0f7-4bdb-a5b0-5c18046af690','山石榴花十二韻','白居易','唐','唐诗','tang','','[]','曄曄復煌煌，花中無比方。',144,'全唐诗/poet.tang.23000.json','["曄曄復煌煌，花中無比方。", "豔夭宜小院，條短稱低廊。", "本是山頭物，今爲砌下芳。", "千叢相向背，萬朵互低昂。", "照灼連朱檻，玲瓏暎粉牆。", "風來添意態，日出助晶光。", "漸綻臙脂萼，猶含琴軫房。", "離披亂剪綵，斑駮未勻妝。", "絳焰燈千炷，紅裙妓一行。", "此時逢國色，何處覓天香？", "恐合栽金闕，思將獻玉皇。", "好差青鳥使，封作百花王。"]'),
('ec054e7f-324d-454e-a244-8bef18e7ee8a','送敏中歸豳寧幕','白居易','唐','唐诗','tang','','[]','六十衰翁兒女悲，傍人應笑爾應知。',64,'全唐诗/poet.tang.23000.json','["六十衰翁兒女悲，傍人應笑爾應知。", "弟兄垂老相逢日，桮酒臨歡欲散時。", "前路加餐須努力，今宵盡醉莫推辭。", "司徒知我難爲別，直過秋歸未訝遲。"]'),
('81dd6865-1e6d-474f-bc5c-8b8223109c5a','宴散','白居易','唐','唐诗','tang','','["\u5bb4\u996e", "\u79cb\u5929", "\u751f\u6d3b"]','小宴追涼散，平橋步月回。',48,'全唐诗/poet.tang.23000.json','["小宴追涼散，平橋步月回。", "笙歌歸院落，燈火下樓臺。", "殘暑蟬催盡，新秋雁帶來。", "將何迎睡興，臨臥舉殘桮。"]'),
('887824c8-fdd5-4e78-bf32-a2ec822f20ab','人定','白居易','唐','唐诗','tang','','[]','人定月朧明，香消枕簟清。',48,'全唐诗/poet.tang.23000.json','["人定月朧明，香消枕簟清。", "翠屏遮燭影，紅袖下簾聲。", "坐久吟方罷，眠初夢未成。", "誰家教鸚鵡，故故語相驚。"]'),
('a63be1d1-0287-415b-9a20-774daf45db93','池上','白居易','唐','唐诗','tang','','[]','褭褭涼風動，淒淒寒露零。',48,'全唐诗/poet.tang.23000.json','["褭褭涼風動，淒淒寒露零。", "蘭衰花始白，荷破葉猶青。", "獨立棲沙鶴，雙飛照水螢。", "若爲寥落境，仍值酒初醒。"]'),
('946d9648-d416-44b1-bae2-2414276c2ceb','池窗','白居易','唐','唐诗','tang','','[]','池晚蓮芳謝，窗秋竹意深。',24,'全唐诗/poet.tang.23000.json','["池晚蓮芳謝，窗秋竹意深。", "更無人作伴，唯對一張琴。"]'),
('9af72b11-3f71-4862-a45a-d5655fcf6816','花酒','白居易','唐','唐诗','tang','','[]','香醅淺酌浮如蟻，雪鬢新梳薄似蟬。',32,'全唐诗/poet.tang.23000.json','["香醅淺酌浮如蟻，雪鬢新梳薄似蟬。", "爲報洛城花酒道，莫辭送老二三年。"]'),
('224152f2-bd04-4630-8643-b1584f086c5c','題崔常侍濟源莊','白居易','唐','唐诗','tang','','[]','谷口誰家住，雲扃鎖竹泉。',48,'全唐诗/poet.tang.23000.json','["谷口誰家住，雲扃鎖竹泉。", "主人何處去，蘿薜換貂蟬。", "籍在金閨內，班排玉扆前。", "誠知憶山水，歸得是何年。"]'),
('77037740-3c99-4565-a8d9-976282f54bec','認春戲呈馮少尹李郎中陳主簿','白居易','唐','唐诗','tang','','[]','認得春風先到處，西園南面水東頭。',64,'全唐诗/poet.tang.23000.json','["認得春風先到處，西園南面水東頭。", "柳初變後條猶重，花未開時枝已稠。", "闇助醉歡尋綠酒，潛添睡興著紅樓。", "知君未別陽和意，直待春深始擬遊。"]'),
('a1453f1c-6d56-4161-b800-7e863251437e','魏堤有懷','白居易','唐','唐诗','tang','','[]','魏王堤下水，聲似使君灘。',48,'全唐诗/poet.tang.23000.json','["魏王堤下水，聲似使君灘。", "惆悵回頭聽，躊躕立馬看。", "蕩風波眼急，翻雪浪心寒。", "憶得瞿唐事，重吟行路難。"]'),
('dcac29bf-007e-4b0d-b636-3167f0eb49b5','柘枝詞','白居易','唐','唐诗','tang','','[]','柳闇長廊合，花深小院開。',48,'全唐诗/poet.tang.23000.json','["柳闇長廊合，花深小院開。", "蒼頭鋪錦褥，皓腕捧銀桮。", "繡帽珠稠綴，香衫袖窄裁。", "將軍拄毬杖，看按柘枝來。"]'),
('2a527907-ee34-4da1-a5c2-1f1bb3801581','代夢得吟','白居易','唐','唐诗','tang','','[]','後來變化三分貴，同輩凋零太半無。',64,'全唐诗/poet.tang.23000.json','["後來變化三分貴，同輩凋零太半無。", "世上爭先從盡汝，人間鬬在不如吾。", "竿頭已到應難久，局勢雖遲未必輸。", "不見山苗與林葉，迎春先綠亦先枯。"]'),
('ae7bdec0-bc26-47b6-9bf8-34c27e1c61e3','寄答周協律','白居易','唐','唐诗','tang','','[]','故人敘舊寄新篇，惆悵江南到眼前。',64,'全唐诗/poet.tang.23000.json','["故人敘舊寄新篇，惆悵江南到眼前。", "闇想樓臺萬餘里，不聞歌吹一周年。", "橋頭誰更看新月，池畔猶應泊舊船。", "最憶後庭桮酒散，紅屏風掩綠窗眠。"]'),
('3a66607c-8293-4818-b586-4b1390c222f0','太和戊申歲大有年詔賜百寮出城觀稼謹書盛事以俟采詩','白居易','唐','唐诗','tang','','[]','清晨承詔命，豐歲閱田閭。',72,'全唐诗/poet.tang.23000.json','["清晨承詔命，豐歲閱田閭。", "膏雨抽苗足，涼風吐穗初。", "早禾黃錯落，晚稻綠扶疎。", "好入詩家詠，宜令史館書。", "散爲萬姓食，堆作九年儲。", "莫道如雲稼，今秋雲不如。"]'),
('97d1b08e-b92a-408c-ac0c-01192eddac34','贈悼懷太子挽歌辭二首 一','白居易','唐','唐诗','tang','','[]','竹馬書薨歲，銅龍表葬時。',48,'全唐诗/poet.tang.23000.json','["竹馬書薨歲，銅龍表葬時。", "永言窀穸事，全用少陽儀。", "壽夭由天命，哀榮出聖慈。", "恭聞褒贈詔，軫念在與夷。"]'),
('39c85c6d-d4c8-4c91-9d88-c30297c12c17','贈悼懷太子挽歌辭二首 二','白居易','唐','唐诗','tang','','[]','剪葉藩封早，承華冊命尊。',48,'全唐诗/poet.tang.23000.json','["剪葉藩封早，承華冊命尊。", "笙歌辭洛苑，風雪蔽梁園。", "鹵簿凌霜宿，銘旌向月翻。", "宮寮不逮事，哭送出都門。"]'),
('e62cd454-8cda-44d6-b491-6a7a127de4a9','雨中招張司業宿','白居易','唐','唐诗','tang','','[]','過夏衣香潤，迎秋簟色鮮。',48,'全唐诗/poet.tang.23000.json','["過夏衣香潤，迎秋簟色鮮。", "斜支花石枕，臥詠蘂珠篇。", "泥濘非遊日，陰沈好睡天。", "能來同宿否，聽雨對牀眠。"]'),
('e555361a-7e41-48b8-8040-b411fde3d49d','和集賢劉學士早朝作','白居易','唐','唐诗','tang','','[]','吟君昨日早朝詩，金御爐前喚仗時。',64,'全唐诗/poet.tang.23000.json','["吟君昨日早朝詩，金御爐前喚仗時。", "煙吐白龍頭宛轉，扇開青雉尾參差。", "暫留春殿多稱屈，合入綸闈即可知。", "從此摩霄去非晚，鬢邊未有一莖絲。"]'),
('874bb5b3-1e94-4b59-a222-bce3060a603d','送陝州王司馬建赴任','白居易','唐','唐诗','tang','','[]','陝州司馬去何如，養靜資貧兩有餘。',64,'全唐诗/poet.tang.23000.json','["陝州司馬去何如，養靜資貧兩有餘。", "公事閑忙同少尹，料錢多少敵尚書。", "秪攜美酒爲行伴，唯作新詩趂下車。", "自有鐵牛無詠者，料君投刃必應虛。"]'),
('cc48cce6-8d81-40d0-8ab6-c9eacbcdbaea','對琴待月','白居易','唐','唐诗','tang','','[]','竹院新晴夜，松窗未臥時。',48,'全唐诗/poet.tang.23000.json','["竹院新晴夜，松窗未臥時。", "共琴爲老伴，與月有秋期。", "玉軫臨風久，金波出霧遲。", "幽音待清景，唯是我心知。"]'),
('c8fb95f3-ae8d-4722-b50f-4b37c202e15d','楊家南亭','白居易','唐','唐诗','tang','','[]','小亭門向月斜開，滿地涼風滿地苔。',32,'全唐诗/poet.tang.23000.json','["小亭門向月斜開，滿地涼風滿地苔。", "此院好彈秋思處，終須一夜抱琴來。"]'),
('e11a806e-7117-4cdf-a8f8-05cc03560457','早寒','白居易','唐','唐诗','tang','','[]','黃葉聚牆角，青苔圍柱根。',48,'全唐诗/poet.tang.23000.json','["黃葉聚牆角，青苔圍柱根。", "被經霜後薄，鏡遇雨來昏。", "半卷寒簷幕，斜開暖閣門。", "迎冬兼送老，只仰酒盈尊。"]'),
('c6a8d607-0b55-48fa-8171-25544edde49c','齋月靜居','白居易','唐','唐诗','tang','','[]','病來心靜一無思，老去身閑百不爲。',64,'全唐诗/poet.tang.23000.json','["病來心靜一無思，老去身閑百不爲。", "忽忽眼塵猶愛睡，些些口業尚誇詩。", "葷腥每斷齋居月，香火常親宴坐時。", "萬慮消停百神泰，唯應寂寞殺三尸。"]'),
('7a80c83c-5604-4112-ab99-8edf1bb3829a','宿裴相公興化池亭','白居易','唐','唐诗','tang','','[]','林亭一出宿風塵，忘却平津是要津。',64,'全唐诗/poet.tang.23000.json','["林亭一出宿風塵，忘却平津是要津。", "松閣晴看山色近，石渠秋放水聲新。", "孫弘閣鬧無閑客，傅說舟忙不借人。", "何似掄才濟川外，別開池館待交親。"]'),
('977b738f-7a6f-4200-a957-7770bbf925f3','和劉郎中望終南山秋雪','白居易','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','遍覽古今集，都無秋雪詩。',48,'全唐诗/poet.tang.23000.json','["遍覽古今集，都無秋雪詩。", "陽春先唱後，陰嶺未消時。", "草訝霜凝重，松疑鶴散遲。", "清光莫獨占，亦對白雲司。"]'),
('8c4ab796-a808-4556-8fc3-828dc5fa3d8a','廣府胡尚書頻寄詩因答絕句','白居易','唐','唐诗','tang','','[]','尚書清白臨南海，雖飲貪泉心不回。',32,'全唐诗/poet.tang.23000.json','["尚書清白臨南海，雖飲貪泉心不回。", "唯向詩中得珠玉，時時寄到帝鄉來。"]'),
('7034a173-7baa-4bf3-a52e-b428e28572a7','送鶴與裴相臨別贈詩','白居易','唐','唐诗','tang','','[]','司空愛爾爾須知，不信聽吟送鶴詩。',64,'全唐诗/poet.tang.23000.json','["司空愛爾爾須知，不信聽吟送鶴詩。", "羽翮勢高寧惜別，稻粱恩厚莫愁飢。", "夜棲少共雞爭樹，曉浴先饒鳳占池。", "穩上青雲勿回顧，的應勝在白家時。"]'),
('7952a975-819b-4b52-be03-f1bee23ca585','令狐相公拜尚書後有喜從鎮歸朝之作劉郎中先和因以繼之','白居易','唐','唐诗','tang','','[]','車騎新從梁苑回，履聲珮響入中臺。',64,'全唐诗/poet.tang.23000.json','["車騎新從梁苑回，履聲珮響入中臺。", "鳳池望在終重去，龍節功成且納來。", "金勒最宜乘雪出，玉觴何必待花開。", "尚書首唱郎中和，不計官資只計才。"]'),
('8215659a-3816-4b6f-841f-1e5a9d14bcf6','送河南尹馮學士赴任','白居易','唐','唐诗','tang','','[]','石渠金谷中間路，軒騎翩翩十日程。',64,'全唐诗/poet.tang.23000.json','["石渠金谷中間路，軒騎翩翩十日程。", "清洛飲冰添苦節，碧嵩看雪助高情。", "謾誇河北操旄鉞，莫羨江西擁斾旌。", "何似府寮京令外，別教三十六峰迎。"]'),
('33107f49-023b-41dc-824a-bf27a0970082','讀鄂公傳','白居易','唐','唐诗','tang','','[]','高臥深居不見人，功名斗藪似灰塵。',32,'全唐诗/poet.tang.23000.json','["高臥深居不見人，功名斗藪似灰塵。", "唯留一部清商樂，月下風前伴老身。"]'),
('232f014d-c66d-43c8-be71-b25dffcb88ba','烏夜啼','白居易','唐','唐诗','tang','','[]','城上歸時晚，庭前宿處危。',48,'全唐诗/poet.tang.23000.json','["城上歸時晚，庭前宿處危。", "月明無葉樹，霜滑有風枝。", "啼澀飢喉咽，飛低凍翅垂。", "畫堂鸚鵡鳥，冷暖不相知。"]'),
('4d4eb058-b753-472d-b307-b425ac50515c','鏡換桮','白居易','唐','唐诗','tang','','[]','欲將珠匣青銅鏡，換取金尊白玉巵。',64,'全唐诗/poet.tang.23000.json','["欲將珠匣青銅鏡，換取金尊白玉巵。", "鏡裏老來無避處，尊前愁至有消時。", "茶能散悶爲功淺，萱縱忘憂得力遲。", "不似杜康神用速，十分一盞便開眉。"]'),
('f2b2f64c-ecc1-4380-9726-cb54a98a77df','冬夜聞蟲','白居易','唐','唐诗','tang','','[]','蟲聲冬思苦於秋，不解愁人聞亦愁。',32,'全唐诗/poet.tang.23000.json','["蟲聲冬思苦於秋，不解愁人聞亦愁。", "我是老翁聽不畏，少年莫聽白君頭。"]'),
('483ef41e-5a21-44ad-a591-03708a51ce91','雙鸚鵡','白居易','唐','唐诗','tang','','[]','綠衣整頓雙棲起，紅觜分明對語時。',64,'全唐诗/poet.tang.23000.json','["綠衣整頓雙棲起，紅觜分明對語時。", "始覺琵琶弦莽鹵，方知吉了舌參差。", "鄭牛識字吾常嘆，丁鶴能歌爾亦知。", "若稱白家鸚鵡鳥，籠中兼合解吟詩。"]'),
('a4a0b702-9570-431a-b745-d22ecca78ae9','贈朱道士','白居易','唐','唐诗','tang','','[]','儀容白皙上仙郎，方寸清虛內道場。',64,'全唐诗/poet.tang.23000.json','["儀容白皙上仙郎，方寸清虛內道場。", "兩翼化生因服藥，三尸臥死爲休糧。", "醮壇北向宵占斗，寢室東開早納陽。", "盡日窗間更無事，唯燒一炷降真香。"]'),
('4759e66e-3358-437a-87cd-2f7c8f16ead8','昨以拙詩十首寄西川杜相公相公亦以新作十首惠然報示首數雖等工拙不倫重以一章用伸答謝','白居易','唐','唐诗','tang','','[]','詩家律手在成都，權與尋常將相殊。',64,'全唐诗/poet.tang.23000.json','["詩家律手在成都，權與尋常將相殊。", "剪截五言兼用鉞，陶鈞六義別開爐。", "驚人卷軸須知有，隨事文章不道無。", "篇數雖同光價異，十魚目換十驪珠。"]'),
('778f314b-7103-490e-86fe-c9fc1a24d42f','和汴州令狐相公新於郡內栽竹百竿拆壁開軒旦夕對翫偶題七言五韻','白居易','唐','唐诗','tang','','[]','梁園修竹舊傳名，園廢年深竹不生。',80,'全唐诗/poet.tang.23000.json','["梁園修竹舊傳名，園廢年深竹不生。", "千畝荒涼尋未得，百竿青翠種新成。", "牆開乍見重添興，窗靜時聞別有情。", "煙葉蒙籠侵夜色，風枝蕭颯欲秋聲。", "更登樓望尤堪重，千萬人家無一莖。"]'),
('7fb3270a-18a9-452d-a2f1-6bee72676b26','重答汝州李六使君見和憶吳中舊遊五首','白居易','唐','唐诗','tang','','[]','爲憶娃宮與虎丘，翫君新作不能休。',64,'全唐诗/poet.tang.23000.json','["爲憶娃宮與虎丘，翫君新作不能休。", "蜀牋寫出篇篇好，吳調吟時句句愁。", "洛下林園終共住，江南風月會重遊。", "由來事過多堪惜，何況蘇州勝汝州。"]'),
('27e1e855-bdb1-4d4a-96a6-681cf936ccd4','見殷堯藩侍御憶江南詩三十首詩中多敘蘇杭勝事余嘗典二郡因繼和之','白居易','唐','唐诗','tang','','[]','江南名郡數蘇杭，寫在殷家三十章。',64,'全唐诗/poet.tang.23000.json','["江南名郡數蘇杭，寫在殷家三十章。", "君是旅人猶苦憶，我爲刺史更難忘。", "境牽吟詠真詩國，興入笙歌好醉鄉。", "爲念舊遊終一去，扁舟直擬到滄浪。"]'),
('7768a418-3453-4ca1-97ae-e216a411191d','聞新蟬贈劉二十八','白居易','唐','唐诗','tang','','[]','蟬發一聲時，槐花帶兩枝。',48,'全唐诗/poet.tang.23000.json','["蟬發一聲時，槐花帶兩枝。", "只應催我老，兼遣報君知。", "白髮生頭速，青雲入手遲。", "無過一桮酒，相勸數開眉。"]'),
('312c1c66-cbdf-499d-adaa-55a1322423f5','贈王山人','白居易','唐','唐诗','tang','','[]','玉芝觀裏王居士，服氣餐霞善養身。',64,'全唐诗/poet.tang.23000.json','["玉芝觀裏王居士，服氣餐霞善養身。", "夜後不聞龜喘息，秋來唯長鶴精神。", "容顏盡怪長如故，名姓多疑不是真。", "貴重榮華輕壽命，知君悶見世間人。"]'),
('3dc665d9-b6f4-40bc-ba4d-8b72f120db76','和劉郎中學士題集賢閣','白居易','唐','唐诗','tang','','[]','朱閣青山高庳齊，與君才子作詩題。',64,'全唐诗/poet.tang.23000.json','["朱閣青山高庳齊，與君才子作詩題。", "傍聞大內笙歌近，下視諸司屋舍低。", "萬卷圖書天祿上，一條風景月華西。", "欲知丞相優賢意，百步新廊不蹋泥。"]'),
('29d8afc5-0b5d-40b3-a373-76d40b33bd28','觀幻','白居易','唐','唐诗','tang','','[]','有起皆因滅，無暌不暫同。',48,'全唐诗/poet.tang.23000.json','["有起皆因滅，無暌不暫同。", "從歡終作慼，轉苦又成空。", "次第花生眼，須臾燭過風。", "更無尋覓處，鳥跡印空中。"]'),
('2882300f-b22a-46d6-8003-11948ccb8c23','病假中龐少尹攜魚酒相過','白居易','唐','唐诗','tang','','[]','宦情牢落年將暮，病假聯緜日漸深。',64,'全唐诗/poet.tang.23000.json','["宦情牢落年將暮，病假聯緜日漸深。", "被老相催雖白首，與春無分未甘心。", "閑停茶椀從容語，醉把花枝取次吟。", "勞動故人龐閣老，提魚攜酒遠相尋。"]'),
('401c1e34-c0a2-4d90-968c-43d1daa325f4','聽田順兒歌','白居易','唐','唐诗','tang','','[]','戛玉敲冰聲未停，嫌雲不遏入青冥。',32,'全唐诗/poet.tang.23000.json','["戛玉敲冰聲未停，嫌雲不遏入青冥。", "爭得黃金滿衫袖，一時拋與斷年聽。"]'),
('8d45ddee-35d8-4382-8108-e2e4f27ce179','聽曹剛琵琶兼示重蓮','白居易','唐','唐诗','tang','','[]','撥撥弦弦意不同，胡啼番語兩玲瓏。',32,'全唐诗/poet.tang.23000.json','["撥撥弦弦意不同，胡啼番語兩玲瓏。", "誰能截得曹剛手，插向重蓮衣袖中。"]'),
('88c99df5-f3e0-4c3d-9938-d0f2814178af','酬令狐相公春日尋花見寄六韻','白居易','唐','唐诗','tang','','[]','病臥帝王州，花時不得遊。',72,'全唐诗/poet.tang.23000.json','["病臥帝王州，花時不得遊。", "老應隨日至，春肯爲人留。", "粉壞杏將謝，火繁桃尚稠。", "白飄僧院地，紅落酒家樓。", "空裏雪相似，晚來風不休。", "吟君悵望句，如到曲江頭。"]'),
('138ff99d-9c55-4124-8001-969bbd55dd95','和劉郎中曲江春望見示','白居易','唐','唐诗','tang','','[]','芳景多遊客，衰翁獨在家。',48,'全唐诗/poet.tang.23000.json','["芳景多遊客，衰翁獨在家。", "肺傷妨飲酒，眼痛忌看花。", "寺路隨江曲，宮牆夾道斜。", "羨君猶壯健，不枉度年華。"]'),
('190d90cc-22b2-4755-a834-4adf7155988a','送東都留守令狐尚書赴任','白居易','唐','唐诗','tang','','[]','翠華黃屋未東巡，碧洛青嵩付大臣。',64,'全唐诗/poet.tang.23000.json','["翠華黃屋未東巡，碧洛青嵩付大臣。", "地稱高情多水竹，山宜閑望少風塵。", "龍門即擬爲遊客，金谷先憑作主人。", "歌酒家家花處處，莫空管領上陽春。"]'),
('e814ead9-53cd-4d54-a500-a120a38ee9cf','自題新昌居止因招楊郎中小飲','白居易','唐','唐诗','tang','','[]','地偏坊遠巷仍斜，最近東頭是白家。',64,'全唐诗/poet.tang.23000.json','["地偏坊遠巷仍斜，最近東頭是白家。", "宿雨長齊鄰舍柳，晴光照出夾城花。", "春風小榼三升酒，寒食深爐一椀茶。", "能到南園同醉否，笙歌隨分有些些。"]'),
('c1540716-9d28-45d6-b1f7-1af4818684fb','南園試小樂','白居易','唐','唐诗','tang','','[]','小園斑駮花初發，新樂錚摐教欲成。',64,'全唐诗/poet.tang.23000.json','["小園斑駮花初發，新樂錚摐教欲成。", "紅萼紫房皆手植，蒼頭碧玉盡家生。", "高調管色吹銀字，慢拽歌詞唱渭城。", "不飲一杯聽一曲，將何安慰老心情。"]'),
('2b9b6071-6dc8-4b04-949c-5350f23e4f9d','和微之春日投簡陽明洞天五十韻','白居易','唐','唐诗','tang','','[]','青陽行已半，白日坐將徂。',288,'全唐诗/poet.tang.23000.json','["青陽行已半，白日坐將徂。", "越國強仍大，稽城高且孤。", "利饒鹽煮海，名勝水澄湖。", "牛斗天垂象，台明地展圖。", "瓌奇填市井，佳麗溢闉闍。", "句踐遺風霸，西施舊俗姝。", "船頭龍夭矯，橋脚獸睢盱。", "鄉味珍蟛蚏，時鮮貴鷓鴣。", "語言諸夏異，衣服一方殊。", "擣練蛾眉婢，鳴榔蛙角奴。", "江清敵伊洛，山翠勝荆巫。", "華表雙棲鶴，聯檣幾點烏。", "煙波分渡口，雲樹接城隅。", "澗遠松如畫，洲平水似鋪。", "綠科秧早稻，紫笋折新蘆。", "暖蹋泥中藕，香尋石上蒲。", "雨來萌盡達，雷後蟄全蘇。", "柳眼黃絲纇，花房絳蠟珠。", "林風新竹折，野燒老桑枯。", "帶嚲長枝蕙，錢穿短貫榆。", "暄和生野菜，卑濕長街蕪。", "女浣紗相伴，兒烹鯉一呼。", "山魈啼稚子，林狖挂山都。", "產業論蠶蟻，孳生計鴨雛。"]'),
('9dec5737-b0fb-4333-a9db-68fa6d3779c7','酬鄭侍御多雨春空過詩三十韻','白居易','唐','唐诗','tang','','[]','南雨來多滯，東風動即狂。',288,'全唐诗/poet.tang.23000.json','["南雨來多滯，東風動即狂。", "月行離畢急，龍走召雲忙。", "鬼轉雷車響，蛇騰電策光。", "浸淫天似漏，沮洳地成瘡。", "慘淡陰煙白，空濛宿霧黃。", "闇遮千里目，悶結九回腸。", "寂寞羈臣館，深沈思婦房。", "鏡昏鸞滅影，衣潤麝消香。", "蘭濕難紉珮，花凋易落妝。", "沾黃鶯翅重，滋綠草心長。", "紫陌皆泥濘，黃汚共淼茫。", "恐霖成怪沴，望霽劇禎祥。", "楚柳腰肢嚲，湘筠涕淚滂。", "晝昏疑是夜，陰盛勝於陽。", "居士巾皆墊，行人蓋盡張。", "跳蛙還屢出，移蟻欲深藏。", "端坐交遊廢，閑行去步妨。", "愁生垂白叟，惱殺蹋青娘。", "變海常須慮，爲魚慎勿忘。", "此時方共懼，何處可相將？", "已望東溟禱，仍封北戶禳。", "却思逢旱魃，誰喜見商羊。", "預怕爲蠶病，先憂作麥傷。", "惠應施浹洽，政豈假揄揚。"]'),
('b4d5f3ae-e7ec-43e1-9d40-aef83d598acd','和春深二十首 一','白居易','唐','唐诗','tang','','[]','何處春深好，春深富貴家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深富貴家。", "馬爲中路鳥，妓作後庭花。", "羅綺驅論隊，金銀用斷車。", "眼前何所苦，唯苦日西斜。"]'),
('269e8518-1710-4e3f-9c94-022b2e452f65','和春深二十首 二','白居易','唐','唐诗','tang','','[]','何處春深好，春深貧賤家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深貧賤家。", "荒涼三徑草，冷落四鄰花。", "奴困歸傭力，妻愁出賃車。", "途窮平路險，舉足劇褒斜。"]'),
('d7d4d801-7c25-4697-9bb5-17c31fb4e7d6','和春深二十首 三','白居易','唐','唐诗','tang','','[]','何處春深好，春深執政家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深執政家。", "鳳池添硯水，雞樹落衣花。", "詔借當衢宅，恩容上殿車。", "延英開對久，門與日西斜。"]'),
('126184fb-9a70-44be-bbfb-94e93ad79f29','和春深二十首 四','白居易','唐','唐诗','tang','','[]','何處春深好，春深方鎮家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深方鎮家。", "通犀排帶胯，瑞鶻勘袍花。", "飛絮衝毬馬，垂楊拂妓車。", "戎裝拜春設，左握寶刀斜。"]'),
('b2d758fc-5c12-40c0-887e-63072552962c','和春深二十首 五','白居易','唐','唐诗','tang','','[]','何處春深好，春深刺史家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深刺史家。", "陰繁棠布葉，岐秀麥分花。", "五疋鳴珂馬，雙輪畫軾車。", "和風引行樂，葉葉隼旟斜。"]'),
('1d9386b2-89ad-4e4c-8eaa-8c2db3c4cbd7','和春深二十首 六','白居易','唐','唐诗','tang','','[]','何處春深好，春深學士家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深學士家。", "鳳書裁五色，馬鬣剪三花。", "蠟炬開明火，銀臺賜物車。", "相逢不敢揖，彼此帽低斜。"]'),
('fcd4fd54-5d56-453c-bb9d-49ac89d17661','和春深二十首 七','白居易','唐','唐诗','tang','','[]','何處春深好，春深女學家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深女學家。", "慣看溫室樹，飽識浴堂花。", "御印提隨仗，香牋把下車。", "宋家宮樣髻，一片綠雲斜。"]'),
('b40085bc-5eb9-42c9-9f51-3e41190efd8f','和春深二十首 八','白居易','唐','唐诗','tang','','[]','何處春深好，春深御史家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深御史家。", "絮縈驄馬尾，蝶繞繡衣花。", "破柱行持斧，埋輪立駐車。", "入班遙認得，魚貫一行斜。"]'),
('c442a1dc-6649-4650-a0ab-1b1d0d296020','和春深二十首 九','白居易','唐','唐诗','tang','','[]','何處春深好，春深遷客家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深遷客家。", "一桮寒食酒，萬里故園花。", "炎瘴蒸如火，光陰走似車。", "爲憂鵩鳥至，只恐日光斜。"]'),
('bf899e8c-521e-4f22-83d7-c58f8b5b118b','和春深二十首 十','白居易','唐','唐诗','tang','','[]','何處春深好，春深經業家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深經業家。", "唯求太常第，不管曲江花。", "折桂名慙郄，收螢志慕車。", "官場泥補處，最怕寸陰斜。"]'),
('90ac8ea1-5da6-4c89-bff1-285ff70d5b47','和春深二十首 十一','白居易','唐','唐诗','tang','','[]','何處春深好，春深隱士家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深隱士家。", "野衣裁薜葉，山飯曬松花。", "蘭索紉幽珮，蒲輪駐軟車。", "林間箕踞坐，白眼向人斜。"]'),
('ed3e62b6-3c09-44b2-b8d4-992a5f07d953','和春深二十首 十二','白居易','唐','唐诗','tang','','[]','何處春深好，春深漁父家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深漁父家。", "松灣隨櫂月，桃浦落船花。", "投餌移輕楫，牽輪轉小車。", "蕭蕭蘆葉裏，風起釣絲斜。"]'),
('5124d7a9-5485-4b33-9781-dceb2457eb43','和春深二十首 十三','白居易','唐','唐诗','tang','','[]','何處春深好，春深潮戶家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深潮戶家。", "濤翻三月雪，浪噴四時花。", "曳練馳千馬，驚雷走萬車。", "餘波落何處，江轉富陽斜。"]'),
('5c200245-2718-4e76-934a-efa60fb49cca','和春深二十首 十四','白居易','唐','唐诗','tang','','[]','何處春深好，春深痛飲家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深痛飲家。", "十分桮裏物，五色眼前花。", "餔歠眠糟甕，流涎見麴車。", "中山一沈醉，千度日西斜。"]'),
('adb95ad5-ed32-46ec-8de4-a428ac23d0ae','和春深二十首 十五','白居易','唐','唐诗','tang','','[]','何處春深好，春深上巳家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深上巳家。", "蘭亭席上酒，曲洛岸邊花。", "弄水遊童櫂，湔裾小婦車。", "齊橈爭渡處，一匹錦標斜。"]'),
('67075157-fff2-492d-97bf-62662bc88623','和春深二十首 十六','白居易','唐','唐诗','tang','','[]','何處春深好，春深寒食家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深寒食家。", "玲瓏鏤雞子，宛轉綵毬花。", "碧草追遊騎，紅塵拜掃車。", "鞦韆細腰女，搖曳逐風斜。"]'),
('e97a325e-e1df-40a0-890c-096bf38d0b6b','和春深二十首 十七','白居易','唐','唐诗','tang','','[]','何處春深好，春深博弈家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深博弈家。", "一先爭破眼，六聚鬬成花。", "鼓應投壺馬，兵衝象戲車。", "彈碁局上事，最妙是長斜。"]'),
('49623bd9-d02c-40bb-a14d-e7f882f8c0dc','和春深二十首 十八','白居易','唐','唐诗','tang','','[]','何處春深好，春深嫁女家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深嫁女家。", "紫排襦上雉，黃帖鬢邊花。", "轉燭初移障，鳴環欲上車。", "青衣傳氈褥，錦繡一條斜。"]'),
('9609189c-395d-4d53-b23a-be20166da715','和春深二十首 十九','白居易','唐','唐诗','tang','','[]','何處春深好，春深娶婦家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深娶婦家。", "兩行籠裏燭，一樹扇間花。", "賓拜登華席，親迎障幰車。", "催妝詩未了，星斗漸傾斜。"]'),
('b590d1f5-7509-4e19-b2e9-0b35bf6ca3c7','和春深二十首 二十','白居易','唐','唐诗','tang','','[]','何處春深好，春深妓女家。',48,'全唐诗/poet.tang.23000.json','["何處春深好，春深妓女家。", "眉欺楊柳葉，裙妬石榴花。", "蘭麝熏行被，金銅釘坐車。", "杭州蘇小小，人道最夭斜。"]'),
('4c02f7ae-a3c9-4e40-98fb-e098dcf3f93f','詠家醖十韻','白居易','唐','唐诗','tang','','[]','獨醒從古笑靈均，長醉如今斅伯倫。',160,'全唐诗/poet.tang.23000.json','["獨醒從古笑靈均，長醉如今斅伯倫。", "舊法依稀傳自杜，新方要妙得於陳。", "井泉王相資重九，麴糵精靈用上寅。", "釀糯豈勞炊范黍，撇篘何假漉陶巾。", "常嫌竹葉猶凡濁，始覺榴花不正真。", "甕揭開時香酷烈，缾封貯後味甘辛。", "捧疑明水從空化，飲似陽和滿腹春。", "色洞玉壺無表裏，光搖金醆有精神。", "能銷忙事成閑事，轉得憂人作樂人。", "應是世間賢聖物，與君還往擬終身。"]'),
('efd04832-4cbd-4b1e-a1b5-98c570a312af','池鶴二首 一','白居易','唐','唐诗','tang','','[]','高竹籠前無伴侶，亂雞羣裏有風標。',64,'全唐诗/poet.tang.23000.json','["高竹籠前無伴侶，亂雞羣裏有風標。", "低頭乍恐丹砂落，曬翅常疑白雪消。", "轉覺鸕鷀毛色下，苦嫌鸚鵡語聲嬌。", "臨風一唳思何事，悵望青田雲水遙。"]'),
('8b9ada4c-ae7c-4a80-8b9c-81b4eedf5be4','池鶴二首 二','白居易','唐','唐诗','tang','','[]','池中此鶴鶴中稀，恐是遼東老令威。',64,'全唐诗/poet.tang.23000.json','["池中此鶴鶴中稀，恐是遼東老令威。", "帶雪松枝翹膝脛，放花菱片綴毛衣。", "低迴且向林間宿，奮迅終須天外飛。", "若問故巢知處在，主人相戀未能歸。"]'),
('475f20cc-bff7-4225-bd20-ac5b1d6bb96d','對酒五首 一','白居易','唐','唐诗','tang','','[]','巧拙賢愚相是非，何如一醉盡忘機。',32,'全唐诗/poet.tang.23000.json','["巧拙賢愚相是非，何如一醉盡忘機。", "君知天地中寬窄，鵰鶚鸞皇各自飛。"]'),
('e603b132-ce1c-4009-94da-e5aae4820914','對酒五首 二','白居易','唐','唐诗','tang','','[]','蝸牛角上爭何事，石火光中寄此身。',32,'全唐诗/poet.tang.23000.json','["蝸牛角上爭何事，石火光中寄此身。", "隨富隨貧且歡樂，不開口笑是癡人。"]'),
('cbc907f2-5469-4558-a423-4e7b869de6e9','對酒五首 三','白居易','唐','唐诗','tang','','[]','丹砂見火去無迹，白髮泥人來不休。',32,'全唐诗/poet.tang.23000.json','["丹砂見火去無迹，白髮泥人來不休。", "賴有酒仙相暖熱，松喬醉即到前頭。"]'),
('e8ad1721-8b65-4822-a830-8105eb343f4c','對酒五首 四','白居易','唐','唐诗','tang','','[]','百歲無多時壯健，一春能幾日晴明。',32,'全唐诗/poet.tang.23000.json','["百歲無多時壯健，一春能幾日晴明。", "相逢且莫推辭醉，聽唱陽關第四聲。"]'),
('74e8a1ab-6753-4ac5-87f0-8589eec0ee09','對酒五首 五','白居易','唐','唐诗','tang','','[]','昨日低眉問疾來，今朝收淚弔人回。',32,'全唐诗/poet.tang.23000.json','["昨日低眉問疾來，今朝收淚弔人回。", "眼前流例君看取，且遣琵琶送一桮。"]'),
('fbebe3bb-6bbf-492f-b55a-f6407ae867cd','僧院花','白居易','唐','唐诗','tang','','[]','欲悟色空爲佛事，故栽芳樹在僧家。',32,'全唐诗/poet.tang.23000.json','["欲悟色空爲佛事，故栽芳樹在僧家。", "細看便是華嚴偈，方便風開智慧花。"]'),
('dde9fcb5-0bee-4caa-b76b-4f40f811f831','老戒','白居易','唐','唐诗','tang','','[]','我有白頭戒，聞於韓侍郎。',48,'全唐诗/poet.tang.23000.json','["我有白頭戒，聞於韓侍郎。", "老多憂活計，病更戀班行。", "矍鑠誇身健，周遮說話長。", "不知吾免否，兩鬢已成霜。"]'),
('c430d72c-3b6e-40c4-8511-da871922f1fc','洛橋寒食日作十韻','白居易','唐','唐诗','tang','','["\u5bd2\u98df\u8282", "\u601d\u4e61"]','上苑風煙好，中橋道路平。',120,'全唐诗/poet.tang.23000.json','["上苑風煙好，中橋道路平。", "蹴毬塵不起，潑火雨新晴。", "宿醉頭仍重，晨遊眼乍明。", "老慵雖省事，春誘尚多情。", "遇客踟躕立，尋花取次行。", "連錢嚼金勒，鑿落寫銀罌。", "府醞傷教送，官娃豈要迎。", "舞腰那及柳，歌舌不如鶯。", "鄉國真堪戀，光陰可合輕。", "三年遇寒食，盡在洛陽城。"]'),
('abd0cd0e-97b9-4a67-a1b5-4792a2c372aa','快活','白居易','唐','唐诗','tang','','[]','可惜鶯啼花落處，一壺濁酒送殘春。',64,'全唐诗/poet.tang.23000.json','["可惜鶯啼花落處，一壺濁酒送殘春。", "可憐月好風涼夜，一部清商伴老身。", "飽食安眠消日月，閑談冷笑接交親。", "誰知將相王侯外，別有優游快活人。"]'),
('acab01b4-43e9-4f17-a94f-7d851fdd94e8','送令狐相公赴太原','白居易','唐','唐诗','tang','','[]','六纛雙旌萬鐵衣，幷汾舊路滿光輝。',64,'全唐诗/poet.tang.23000.json','["六纛雙旌萬鐵衣，幷汾舊路滿光輝。", "青衫書記何年去，紅斾將軍昨日歸。", "詩作馬蹄隨筆走，獵酣鷹翅伴觥飛。", "此都莫作多時計，再爲蒼生入紫微。"]');
